function dataQualityEngine() {
  if (!sharedDataQualityEngine) {
    sharedDataQualityEngine = createDataQualityEngine({
      productImageUrls,
      productIsCloseout,
      productUomInfo,
      shopifyPurchaseVariants,
      sourceCatalogCost,
      marketplaceSuggestedPrice,
      marketplaceListingQuantity,
      categoryMappingForProduct,
      categorySettingForProduct,
      ebayListingCategoryId,
      ebayChannelSettings,
      withShopifyStatus
    });
  }
  return sharedDataQualityEngine;
}

function productQualityChecks(item = {}) {
  return dataQualityEngine().productQualityChecks(item);
}

function productQualitySummary(item = {}) {
  return dataQualityEngine().productQualitySummary(item);
}

function categoryQualityLookupKey(value = "") {
  return formatCategoryName(value || "").toLowerCase();
}

function buildCategoryQualityContext(db = {}) {
  const settings = normalizeCategorySettings(db.categorySettings).map((row) => applyStoredAttributeMappingsToCategory(row));
  const byName = new Map();
  const byId = new Map();
  for (const setting of settings) {
    const nameKey = categoryQualityLookupKey(setting.name || setting.category || "");
    if (nameKey && !byName.has(nameKey)) byName.set(nameKey, setting);
    const idKey = String(setting.categoryId || "").trim().toLowerCase();
    if (idKey && !byId.has(idKey)) byId.set(idKey, setting);
  }
  return { byName, byId, ebaySettings: ebayChannelSettings(db), shopifySettings: findChannelByName(db, "Shopify")?.settings || DEFAULT_CHANNEL_SETTINGS };
}

function categorySettingFromQualityContext(context = {}, item = {}) {
  const categoryKey = categoryQualityLookupKey(item.category || item.mainCategory || "");
  if (!categoryKey) return null;
  return context.byName?.get(categoryKey) || context.byId?.get(categoryKey) || null;
}

function categoryChannelMappingFromQualityContext(context = {}, item = {}, channel = "shopify") {
  return categorySettingFromQualityContext(context, item)?.mappings?.[channel] || null;
}

function shopifyQualitySummary(db, item = {}, context = null) {
  const sharedContext = context ? {
    ...context,
    categoryChannelMapping: (product, channel) => categoryChannelMappingFromQualityContext(context, product, channel)
  } : null;
  return dataQualityEngine().shopifyQualitySummary(db, item, sharedContext);
}

function ebayQualitySummary(db, item = {}, context = null) {
  const sharedContext = context ? {
    ...context,
    categoryChannelMapping: (product, channel) => categoryChannelMappingFromQualityContext(context, product, channel)
  } : null;
  return dataQualityEngine().ebayQualitySummary(db, item, sharedContext);
}

function pricingQualitySummary(item = {}) {
  return dataQualityEngine().pricingQualitySummary(item);
}

function categoryQualitySummary(db, item = {}, context = null) {
  const sharedContext = context ? {
    ...context,
    categoryChannelMapping: (product, channel) => categoryChannelMappingFromQualityContext(context, product, channel),
    categorySetting: (product) => categorySettingFromQualityContext(context, product)
  } : null;
  return dataQualityEngine().categoryQualitySummary(db, item, sharedContext);
}

function dataQualityRow(db, rawItem = {}, shopifyStatusMap = {}, context = null) {
  const sharedContext = context ? {
    ...context,
    categoryChannelMapping: (product, channel) => categoryChannelMappingFromQualityContext(context, product, channel),
    categorySetting: (product) => categorySettingFromQualityContext(context, product)
  } : null;
  return dataQualityEngine().dataQualityRow(db, rawItem, shopifyStatusMap, sharedContext);
}

function dataQualitySnapshot(db, options = {}) {
  const shopifyStatusMap = options.shopifyStatusMap || readShopifyStatusMapSync();
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const context = options.context || buildCategoryQualityContext(db);
  const rows = (db.inventory || []).map((item) => dataQualityRow(db, sourceEnrichedItem(item, sourceEnrichmentMap), shopifyStatusMap, context));
  const issueCounts = {};
  const typeCounts = {};
  for (const row of rows) {
    for (const issue of row.issues) issueCounts[issue] = (issueCounts[issue] || 0) + 1;
    for (const type of row.issueTypes) typeCounts[type] = (typeCounts[type] || 0) + 1;
  }
  const summary = {
    generatedAt: new Date().toISOString(),
    total: rows.length,
    productReady: rows.filter((row) => row.ready).length,
    needsWork: rows.filter((row) => !row.ready).length,
    shopifyReady: rows.filter((row) => row.shopifyReady).length,
    shopifyLive: rows.filter((row) => row.shopifyLive).length,
    ebayReady: rows.filter((row) => row.ebayReady).length,
    ebayLive: rows.filter((row) => row.ebayLive).length,
    staleShopify: rows.filter((row) => row.staleDays !== null && row.staleDays > 7).length,
    closeouts: rows.filter((row) => row.toBeDiscontinued).length,
    issueCounts: Object.fromEntries(Object.entries(issueCounts).sort((a, b) => b[1] - a[1])),
    typeCounts
  };
  return { summary, rows };
}

function writeDataQualitySnapshot(snapshot = {}) {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.writeFileSync(DATA_QUALITY_SNAPSHOT_FILE, JSON.stringify(snapshot, null, 2));
  if (postgres.isPostgresEnabled()) {
    postgres.replaceProductQualityRows(snapshot.rows || []).catch((error) => {
      console.error("Unable to persist data-quality snapshot to Postgres", error.message || error);
    });
    postgres.writeStateDocuments({ dataQualitySummary: snapshot.summary || {} }).catch((error) => {
      console.error("Unable to persist data-quality summary to Postgres", error.message || error);
    });
  }
}

function readDataQualitySnapshot() {
  try {
    if (!fs.existsSync(DATA_QUALITY_SNAPSHOT_FILE)) return null;
    return JSON.parse(fs.readFileSync(DATA_QUALITY_SNAPSHOT_FILE, "utf8"));
  } catch {
    return null;
  }
}

function filterDataQualityRows(snapshot = {}, query = {}) {
  const q = String(query.q || "").trim().toLowerCase();
  const issue = String(query.issue || "").trim().toLowerCase();
  const type = String(query.type || "").trim().toLowerCase();
  const channel = String(query.channel || "").trim().toLowerCase();
  const status = String(query.status || "").trim().toLowerCase();
  let rows = Array.isArray(snapshot.rows) ? snapshot.rows : [];
  if (q) rows = rows.filter((row) => [row.sku, row.title, row.brand, row.vendor, row.category].some((value) => String(value || "").toLowerCase().includes(q)));
  if (issue) rows = rows.filter((row) => (row.issueKeys || []).includes(issue) || (row.issues || []).some((label) => dataQualityIssueKey(label) === issue));
  if (type) rows = rows.filter((row) => (row.issueTypes || []).includes(type));
  if (channel === "shopify") rows = rows.filter((row) => !row.shopifyReady || !row.shopifyLive);
  if (channel === "ebay") rows = rows.filter((row) => !row.ebayReady || !row.ebayLive);
  if (status === "ready") rows = rows.filter((row) => row.ready);
  if (status === "needs-work") rows = rows.filter((row) => !row.ready);
  if (status === "shopify-ready") rows = rows.filter((row) => row.shopifyReady);
  if (status === "shopify-live") rows = rows.filter((row) => row.shopifyLive);
  if (status === "stale") rows = rows.filter((row) => row.staleDays !== null && row.staleDays > 7);
  if (status === "closeout") rows = rows.filter((row) => row.toBeDiscontinued);
  return rows.sort((a, b) => a.productScore - b.productScore || String(a.sku).localeCompare(String(b.sku)));
}

async function dataQualitySnapshotFromPostgres(options = {}) {
  const baseDb = normalizeDb(await readDbFast({ skipInventory: true }));
  const shopifyStatusMap = options.shopifyStatusMap || readShopifyStatusMapSync();
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const context = buildCategoryQualityContext(baseDb);
  const total = await postgres.countProducts();
  const pageSize = Math.max(100, Math.min(5000, Number(options.pageSize || 1000)));
  const rows = [];
  const issueCounts = {};
  const typeCounts = {};
  const progress = typeof options.progress === "function" ? options.progress : null;
  const isCanceled = typeof options.isCanceled === "function" ? options.isCanceled : () => false;
  for (let page = 1; rows.length < total || page === 1; page += 1) {
    if (isCanceled()) throw new Error("Job was canceled.");
    const result = await postgres.listProducts({ page, limit: pageSize });
    const items = result?.inventory || result?.items || [];
    if (!items.length) break;
    for (const item of items) {
      const row = dataQualityRow(baseDb, sourceEnrichedItem(item, sourceEnrichmentMap), shopifyStatusMap, context);
      rows.push(row);
      for (const issue of row.issues) issueCounts[issue] = (issueCounts[issue] || 0) + 1;
      for (const type of row.issueTypes) typeCounts[type] = (typeCounts[type] || 0) + 1;
    }
    progress?.({ phase: "scanning_products", processedRows: rows.length, totalRows: total });
    if (items.length < pageSize) break;
  }
  const summary = {
    generatedAt: new Date().toISOString(),
    total: rows.length,
    productReady: rows.filter((row) => row.ready).length,
    needsWork: rows.filter((row) => !row.ready).length,
    shopifyReady: rows.filter((row) => row.shopifyReady).length,
    shopifyLive: rows.filter((row) => row.shopifyLive).length,
    ebayReady: rows.filter((row) => row.ebayReady).length,
    ebayLive: rows.filter((row) => row.ebayLive).length,
    staleShopify: rows.filter((row) => row.staleDays !== null && row.staleDays > 7).length,
    closeouts: rows.filter((row) => row.toBeDiscontinued).length,
    issueCounts: Object.fromEntries(Object.entries(issueCounts).sort((a, b) => b[1] - a[1])),
    typeCounts,
    storage: "postgres"
  };
  return { summary, rows };
}

async function startDataQualityScanJob(jobId) {
  setTimeout(async () => {
    const job = activeJobRecords.get(jobId) || normalizeImportJob({ id: jobId });
    try {
      if (!["queued", "running"].includes(String(job.status || "").toLowerCase())) return;
      setActiveJobProgress(jobId, {
        status: "running",
        phase: "starting",
        processedRows: 0,
        totalRows: Number(job.totalRows || 0) || 0,
        startedAt: job.startedAt || new Date().toISOString()
      });
      job.status = "running";
      job.startedAt = job.startedAt || new Date().toISOString();
      job.updatedAt = new Date().toISOString();
      job.message = "Scanning product data quality...";
      upsertImportJobStore(job);
      let lastProgressPersistedAt = 0;
      const progress = (patch = {}) => {
        const next = setActiveJobProgress(jobId, {
          ...patch,
          status: "running",
          startedAt: job.startedAt || new Date().toISOString()
        });
        job.totalRows = next.totalRows;
        job.processedRows = next.processedRows;
        job.progressPercent = next.progressPercent;
        job.estimatedSecondsRemaining = next.estimatedSecondsRemaining;
        job.phase = next.phase;
        job.lastProgressAt = next.lastProgressAt;
        activeJobRecords.set(jobId, normalizeImportJob(job));
        if (Date.now() - lastProgressPersistedAt > 1000 || Number(next.progressPercent || 0) >= 100) {
          lastProgressPersistedAt = Date.now();
          upsertImportJobStore(job);
        }
      };
      const isCanceled = () => !["queued", "running"].includes(String(activeJobProgress.get(jobId)?.status || job.status || "").toLowerCase());
      const snapshot = postgres.isPostgresEnabled()
        ? await dataQualitySnapshotFromPostgres({ progress, isCanceled })
        : dataQualitySnapshot(normalizeDb(await readDbFast()), { progress, isCanceled });
      progress({ phase: "saving_snapshot", processedRows: snapshot.summary.total, totalRows: snapshot.summary.total });
      writeDataQualitySnapshot(snapshot);
      activeJobProgress.delete(jobId);
      finishImportJob(job, {
        status: "success",
        message: `Data quality scan finished for ${Number(snapshot.summary.total || 0).toLocaleString()} products.`,
        totalRows: snapshot.summary.total,
        processedRows: snapshot.summary.total,
        changed: snapshot.summary.needsWork,
        progressPercent: 100,
        estimatedSecondsRemaining: 0,
        phase: "complete",
        details: `${Number(snapshot.summary.needsWork || 0).toLocaleString()} products need work.`
      });
      upsertImportJobStore(job);
    } catch (error) {
      activeJobProgress.delete(jobId);
      const wasCanceled = /canceled|cancelled|stopped/i.test(String(error.message || ""));
      finishImportJob(job, {
        status: wasCanceled ? "stopped" : "failed",
        message: wasCanceled ? "Data quality scan was canceled." : error.message || "Data quality scan failed.",
        errors: [error.message || "Data quality scan failed."],
        missingCount: wasCanceled ? 0 : 1
      });
      upsertImportJobStore(job);
    }
  }, 1000);
}

function startPostgresBackupJob(jobId, attrs = {}) {
  setTimeout(async () => {
    const job = activeJobRecords.get(jobId) || normalizeImportJob({ id: jobId, operation: "Postgres backup" });
    try {
      if (!postgres.isPostgresEnabled()) throw new Error("Postgres is not configured.");
      if (!["queued", "running"].includes(String(job.status || "").toLowerCase())) return;
      const settings = readSystemSettingsStore(dbCache.data?.systemSettings || {});
      const includeSourceCatalog = attrs.includeSourceCatalog === undefined
        ? settings.backupIncludeSourceCatalog === true
        : attrs.includeSourceCatalog === true || String(attrs.includeSourceCatalog || "").toLowerCase() === "true";
      job.status = "running";
      job.phase = "starting";
      job.startedAt = job.startedAt || new Date().toISOString();
      job.updatedAt = new Date().toISOString();
      job.message = "Creating Postgres backup...";
      upsertImportJobStore(job);
      let lastProgressPersistedAt = 0;
      const progress = (patch = {}) => {
        const next = setActiveJobProgress(jobId, {
          ...patch,
          status: "running",
          startedAt: job.startedAt
        });
        Object.assign(job, {
          processedRows: next.processedRows,
          totalRows: next.totalRows,
          progressPercent: next.progressPercent,
          estimatedSecondsRemaining: next.estimatedSecondsRemaining,
          phase: next.phase,
          lastProgressAt: next.lastProgressAt,
          message: next.message || job.message
        });
        activeJobRecords.set(jobId, normalizeImportJob(job));
        if (Date.now() - lastProgressPersistedAt > 1000 || Number(next.progressPercent || 0) >= 100) {
          lastProgressPersistedAt = Date.now();
          upsertImportJobStore(job);
        }
      };
      const isCanceled = () => !["queued", "running"].includes(String(activeJobProgress.get(jobId)?.status || job.status || "").toLowerCase());
      const backup = await postgres.createPostgresBackup({
        outputDir: path.join(DATA_DIR, "backups"),
        includeSourceCatalog,
        onProgress: progress,
        isCanceled
      });
      attachImportJobOriginalFilePath(job, backup.manifestPath, "manifest.json");
      activeJobProgress.delete(jobId);
      finishImportJob(job, {
        status: "success",
        message: `Postgres backup complete: ${Number(backup.rows || 0).toLocaleString()} rows across ${Number(backup.tables?.length || 0).toLocaleString()} tables.`,
        details: `Backup folder: ${backup.backupDir}${backup.skippedTables?.length ? `. Skipped large tables by setting: ${backup.skippedTables.join(", ")}.` : ""}`,
        totalRows: backup.totalRows || backup.rows || 0,
        processedRows: backup.rows || backup.totalRows || 0,
        changed: backup.tables?.length || 0,
        progressPercent: 100,
        estimatedSecondsRemaining: 0,
        phase: "complete"
      });
      upsertImportJobStore(job);
    } catch (error) {
      activeJobProgress.delete(jobId);
      const wasCanceled = /canceled|cancelled|stopped/i.test(String(error.message || ""));
      finishImportJob(job, {
        status: wasCanceled ? "stopped" : "failed",
        message: wasCanceled ? "Postgres backup was canceled." : error.message || "Postgres backup failed.",
        errors: wasCanceled ? [] : [error.message || "Postgres backup failed."],
        missingCount: wasCanceled ? 0 : 1,
        phase: wasCanceled ? "stopped" : "failed",
        estimatedSecondsRemaining: 0
      });
      upsertImportJobStore(job);
    } finally {
      activeJobRecords.delete(jobId);
    }
  }, 1000);
}

function shouldRunJobsInline() {
  const settings = readSystemSettingsStore(dbCache.data?.systemSettings || {});
  return String(settings.backgroundJobsMode || "inline").toLowerCase() !== "worker";
}

function shouldRunDataQualityInline() {
  const settings = readSystemSettingsStore(dbCache.data?.systemSettings || {});
  return String(settings.backgroundJobsMode || "inline").toLowerCase() !== "worker" || settings.dataQualityWorkerEnabled !== true;
}

async function queueDataQualityScanIfEnabled(reason = "Catalog data changed") {
  try {
    const settings = readSystemSettingsStore(dbCache.data?.systemSettings || {});
    if (settings.autoDataQualityScanAfterImports !== true) return null;
    const existing = [...activeJobRecords.values()].find((job) => /data quality/i.test(String(job.operation || job.message || "")) && ["queued", "running"].includes(String(job.status || "").toLowerCase()));
    if (existing) return existing;
    const db = await readDbFast({ skipInventory: postgres.isPostgresEnabled() });
    const totalRows = postgres.isPostgresEnabled() ? await postgres.countProducts() : (db.inventory || []).length;
    const job = createImportJob(db, {
      section: "Products",
      operation: "Data quality scan",
      direction: "scan",
      status: "queued",
      fileName: "data-quality-snapshot.json",
      totalRows,
      processedRows: 0,
      progressPercent: 0,
      phase: "queued",
      workerTask: shouldRunDataQualityInline() ? "" : "data-quality-scan",
      workerPayload: shouldRunDataQualityInline() ? {} : { reason },
      message: `Data quality scan queued after ${reason}.`
    });
    upsertImportJobStore(job);
    if (shouldRunDataQualityInline()) {
      activeJobRecords.set(job.id, normalizeImportJob(job));
      setActiveJobProgress(job.id, { status: "queued", phase: "queued", totalRows, processedRows: 0, progressPercent: 0 });
      startDataQualityScanJob(job.id);
    }
    return job;
  } catch (error) {
    console.error("Unable to queue data quality scan", error.message || error);
    return null;
  }
}

function loadLocalEnv() {
  if (!fs.existsSync(ENV_FILE)) return;
  const lines = fs.readFileSync(ENV_FILE, "utf8").split(/\r?\n/);
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#") || !trimmed.includes("=")) continue;
    const index = trimmed.indexOf("=");
    const key = trimmed.slice(0, index).trim();
    const value = trimmed.slice(index + 1).trim().replace(/^["']|["']$/g, "");
    if (key && process.env[key] === undefined) process.env[key] = value;
  }
}

function sourceScalarValue(value) {
  if (value == null) return value;
  if (value instanceof Date) return value.toISOString();
  if (value && typeof value === "object") {
    if (value.$numberDecimal !== undefined) return value.$numberDecimal;
    if (value.$date !== undefined) return sourceScalarValue(value.$date);
    if (value._bsontype === "Decimal128" && typeof value.toString === "function") return value.toString();
    if (value._bsontype === "ObjectId" && typeof value.toString === "function") return value.toString();
  }
  return value;
}

function sourceTextValue(value) {
  const scalar = sourceScalarValue(value);
  return scalar == null ? "" : String(scalar).trim();
}

function sourceNumberValue(value, fallback = 0) {
  const number = Number(sourceScalarValue(value));
  return Number.isFinite(number) ? number : fallback;
}

function sourceListValue(value) {
  if (Array.isArray(value)) return value.map(sourceTextValue).filter(Boolean);
  const text = sourceTextValue(value);
  if (!text) return [];
  return text.split(/[|,]/).map((item) => item.trim()).filter(Boolean);
}

function sourceBooleanValue(value, fallback = false) {
  if (value === undefined) return fallback;
  if (value === true || value === false) return value;
  const text = sourceTextValue(value).toLowerCase();
  if (["true", "1", "yes", "y", "active"].includes(text)) return true;
  if (["false", "0", "no", "n", "inactive"].includes(text)) return false;
  return fallback;
}

function isClearanceItem(item = {}) {
  const statusValues = [
    item.status,
    item.stockStatus,
    item.raw?.status,
    item.raw?.stockStatus
  ].map((value) => sourceTextValue(value).toLowerCase());
  const indicatorValues = [
    item.itemClearanceIndicator,
    item.item_clearance_indicator,
    item.raw?.itemClearanceIndicator,
    item.raw?.item_clearance_indicator
  ].map((value) => sourceTextValue(value).toLowerCase());
  return statusValues.some((value) => ["clearance", "clearance item", "closeout"].includes(value))
    || indicatorValues.some((value) => ["clearance", "clearance item", "closeout", "y", "yes", "true", "1"].includes(value));
}

function calculateDimensionalWeight(item = {}) {
  const length = Number(sourceNumberValue(item.packageLength ?? item.package_length ?? item.raw?.packageLength ?? item.raw?.package_length ?? 0));
  const width = Number(sourceNumberValue(item.packageWidth ?? item.package_width ?? item.raw?.packageWidth ?? item.raw?.package_width ?? 0));
  const height = Number(sourceNumberValue(item.packageHeight ?? item.package_height ?? item.raw?.packageHeight ?? item.raw?.package_height ?? 0));
  if (!(length > 0 && width > 0 && height > 0)) return 0;
  return Math.round(((length * width * height) / 139) * 1000) / 1000;
}

function productShippingDimensionValue(item = {}, camelKey = "", snakeKey = "") {
  return sourceNumberValue(item[camelKey] ?? item[snakeKey] ?? item.raw?.[camelKey] ?? item.raw?.[snakeKey] ?? item.original?.[snakeKey] ?? 0);
}

function productHasShippingMeasurements(item = {}) {
  return [
    ["packageLength", "package_length"],
    ["packageWidth", "package_width"],
    ["packageHeight", "package_height"],
    ["packageWeight", "package_weight"],
    ["itemLength", "item_length"],
    ["itemWidth", "item_width"],
    ["itemHeight", "item_height"],
    ["itemWeight", "item_weight"]
  ].some(([camelKey, snakeKey]) => productShippingDimensionValue(item, camelKey, snakeKey) > 0);
}

function productShippingClassification(item = {}) {
  const packageLength = productShippingDimensionValue(item, "packageLength", "package_length");
  const packageWidth = productShippingDimensionValue(item, "packageWidth", "package_width");
  const packageHeight = productShippingDimensionValue(item, "packageHeight", "package_height");
  const packageWeight = productShippingDimensionValue(item, "packageWeight", "package_weight");
  const itemLength = productShippingDimensionValue(item, "itemLength", "item_length");
  const itemWidth = productShippingDimensionValue(item, "itemWidth", "item_width");
  const itemHeight = productShippingDimensionValue(item, "itemHeight", "item_height");
  const itemWeight = productShippingDimensionValue(item, "itemWeight", "item_weight");
  const length = packageLength || itemLength;
  const width = packageWidth || itemWidth;
  const height = packageHeight || itemHeight;
  const weight = packageWeight || itemWeight;
  const dimensionalWeight = sourceNumberValue(item.dimensionalWeight ?? item.dimensional_weight ?? item.raw?.dimensionalWeight ?? item.raw?.dimensional_weight) || calculateDimensionalWeight({
    packageLength,
    packageWidth,
    packageHeight
  });
  const sorted = [length, width, height].sort((a, b) => b - a);
  const longest = sorted[0] || 0;
  const girth = 2 * ((sorted[1] || 0) + (sorted[2] || 0));
  const lengthPlusGirth = longest + girth;
  const ltlReasons = [];
  if (longest > 60) ltlReasons.push(`longest side ${longest}" exceeds 60" parcel free-shipping threshold`);
  if (lengthPlusGirth > 130) ltlReasons.push(`length plus girth ${lengthPlusGirth}" exceeds 130"`);
  if (weight >= 50) ltlReasons.push(`package weight ${weight} lb is 50 lb or more`);
  if (dimensionalWeight >= 70) ltlReasons.push(`dimensional weight ${dimensionalWeight} lb is 70 lb or more`);
  if (ltlReasons.length) return { shippingClass: "ltl", shippingMethod: "LTL", shippingClassReason: ltlReasons.join("; "), dimensionalWeight };
  const oversizeReasons = [];
  if (longest > 48) oversizeReasons.push(`longest side ${longest}" exceeds 48"`);
  if (lengthPlusGirth > 105) oversizeReasons.push(`length plus girth ${lengthPlusGirth}" exceeds 105"`);
  if (dimensionalWeight >= 50) oversizeReasons.push(`dimensional weight ${dimensionalWeight} lb is 50 lb or more`);
  if (oversizeReasons.length) return { shippingClass: "oversize_parcel", shippingMethod: "Oversize Parcel", shippingClassReason: oversizeReasons.join("; "), dimensionalWeight };
  return { shippingClass: "parcel", shippingMethod: "Parcel", shippingClassReason: "Within parcel size and weight thresholds.", dimensionalWeight };
}

function applyProductShippingClassification(item = {}) {
  const classification = productShippingClassification(item);
  if (!productHasShippingMeasurements(item)) return { shippingClass: "", shippingMethod: "", shippingClassReason: "", dimensionalWeight: 0 };
  item.dimensionalWeight = classification.dimensionalWeight;
  item.shippingClass = classification.shippingClass;
  item.shippingMethod = classification.shippingMethod;
  item.shippingClassReason = classification.shippingClassReason;
  if (item.raw && typeof item.raw === "object" && !Array.isArray(item.raw)) {
    item.raw.dimensionalWeight = classification.dimensionalWeight;
    item.raw.shippingClass = classification.shippingClass;
    item.raw.shippingMethod = classification.shippingMethod;
    item.raw.shippingClassReason = classification.shippingClassReason;
  }
  return classification;
}

function normalizedCompareValue(value) {
  if (Array.isArray(value)) return value.map((item) => normalizedCompareValue(item)).join("|");
  if (value && typeof value === "object") return JSON.stringify(value);
  if (value === undefined || value === null) return "";
  const number = Number(value);
  if (Number.isFinite(number) && String(value).trim() !== "") return String(Number(number.toFixed(4)));
  return String(value).trim();
}

function formatBrandName(value) {
  const text = sourceTextValue(value).replace(/[\u2122\u00ae\u00a9]/g, "").replace(/\s+/g, " ").trim();
  if (!text) return "";
  const acronyms = new Set(["3M", "A/C", "AC", "ANSI", "BUNN", "CFC", "CFL", "CMM", "CNC", "CPR", "CPU", "DVI", "EPA", "GFCI", "HD", "HDMI", "HVAC", "ISO", "IT", "LED", "LLC", "LP", "MRO", "NEMA", "NSF", "OSHA", "PVC", "RFID", "UL", "UPS", "USB", "USA", "US", "UV", "VGA", "WiFi", "WIFI", "WD-40"]);
  const lowerWords = new Set(["and", "of", "the", "for", "in", "on", "to", "with"]);
  const formatPart = (part, index) => {
    if (!part) return part;
    const upper = part.toUpperCase();
    const compactUpper = upper.replace(/[^A-Z0-9]/g, "");
    if (compactUpper === "3M") return "3M";
    if (/^([A-Z]\.){2,}[A-Z]?\.?$/i.test(part)) return upper;
    if (/^[A-Z0-9]{2,4}$/.test(part)) return upper;
    if (acronyms.has(upper)) return upper === "WIFI" ? "WiFi" : upper;
    if (/^\d+[A-Z]*$/i.test(part)) return upper;
    const lower = part.toLowerCase();
    if (index > 0 && lowerWords.has(lower)) return lower;
    return lower.charAt(0).toUpperCase() + lower.slice(1);
  };
  return text
    .split(" ")
    .map((word, wordIndex) => word
      .split("/")
      .map((slashPart) => slashPart
        .split("-")
        .map((part, partIndex) => formatPart(part, wordIndex + partIndex))
        .join("-"))
      .join("/"))
    .join(" ");
}

function formatCategoryName(value) {
  const text = sourceTextValue(value).replace(/[\u2122\u00ae\u00a9]/g, "").replace(/\s*>\s*/g, " > ").replace(/\s+/g, " ").trim();
  if (!text) return "";
  const acronyms = new Set(["3D", "A/C", "AC", "ANSI", "CFC", "CFL", "CNC", "CPR", "CPU", "DVI", "EPA", "GFCI", "HD", "HDMI", "HVAC", "ISO", "IT", "LED", "MRO", "NEMA", "NSF", "OSHA", "PPE", "PVC", "RFID", "UL", "UPS", "USB", "UV", "VGA", "VFD", "WiFi", "WIFI"]);
  const lowerWords = new Set(["and", "of", "the", "for", "in", "on", "to", "with"]);
  const formatToken = (token, index) => {
    if (!token || token === "&") return token;
    const upper = token.toUpperCase();
    if (/^([A-Z]\.){2,}[A-Z]?\.?$/i.test(token)) return upper;
    if (acronyms.has(upper)) return upper === "WIFI" ? "WiFi" : upper;
    if (/^\d+[A-Z]*$/i.test(token)) return upper;
    const lower = token.toLowerCase();
    if (index > 0 && lowerWords.has(lower)) return lower;
    if (/^[A-Z0-9]{2,4}$/.test(token)) return upper;
    return lower.charAt(0).toUpperCase() + lower.slice(1);
  };
  return text
    .split(" > ")
    .map((segment) => segment
      .split(" ")
      .map((word, wordIndex) => word
        .split("/")
        .map((slashPart) => slashPart
          .split("-")
          .map((part, partIndex) => formatToken(part, wordIndex + partIndex))
          .join("-"))
        .join("/"))
      .join(" "))
    .join(" > ");
}

function productSupplierIdentity(item = {}) {
  return [
    item.supplier,
    item.vendor,
    item.supplierCode,
    item.defaultSupplier,
    item.productManagerFields?.supplier,
    item.productManagerFields?.supplier_code,
    item.productManagerFields?.default_supplier,
    item.original?.supplier,
    item.original?.supplier_code
  ].map((value) => sourceTextValue(value).toLowerCase()).filter(Boolean);
}

function shouldPromoteSourceCategoryToMain(item = {}, settings = {}) {
  if (settings.trueValueSourceCategoryAsMainCategory === false) return false;
  return productSupplierIdentity(item).some((value) => value === "true value" || value === "trv" || value.includes("true value"));
}

function effectiveMainCategoryName(item = {}, settings = {}) {
  const sourceCategory = formatCategoryName(item.sourceCategory || item.vendorCategory || item.productManagerFields?.category || item.original?.category || "");
  if (shouldPromoteSourceCategoryToMain(item, settings) && sourceCategory) return sourceCategory;
  return formatCategoryName(item.category || item.mainCategory || sourceCategory || "");
}

function applySourceCategoryMainPromotion(item = {}, settings = {}) {
  const sourceCategory = formatCategoryName(item.sourceCategory || item.vendorCategory || item.productManagerFields?.category || item.original?.category || "");
  if (!shouldPromoteSourceCategoryToMain(item, settings) || !sourceCategory) return item;
  return {
    ...item,
    category: sourceCategory,
    mainCategory: sourceCategory,
    sourceCategory,
    vendorCategory: sourceCategory,
    categoryVerified: true,
    mainCategorySource: "vendor-category"
  };
}

function sourceBrandFrom(item = {}) {
  return sourceTextValue(item.sourceBrand || item.productManagerFields?.brand || item.original?.brand || item.brand || "");
}

function brandLooksLikeSupplier(item = {}) {
  const brand = sourceTextValue(item.brand).toLowerCase();
  if (!brand) return true;
  return [item.supplier, item.vendor, item.defaultSupplier, item.supplierCode]
    .map((value) => sourceTextValue(value).toLowerCase())
    .filter(Boolean)
    .includes(brand);
}

function normalizeCatalogImportReviews(reviews = []) {
  return (Array.isArray(reviews) ? reviews : []).map((review) => ({
    id: review.id || crypto.randomUUID(),
    sku: sourceTextValue(review.sku),
    productId: sourceTextValue(review.productId),
    field: sourceTextValue(review.field),
    label: sourceTextValue(review.label || review.field),
    currentValue: review.currentValue ?? "",
    incomingValue: review.incomingValue ?? "",
    source: sourceTextValue(review.source || "Product dump"),
    status: sourceTextValue(review.status || "pending"),
    createdAt: review.createdAt || new Date().toISOString(),
    updatedAt: review.updatedAt || review.createdAt || new Date().toISOString(),
    decidedAt: review.decidedAt || "",
    decisionNote: review.decisionNote || "",
    details: review.details || "",
    externalUrl: review.externalUrl || "",
    externalId: review.externalId || "",
    rawData: review.rawData && typeof review.rawData === "object" ? review.rawData : null
  })).filter((review) => review.sku && review.field).slice(0, 5000);
}

function queueCatalogImportReview(db, item, field, incomingValue, source = "Product dump") {
  const currentValue = item[field];
  if (normalizedCompareValue(currentValue) === normalizedCompareValue(incomingValue)) return false;
  db.catalogImportReviews = normalizeCatalogImportReviews(db.catalogImportReviews);
  const pending = db.catalogImportReviews.find((review) => (
    review.status === "pending"
    && review.sku.toLowerCase() === String(item.sku || "").toLowerCase()
    && review.field === field
  ));
  const now = new Date().toISOString();
  if (pending) {
    pending.productId = item.id || pending.productId;
    pending.currentValue = currentValue ?? "";
    pending.incomingValue = incomingValue ?? "";
    pending.source = source;
    pending.updatedAt = now;
    return true;
  }
  db.catalogImportReviews.unshift({
    id: crypto.randomUUID(),
    sku: item.sku || "",
    productId: item.id || "",
    field,
    label: PRODUCT_MAPPING_FIELDS.find((mapping) => mapping.key === field)?.label || field,
    currentValue: currentValue ?? "",
    incomingValue: incomingValue ?? "",
    source,
    status: "pending",
    createdAt: now,
    updatedAt: now,
    decidedAt: "",
    decisionNote: ""
  });
  db.catalogImportReviews = db.catalogImportReviews.slice(0, 5000);
  return true;
}

function queueUnmappedEbayCatalogReview(db, row) {
  db.catalogImportReviews = normalizeCatalogImportReviews(db.catalogImportReviews);
  const sku = String(row.sku || "").trim();
  if (!sku) return false;
  const externalId = row.listingId || row.offerId || sku;
  const pending = db.catalogImportReviews.find((review) => (
    review.status === "pending"
    && review.field === "ebayCatalogMatch"
    && (
      (review.externalId && externalId && review.externalId === externalId)
      || review.sku.toLowerCase() === sku.toLowerCase()
    )
  ));
  const now = new Date().toISOString();
  const title = row.title || row.description || "Untitled eBay listing";
  const incomingValue = JSON.stringify({
    sku,
    title,
    price: row.price,
    quantity: row.quantity,
    offerId: row.offerId,
    listingId: row.listingId,
    status: row.status
  });
  const payload = {
    sku,
    productId: "",
    field: "ebayCatalogMatch",
    label: "eBay listing not mapped",
    currentValue: "No matching DataPlus product",
    incomingValue,
    source: "eBay catalog",
    status: "pending",
    updatedAt: now,
    details: `Live eBay SKU ${sku} did not match a DataPlus SKU, alias, offer ID, or listing ID.`,
    externalUrl: row.listingUrl || "",
    externalId,
    rawData: row
  };
  if (pending) {
    Object.assign(pending, payload, { id: pending.id, createdAt: pending.createdAt || now });
    return true;
  }
  db.catalogImportReviews.unshift({
    id: crypto.randomUUID(),
    createdAt: now,
    decidedAt: "",
    decisionNote: "",
    ...payload
  });
  db.catalogImportReviews = db.catalogImportReviews.slice(0, 5000);
  return true;
}

function isEmptyCatalogValue(value) {
  if (Array.isArray(value)) return value.length === 0;
  if (value === undefined || value === null) return true;
  if (typeof value === "number") return value === 0;
  return String(value).trim() === "";
}

function applyProtectedSourceProduct(db, existing, incoming, source = "Source catalog") {
  const sourceBrand = sourceBrandFrom(incoming);
  if (sourceBrand) existing.sourceBrand = sourceBrand;
  for (const [field, incomingValue] of Object.entries(incoming || {})) {
    if (["id", "reserved", "shadowSkus", "serialUnits", "warehouseStock"].includes(field)) continue;
    if (field === "qty" && incoming.stockQty !== undefined) continue;
    if (field === "brand") {
      if (!existing.brand || (!existing.brandLocked && brandLooksLikeSupplier(existing))) {
        existing.brand = formatBrandName(incomingValue);
      } else if (existing.brandLocked || normalizedCompareValue(existing.brand) !== normalizedCompareValue(incomingValue)) {
        queueCatalogImportReview(db, existing, "brand", formatBrandName(incomingValue), source);
      }
      continue;
    }
    if (field === "category") {
      const formattedCategory = formatCategoryName(incomingValue);
      if (formattedCategory) {
        if (shouldPromoteSourceCategoryToMain(incoming, readSystemSettingsStore(db.systemSettings || {}))) {
          existing.category = formattedCategory;
          existing.mainCategory = formattedCategory;
          existing.sourceCategory = formattedCategory;
          existing.vendorCategory = formattedCategory;
          existing.categoryVerified = true;
          existing.mainCategorySource = "vendor-category";
        } else {
          existing.sourceCategory = existing.sourceCategory || formattedCategory;
          existing.vendorCategory = existing.vendorCategory || formattedCategory;
        }
      }
      continue;
    }
    if (DUMP_SOURCE_TRACE_FIELDS.has(field)) {
      existing[field] = incomingValue;
      continue;
    }
    if (DUMP_REVIEW_FIELDS.has(field)) {
      if (isEmptyCatalogValue(existing[field]) && !isEmptyCatalogValue(incomingValue)) {
        existing[field] = incomingValue;
      } else {
        queueCatalogImportReview(db, existing, field, incomingValue, source);
      }
      continue;
    }
    if (DUMP_PROTECTED_CONTENT_FIELDS.has(field)) {
      if (isEmptyCatalogValue(existing[field]) && !isEmptyCatalogValue(incomingValue)) existing[field] = incomingValue;
      continue;
    }
    existing[field] = incomingValue;
  }
  existing.sources = { ...(incoming.sources || {}), ...(existing.sources || {}), catalog: incoming.sku || existing.sku };
  existing.updatedAt = new Date().toISOString();
  return existing;
}

const DEFAULT_KNOWLEDGE_CATEGORIES = [
  { id: "whats-new", label: "What's New", active: true },
  { id: "features", label: "Features", active: true },
  { id: "how-to", label: "How To", active: true },
  { id: "workflows", label: "Workflows", active: true }
];

const DEFAULT_KNOWLEDGE_AREAS = [
  "Admin",
  "Catalog",
  "Channels",
  "Customers",
  "Dashboard",
  "Drafts",
  "Import / Export",
  "Inventory",
  "Jobs",
  "Orders",
  "Product Details",
  "Purchasing",
  "Reports",
  "Returns",
  "Release Notes",
  "Workflow"
].map((label) => ({ id: slugifyKnowledgeTitle(label), label, active: true }));

function slugifyKnowledgeTitle(value) {
  const slug = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return slug || `article-${Date.now()}`;
}

function normalizeKnowledgeSettingItem(item = {}, fallbackLabel = "") {
  const label = String(item.label || item.name || fallbackLabel || item.id || "").trim();
  if (!label) return null;
  return {
    id: String(item.id || slugifyKnowledgeTitle(label)).trim() || slugifyKnowledgeTitle(label),
    label,
    active: item.active === undefined ? true : Boolean(item.active)
  };
}

function normalizeKnowledgeSettings(settings = {}) {
  const mergeItems = (customItems, defaultItems, sort = false) => {
    const map = new Map();
    for (const item of defaultItems) {
      const normalized = normalizeKnowledgeSettingItem(item);
      if (normalized) map.set(normalized.id, normalized);
    }
    for (const item of Array.isArray(customItems) ? customItems : []) {
      const normalized = normalizeKnowledgeSettingItem(item);
      if (normalized) map.set(normalized.id, normalized);
    }
    const items = Array.from(map.values());
    return sort ? items.sort((a, b) => a.label.localeCompare(b.label)) : items;
  };
  return {
    categories: mergeItems(settings.categories, DEFAULT_KNOWLEDGE_CATEGORIES),
    areas: mergeItems(settings.areas, DEFAULT_KNOWLEDGE_AREAS, true)
  };
}

function normalizeKnowledgeBlocks(blocks = []) {
  if (!Array.isArray(blocks)) return [];
  return blocks
    .map((block) => {
      const type = String(block?.type || "paragraph").trim() || "paragraph";
      const data = block && typeof block.data === "object" && !Array.isArray(block.data) ? block.data : {};
      return {
        id: String(block?.id || crypto.randomUUID()),
        type,
        data
      };
    })
    .slice(0, 250);
}

function normalizeKnowledgeArticle(article = {}) {
  const now = new Date().toISOString();
  const title = String(article.title || "Untitled article").trim() || "Untitled article";
  const createdAt = article.createdAt || now;
  const updatedAt = article.updatedAt || createdAt;
  const category = String(article.category || "how-to").trim() || "how-to";
  return {
    id: String(article.id || crypto.randomUUID()),
    title,
    slug: String(article.slug || slugifyKnowledgeTitle(title)).trim() || slugifyKnowledgeTitle(title),
    category,
    area: String(article.area || "").trim(),
    summary: String(article.summary || "").trim(),
    tags: sourceListValue(article.tags || []).map((tag) => String(tag).trim()).filter(Boolean).slice(0, 24),
    status: String(article.status || "published").toLowerCase() === "draft" ? "draft" : "published",
    blocks: normalizeKnowledgeBlocks(article.blocks || []),
    archived: Boolean(article.archived || false),
    createdAt,
    updatedAt,
    createdBy: String(article.createdBy || "DataPlus").trim() || "DataPlus",
    updatedBy: String(article.updatedBy || article.createdBy || "DataPlus").trim() || "DataPlus"
  };
}

function normalizeKnowledgeArticles(articles = []) {
  return Array.isArray(articles)
    ? articles.map(normalizeKnowledgeArticle).sort((a, b) => String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")))
    : [];
}

function knowledgeSettingIds(settings, key) {
  return new Set((settings?.[key] || []).filter((item) => item.active !== false).map((item) => item.id));
}

function validateKnowledgeArticleSettings(db, body = {}) {
  db.knowledgeSettings = normalizeKnowledgeSettings(db.knowledgeSettings);
  const categoryIds = knowledgeSettingIds(db.knowledgeSettings, "categories");
  const areaIds = knowledgeSettingIds(db.knowledgeSettings, "areas");
  if (!categoryIds.has(String(body.category || ""))) {
    return `Choose a managed knowledge category before saving.`;
  }
  if (!areaIds.has(String(body.area || ""))) {
    return `Choose a managed knowledge area before saving.`;
  }
  return "";
}

function normalizeDb(db) {
  let changed = false;
  db.sequence = db.sequence || {};
  db.sequence.order = Number(db.sequence.order || 1000);
  db.sequence.po = Number(db.sequence.po || 2000);
  db.sequence.vendor = Number(db.sequence.vendor || 3000);
  db.sequence.draft = Number(db.sequence.draft || 0);
  db.inventoryLedger = Array.isArray(db.inventoryLedger) ? db.inventoryLedger : [];
  db.marketplaceTemplates = normalizeMarketplaceTemplates(db.marketplaceTemplates);
  db.exportMappings = normalizeExportMappings(db.exportMappings);
  db.categorySettings = normalizeCategorySettings(db.categorySettings);
  db.sourceCatalogOverrides = normalizeSourceCatalogOverrides(db.sourceCatalogOverrides);
  db.vendorCategoryMappings = normalizeVendorCategoryMappings(db.vendorCategoryMappings);
  db.catalogImportReviews = normalizeCatalogImportReviews(db.catalogImportReviews);
  db.deletedOrders = Array.isArray(db.deletedOrders) ? db.deletedOrders : [];
  db.syncRuns = Array.isArray(db.syncRuns) ? db.syncRuns : [];
  db.importJobs = normalizeImportJobs(db.importJobs, db.syncRuns);
  db.knowledgeSettings = normalizeKnowledgeSettings(db.knowledgeSettings);
  db.knowledgeArticles = normalizeKnowledgeArticles(db.knowledgeArticles);
  db.systemSettings = readSystemSettingsStore(db.systemSettings);
  const connectionRows = Array.isArray(db.connections) ? db.connections : SOURCES.map((name) => ({ id: crypto.randomUUID(), name }));
  const knownConnections = new Set(connectionRows.map((connection) => String(connection.name || "").trim().toLowerCase()).filter(Boolean));
  for (const name of SOURCES) {
    if (knownConnections.has(name.toLowerCase())) continue;
    connectionRows.push({ id: crypto.randomUUID(), name, connected: name === "Shopify" ? Boolean(shopifyAdminConfig().shop) : false, virtual: true });
    knownConnections.add(name.toLowerCase());
  }
  db.connections = connectionRows.map(normalizeChannel);
  const websitePriceSettings = findChannelByName(db, "Shopify")?.settings || db.connections[0]?.settings || DEFAULT_CHANNEL_SETTINGS;
  const websiteMarkupPercent = Number(websitePriceSettings.priceMarkupPercent || SHOPIFY_PRICE_MARKUP_PERCENT);

  db.inventory = (db.inventory || []).map((item) => {
    const defaults = PRODUCT_DEFAULTS[item.sku] || {};
    const categoryVerified = sourceBooleanValue(item.categoryVerified ?? item.mainCategoryVerified, Boolean(defaults.category));
    const currentCategory = formatCategoryName(item.category ?? defaults.category ?? "");
    const sourceCategory = formatCategoryName(item.sourceCategory ?? item.vendorCategory ?? item.productManagerFields?.category ?? item.original?.category ?? (categoryVerified ? "" : currentCategory));
    const effectiveCategory = effectiveMainCategoryName({ ...defaults, ...item, sourceCategory, vendorCategory: sourceCategory }, db.systemSettings);
    const sourceCost = sourceCatalogCost({ ...defaults, ...item });
    const sellUnitCost = productSellUnitCost({ ...defaults, ...item, sourceCost });
    const listPrice = isClearanceItem(item) ? Number(sourceNumberValue(item.listPrice ?? item.list_price ?? item.msrp ?? defaults.msrp ?? 0)) : 0;
    const websitePrice = websitePriceFromRule({ ...defaults, ...item }, sellUnitCost || sourceCost, websiteMarkupPercent)
      || Number(sourceNumberValue(item.shopifyPrice ?? item.channelPrice ?? 0));
    const uomInfo = productUomInfo(item);
    const product = {
      title: item.title ?? item.name ?? defaults.title ?? item.sku ?? "",
      price: websitePrice,
      websitePrice,
      cost: sourceCost,
      sourceCost,
      sellUnitCost,
      listPrice,
      msrp: listPrice,
      brand: formatBrandName(item.brand ?? defaults.brand ?? ""),
      sourceBrand: item.sourceBrand ?? item.productManagerFields?.brand ?? item.original?.brand ?? item.brand ?? "",
      brandLocked: Boolean(item.brandLocked ?? false),
      category: effectiveCategory || (categoryVerified ? currentCategory : ""),
      mainCategory: effectiveCategory || (categoryVerified ? currentCategory : ""),
      categoryVerified: Boolean(effectiveCategory || categoryVerified),
      sourceCategory,
      vendorCategory: sourceCategory,
      condition: item.condition ?? defaults.condition ?? "New",
      status: item.status ?? defaults.status ?? "Draft",
      active: item.active === undefined ? true : Boolean(item.active),
      barcode: item.barcode ?? item.upc ?? item.gtin ?? defaults.barcode ?? "",
      shortDescription: item.shortDescription ?? item.short_description ?? defaults.shortDescription ?? "",
      longDescription: item.longDescription ?? item.description ?? item.long_description ?? defaults.longDescription ?? "",
      bulletPoints: sourceListValue(item.bulletPoints ?? item.bullet_points ?? item.keyFeatures ?? item.features ?? defaults.bulletPoints ?? []),
      images: sourceListValue(item.images ?? defaults.images ?? []),
      tags: sourceListValue(item.tags ?? defaults.tags ?? []),
      weightOz: Number(item.weightOz ?? defaults.weightOz ?? 0),
      lengthIn: Number(item.lengthIn ?? defaults.lengthIn ?? 0),
      widthIn: Number(item.widthIn ?? defaults.widthIn ?? 0),
      heightIn: Number(item.heightIn ?? defaults.heightIn ?? 0),
      vendor: item.vendor ?? item.supplier ?? defaults.vendor ?? "",
      marketplaceTitle: item.marketplaceTitle ?? item.name ?? defaults.marketplaceTitle ?? item.title ?? item.sku,
      seoKeywords: item.seoKeywords ?? defaults.seoKeywords ?? "",
      externalId: item.externalId ?? item._id ?? "",
      shopifyId: item.shopifyId ?? item.shopify_ID ?? item.shopify_id ?? "",
      shopifyVariantId: item.shopifyVariantId ?? item.shopify_variant_id ?? "",
      shopifyHandle: item.shopifyHandle ?? item.shopify_handle ?? "",
      shopifyStatus: item.shopifyStatus ?? item.shopify_status ?? "",
      shopifyPublished: item.shopifyPublished === undefined ? sourceBooleanValue(item.shopify_published, false) : Boolean(item.shopifyPublished),
      shopifyPublishedAt: item.shopifyPublishedAt ?? item.shopify_published_at ?? "",
      shopifyUpdatedAt: item.shopifyUpdatedAt ?? item.shopify_updated_at ?? "",
      shopifySyncedAt: item.shopifySyncedAt ?? item.shopify_synced_at ?? "",
      shopifySyncSource: item.shopifySyncSource ?? item.shopify_sync_source ?? "",
      shopifyOnlineStoreUrl: item.shopifyOnlineStoreUrl ?? item.shopify_online_store_url ?? "",
      shopifyVariantSku: item.shopifyVariantSku ?? item.shopify_variant_sku ?? "",
      shopifyVariantCount: Number(item.shopifyVariantCount ?? item.shopify_variant_count ?? 0),
      defaultImage: item.defaultImage ?? item.default_image ?? "",
      manufacturer: item.manufacturer ?? "",
      mfrPartNumber: item.mfrPartNumber ?? item.mfr_part_number ?? "",
      vendorSku: item.vendorSku ?? item.vendor_sku ?? "",
      supplier: item.supplier ?? "",
      supplierCode: item.supplierCode ?? item.supplier_code ?? "",
      unspsc: item.unspsc ?? "",
      uom: uomInfo.code,
      uomName: uomInfo.name,
      uomQty: String(uomInfo.qty),
      uomDisplay: uomInfo.display,
      isMultiUnit: uomInfo.isMultiUnit,
      minQuantity: item.minQuantity ?? item.min_quantity ?? "",
      quantityIncrements: item.quantityIncrements ?? item.quantity_increments ?? "",
      hazardous: Boolean(item.hazardous ?? false),
      sdsUrl: item.sdsUrl ?? item.sds_url ?? "",
      itemHeight: Number(item.itemHeight ?? item.item_height ?? 0),
      itemLength: Number(item.itemLength ?? item.item_length ?? 0),
      itemWeight: Number(item.itemWeight ?? item.item_weight ?? 0),
      itemWidth: Number(item.itemWidth ?? item.item_width ?? 0),
      packageHeight: Number(item.packageHeight ?? item.package_height ?? 0),
      packageLength: Number(item.packageLength ?? item.package_length ?? 0),
      packageWeight: Number(item.packageWeight ?? item.package_weight ?? 0),
      packageWidth: Number(item.packageWidth ?? item.package_width ?? 0),
      dimensionalWeight: Number(item.dimensionalWeight ?? item.dimensional_weight ?? calculateDimensionalWeight(item)),
      stockQty: Number(sourceNumberValue(item.stockQty ?? item.stock_qty ?? item.qty ?? 0)),
      stockStatus: item.stockStatus ?? item.stock_status ?? "",
      stockUpdatedAt: item.stockUpdatedAt ?? item.stock_updated_at ?? "",
      ctechId: item.ctechId ?? item.ctech_id ?? "",
      ctechIdLastExport: item.ctechIdLastExport ?? item.ctech_id_last_export ?? "",
      fobPrice: Number(sourceNumberValue(item.fobPrice ?? item.fob_price ?? 0)),
      wildcardSearch: item.wildcardSearch ?? "",
      productDumpCreatedAt: item.productDumpCreatedAt ?? item.created_at ?? "",
      productDumpUpdatedAt: item.productDumpUpdatedAt ?? item.updated_at ?? "",
      inactiveMailedAt: item.inactiveMailedAt ?? item.inactive_mailed_at ?? "",
      validatedAt: item.validatedAt ?? item.validated_at ?? "",
      checkedImage: item.checkedImage ?? item.checked_image ?? {},
      checkedImageUrl: item.checkedImageUrl ?? item.checked_image?.url ?? "",
      checkedImageError: item.checkedImageError ?? item.checked_image?.error ?? "",
      checkedImageSize: item.checkedImageSize ?? item.checked_image?.size ?? "",
      checkedImageTimestamp: item.checkedImageTimestamp ?? item.checked_image?.timestamp ?? "",
      zoroLeadtime: item.zoroLeadtime ?? item.zoro_leadtime ?? "",
      zoroPrice: Number(item.zoroPrice ?? item.zoro_price ?? 0),
      zoroSku: item.zoroSku ?? item.zoro_sku ?? "",
      zoroMinimumQty: Number(item.zoroMinimumQty ?? item.zoro_minimum_qty ?? 0),
      varisContractPrice: Number(item.varisContractPrice ?? item.varis_contract_price ?? 0),
      varisListPrice: Number(item.varisListPrice ?? item.varis_list_price ?? 0),
      varisOdManagedPrice: Number(item.varisOdManagedPrice ?? item.varis_od_managed_price ?? 0),
      varisNonOdManagedPrice: Number(item.varisNonOdManagedPrice ?? item.varis_non_od_managed_price ?? 0),
      varisOdPrivatePrice: Number(item.varisOdPrivatePrice ?? item.varis_od_private_price ?? 0),
      varisNonOdPrivatePrice: Number(item.varisNonOdPrivatePrice ?? item.varis_non_od_private_price ?? 0),
      originalImage: item.originalImage ?? item.original_image ?? "",
      defaultSupplier: item.defaultSupplier ?? item.default_supplier ?? "",
      lastPricesUpdateAt: item.lastPricesUpdateAt ?? item.last_prices_update_at ?? "",
      lastPricesUpdateBy: item.lastPricesUpdateBy ?? item.last_prices_update_by ?? "",
      leadTime: item.leadTime ?? item.lead_time ?? item.leadtime ?? "",
      leadtime: item.leadtime ?? "",
      suppliers: item.suppliers === undefined ? [] : item.suppliers,
      altVendorSku: item.altVendorSku ?? item.alt_vendor_sku ?? "",
      countryOfOrigin: item.countryOfOrigin ?? item.country_of_origin ?? "",
      originalSdsUrl: item.originalSdsUrl ?? item.original_sds_url ?? "",
      itemKey: item.itemKey ?? item.item_key ?? "",
      itemClearanceIndicator: item.itemClearanceIndicator ?? item.item_clearance_indicator ?? "",
      original: item.original === undefined ? null : item.original,
      vendorDescription: item.vendorDescription ?? item.vendor_descripton ?? item.vendor_description ?? "",
      uploadedBy: item.uploadedBy ?? item.uploaded_by ?? "",
      productManagerFields: item.productManagerFields && typeof item.productManagerFields === "object" ? item.productManagerFields : {},
      serialUnits: Array.isArray(item.serialUnits) ? item.serialUnits : [],
      warehouseStock: Array.isArray(item.warehouseStock) ? item.warehouseStock : [],
      shadowSkus: Array.isArray(item.shadowSkus) ? item.shadowSkus.map((shadow) => normalizeShadowSku(shadow, item)) : [],
      systemVariants: systemProductVariants({ ...item, uom: uomInfo.code, uomQty: uomInfo.qty, sellUnitCost, sourceCost, cost: sourceCost }),
      aliases: normalizeProductAliases(item.aliases, item),
      attributes: item.attributes || {}
    };

    const merged = { ...item, ...product, images: product.images, tags: product.tags, serialUnits: product.serialUnits, warehouseStock: product.warehouseStock, shadowSkus: product.shadowSkus, systemVariants: product.systemVariants, aliases: product.aliases };
    if (!merged.brandLocked && merged.brand && !brandLooksLikeSupplier(merged)) {
      merged.brandLocked = true;
      changed = true;
    }
    const availableWarehouses = Array.isArray(db.warehouses) ? db.warehouses : [];
    if (!Array.isArray(merged.warehouseStock) || !merged.warehouseStock.length) {
      const fallbackWarehouse = availableWarehouses.find((warehouse) => warehouse.isDefaultReceiving) || availableWarehouses[0];
      merged.warehouseStock = [
        normalizeWarehouseStockRow({
          warehouseId: fallbackWarehouse?.id || "",
          warehouseName: fallbackWarehouse?.name || "Unassigned",
          qty: Number(item.qty || 0),
          reserved: Number(item.reserved || 0),
          reorderPoint: Number(item.reorderPoint || 0)
        }, fallbackWarehouse, merged)
      ];
      changed = true;
    } else {
      merged.warehouseStock = merged.warehouseStock.map((row) => {
        const warehouse = availableWarehouses.find((item) => item.id === row.warehouseId);
        return normalizeWarehouseStockRow(row, warehouse, merged);
      });
    }
    syncInventoryTotalsFromWarehouses(merged);
    if (item.price === undefined || item.shortDescription === undefined || !Array.isArray(item.images)) changed = true;
    return merged;
  });

  db.orders = (db.orders || []).map((order) => {
    const legacyMarketplaceOrder = order.marketplaceOrderId || order.marketplaceOrderNumber || order.orderNumber;
    const internalOrderNumber = order.internalOrderNumber || (/^DP-\d{6}$/.test(order.orderNumber || "") ? order.orderNumber : nextOrderNumber(db));
    const marketplaceOrderNumber = order.marketplaceOrderNumber || legacyMarketplaceOrder || "";
    const detail = ORDER_DETAILS[marketplaceOrderNumber] || ORDER_DETAILS[order.orderNumber] || {};
    const enriched = {
      internalOrderNumber,
      orderNumber: internalOrderNumber,
      displayOrderNumber: internalOrderNumber,
      marketplaceOrderNumber: detail.marketplaceOrderId || marketplaceOrderNumber,
      marketplaceOrderId: detail.marketplaceOrderId || marketplaceOrderNumber,
      marketplaceReferences: order.marketplaceReferences || [
        {
          source: order.source,
          type: "order",
          value: detail.marketplaceOrderId || marketplaceOrderNumber,
          primary: true
        }
      ].filter((reference) => reference.value),
      buyerEmail: detail.buyerEmail || order.buyerEmail || "",
      phone: detail.phone || order.phone || "",
      address: detail.address || order.address || {
        name: order.buyer || "",
        line1: "",
        line2: "",
        city: "",
        state: "",
        postalCode: "",
        country: "US"
      },
      shippingService: detail.shippingService || order.shippingService || "Not selected",
      trackingNumber: detail.trackingNumber || order.trackingNumber || "",
      shippingCarrier: detail.shippingCarrier || order.shippingCarrier || "",
      carrierName: detail.carrierName || order.carrierName || "",
      trackingUrl: detail.trackingUrl || order.trackingUrl || "",
      shipDate: detail.shipDate || order.shipDate || "",
      productCost: Number(detail.productCost ?? order.productCost ?? Number(order.total || 0) * 0.42),
      marketplaceFees: Number(detail.marketplaceFees ?? order.marketplaceFees ?? Number(order.total || 0) * 0.12),
      shippingCost: Number(detail.shippingCost ?? order.shippingCost ?? 0),
      refundAmount: Number(detail.refundAmount ?? order.refundAmount ?? 0),
      notes: detail.notes || order.notes || "",
      items: order.items || [
        {
          sku: order.sku,
          title: order.title,
          qty: order.qty,
          price: Number(order.total || 0) / Math.max(1, Number(order.qty || 1))
        }
      ],
      ...order
    };
    enriched.internalOrderNumber = internalOrderNumber;
    enriched.orderNumber = internalOrderNumber;
    enriched.displayOrderNumber = internalOrderNumber;
    enriched.marketplaceOrderNumber = detail.marketplaceOrderId || marketplaceOrderNumber;
    enriched.marketplaceOrderId = enriched.marketplaceOrderNumber;
    enriched.marketplaceReferences = enriched.marketplaceReferences?.length ? enriched.marketplaceReferences : [
      { source: enriched.source, type: "order", value: enriched.marketplaceOrderNumber, primary: true }
    ].filter((reference) => reference.value);
    if (enriched.trackingNumber) {
      const inferredCarrier = inferCarrierFromTracking(enriched.trackingNumber, enriched.shippingCarrier);
      if (inferredCarrier && String(enriched.shippingCarrier || "").toUpperCase() !== String(inferredCarrier).toUpperCase()) {
        enriched.shippingCarrier = inferredCarrier;
        enriched.carrierName = displayCarrierName(inferredCarrier);
        enriched.trackingUrl = trackingUrlForCarrier(inferredCarrier, enriched.trackingNumber);
        changed = true;
      } else if (!enriched.trackingUrl) {
        enriched.trackingUrl = trackingUrlForCarrier(enriched.shippingCarrier, enriched.trackingNumber);
        if (enriched.trackingUrl) changed = true;
      }
    }
    enriched.refunds = (Array.isArray(enriched.refunds) ? enriched.refunds : []).map((refund) => ({
      ...refund,
      items: (Array.isArray(refund.items) ? refund.items : []).map((item, index) => ({
        sku: String(item.sku || "").trim(),
        title: String(item.title || item.sku || "").trim(),
        qty: Number(item.qty || 0),
        price: Number(item.price || 0),
        lineIndex: Number(item.lineIndex || index)
      })).filter((item) => item.sku && item.qty > 0)
    }));
    enriched.timeline = normalizeOrderTimeline(enriched);
    if (!order.internalOrderNumber || !order.customerId || !order.items || order.productCost === undefined || !order.address) changed = true;
    return enriched;
  });
  if (backfillAliasesFromMappedOrders(db)) changed = true;

  const customerResult = normalizeCustomers(db);
  if (customerResult.changed) changed = true;

  if (!Array.isArray(db.orderDrafts)) {
    db.orderDrafts = [];
    changed = true;
  }
  db.orderDrafts = db.orderDrafts.map((draft) => normalizeOrderDraft(db, draft));

  if (!Array.isArray(db.warehouses)) {
    db.warehouses = seedWarehouses();
    changed = true;
  }
  db.warehouses = (db.warehouses || []).map((warehouse) => normalizeWarehouse(warehouse));
  const fallbackWarehouse = db.warehouses.find((warehouse) => warehouse.isDefaultReceiving) || db.warehouses[0];
  db.inventory = (db.inventory || []).map((item) => {
    item.warehouseStock = Array.isArray(item.warehouseStock) ? item.warehouseStock : [];
    if (!item.warehouseStock.length && fallbackWarehouse) {
      item.warehouseStock = [normalizeWarehouseStockRow({
        warehouseId: fallbackWarehouse.id,
        warehouseName: fallbackWarehouse.name,
        qty: Number(item.qty || 0),
        reserved: Number(item.reserved || 0),
        reorderPoint: Number(item.reorderPoint || 0)
      }, fallbackWarehouse, item)];
      changed = true;
    }
    item.warehouseStock = item.warehouseStock.map((row) => {
      const warehouse = db.warehouses.find((item) => item.id === row.warehouseId) || (row.warehouseId ? null : fallbackWarehouse);
      const normalized = normalizeWarehouseStockRow(row, warehouse, item);
      if (!normalized.warehouseId && fallbackWarehouse) {
        normalized.warehouseId = fallbackWarehouse.id;
        normalized.warehouseName = fallbackWarehouse.name;
      }
      return normalized;
    });
    syncInventoryTotalsFromWarehouses(item);
    return item;
  });
  if (db.warehouses.length && !db.warehouses.some((warehouse) => warehouse.isDefaultReceiving)) {
    db.warehouses[0].isDefaultReceiving = true;
    changed = true;
  }
  if (db.warehouses.length && !db.warehouses.some((warehouse) => warehouse.isDefaultReturns)) {
    db.warehouses[0].isDefaultReturns = true;
    changed = true;
  }

  if (!Array.isArray(db.returns)) {
    db.returns = [
      {
        id: crypto.randomUUID(),
        returnNumber: "RET-00001",
        orderNumber: "TT-90221",
        source: "TikTok Shop",
        sku: "DP-BEAUTY-014",
        warehouseId: db.warehouses[0]?.id || "",
        warehouseName: db.warehouses[0]?.name || "",
        reason: "Changed mind",
        amount: 19.99,
        status: "requested",
        createdAt: "2026-04-21T15:20:00.000Z"
      }
    ];
    changed = true;
  }
  {
    const seenReturnNumbers = new Set();
    let nextReturnSequence = 1;
    db.returns = (db.returns || []).map((item) => {
      let returnNumber = String(item.returnNumber || "").trim();
      if (returnNumber && !seenReturnNumbers.has(returnNumber)) {
        seenReturnNumbers.add(returnNumber);
        const match = returnNumber.match(/^RET-(\d+)$/);
        if (match) nextReturnSequence = Math.max(nextReturnSequence, Number(match[1]) + 1);
      } else {
        while (seenReturnNumbers.has(`RET-${String(nextReturnSequence).padStart(5, "0")}`)) nextReturnSequence += 1;
        returnNumber = `RET-${String(nextReturnSequence).padStart(5, "0")}`;
        seenReturnNumbers.add(returnNumber);
        nextReturnSequence += 1;
        changed = true;
      }
      return {
        ...item,
        returnNumber
      };
    });
    db.sequence = db.sequence || {};
    db.sequence.return = Math.max(Number(db.sequence.return || 0), nextReturnSequence - 1);
  }
  {
    db.returns = (db.returns || []).map((item) => ({
      qty: Math.max(1, Number(item.qty || item.quantity || 1)),
      status: String(item.status || "requested"),
      condition: String(item.condition || "Unknown"),
      receivedAt: item.receivedAt || "",
      receivedBy: item.receivedBy || "",
      binLocation: item.binLocation || "",
      inspectionStatus: item.inspectionStatus || "",
      inspectionCondition: item.inspectionCondition || "",
      inspectionNotes: item.inspectionNotes || "",
      disposition: item.disposition || "",
      resolutionNotes: item.resolutionNotes || "",
      resolvedAt: item.resolvedAt || "",
      resolvedBy: item.resolvedBy || "",
      restockedAt: item.restockedAt || "",
      ...item
    }));
  }

  if (!Array.isArray(db.cancellations)) {
    db.cancellations = [
      {
        id: crypto.randomUUID(),
        orderNumber: "TM-66104",
        source: "Temu",
        sku: "DP-HOME-001",
        reason: "Buyer requested cancellation",
        amount: 24.5,
        status: "closed",
        createdAt: "2026-04-19T13:05:00.000Z"
      }
    ];
    changed = true;
  }

  if (!Array.isArray(db.purchaseOrders)) {
    db.purchaseOrders = [];
    changed = true;
  }

  if (!Array.isArray(db.vendors)) {
    db.vendors = seedVendors();
    changed = true;
  }

  if (db.vendors.some((vendor) => !Array.isArray(vendor.changeLog))) changed = true;
  db.vendors = db.vendors.map((vendor) => normalizeVendor(db, vendor));

  const brandResult = normalizeBrands(db);
  if (brandResult.changed) changed = true;

  db.purchaseOrders = db.purchaseOrders.map((po) => ({
    id: po.id || crypto.randomUUID(),
    poNumber: po.poNumber || nextPoNumber(db),
    status: po.status || "draft",
    vendorId: po.vendorId || findVendorByName(db, po.supplier)?.id || "",
    supplier: po.supplier || findVendorById(db, po.vendorId)?.name || "Unassigned supplier",
    warehouseId: po.warehouseId || db.warehouses[0]?.id || "",
    warehouseName: po.warehouseName || (db.warehouses.find((warehouse) => warehouse.id === po.warehouseId)?.name || db.warehouses[0]?.name || ""),
    source: po.source || "manual",
    orderIds: Array.isArray(po.orderIds) ? po.orderIds : [],
    orderNumbers: Array.isArray(po.orderNumbers) ? po.orderNumbers : [],
    items: Array.isArray(po.items) ? po.items : [],
    totalUnits: Number(po.totalUnits || 0),
    estimatedCost: Number(po.estimatedCost || 0),
    notes: po.notes || "",
    createdBy: po.createdBy || "Luis",
    createdAt: po.createdAt || new Date().toISOString(),
    updatedAt: po.updatedAt || po.createdAt || new Date().toISOString(),
    receipts: Array.isArray(po.receipts) ? po.receipts : [],
    receiptDrafts: Array.isArray(po.receiptDrafts) ? po.receiptDrafts : [],
    submissionHistory: Array.isArray(po.submissionHistory) ? po.submissionHistory : [],
    returns: Array.isArray(po.returns) ? po.returns : [],
    timeline: Array.isArray(po.timeline) && po.timeline.length ? po.timeline : [
      {
        id: crypto.randomUUID(),
        type: "created",
        title: "PO created",
        message: `${po.poNumber || "PO"} added to purchasing.`,
        user: po.createdBy || "Luis",
        createdAt: po.createdAt || new Date().toISOString()
      }
    ]
  }));

  for (const vendor of db.vendors) {
    const pos = db.purchaseOrders.filter((po) => po.vendorId === vendor.id || po.supplier === vendor.name);
    vendor.openPOs = pos.filter((po) => !["closed", "canceled"].includes(po.status)).length;
    vendor.totalPOs = pos.length;
    vendor.totalSpend = pos.reduce((sum, po) => sum + Number(po.estimatedCost || 0), 0);
    vendor.lastPOAt = pos[0]?.createdAt || vendor.lastPOAt || "";
  }

  if (changed) db.__normalizedChanged = true;
  else delete db.__normalizedChanged;
  return db;
}

function normalizeShadowSku(shadow = {}, parent = {}) {
  const marketplace = String(shadow.marketplace || shadow.company || "").trim();
  const createdAt = shadow.createdAt || new Date().toISOString();
  return {
    id: shadow.id || crypto.randomUUID(),
    parentSku: shadow.parentSku || parent.sku || "",
    shadowSku: String(shadow.shadowSku || shadow.sku || "").trim(),
    marketplace,
    company: marketplace,
    price: Number(shadow.price ?? parent.price ?? 0),
    handlingTimeDays: Number(shadow.handlingTimeDays ?? shadow.handlingTime ?? 2),
    safetyQty: Number(shadow.safetyQty ?? 0),
    maxSellableQty: Number(shadow.maxSellableQty ?? 0),
    inventoryPolicy: shadow.inventoryPolicy || "Share parent inventory",
    shippingProfile: shadow.shippingProfile || "",
    shippingService: shadow.shippingService || "",
    shippingTemplateId: shadow.shippingTemplateId || "",
    freeShipping: Boolean(shadow.freeShipping ?? false),
    marketplaceAttributes: shadow.marketplaceAttributes || {},
    contentOverrides: {
      title: shadow.contentOverrides?.title || "",
      shortDescription: shadow.contentOverrides?.shortDescription || "",
      longDescription: shadow.contentOverrides?.longDescription || "",
      imageUrls: Array.isArray(shadow.contentOverrides?.imageUrls) ? shadow.contentOverrides.imageUrls : []
    },
    syncStatus: shadow.syncStatus || "Not synced",
    lastSyncAt: shadow.lastSyncAt || "",
    syncHistory: Array.isArray(shadow.syncHistory) ? shadow.syncHistory : [],
    timeline: Array.isArray(shadow.timeline) && shadow.timeline.length ? shadow.timeline : [
      {
        id: crypto.randomUUID(),
        type: "created",
        title: "Shadow SKU created",
        message: `${shadow.shadowSku || shadow.sku || "Shadow SKU"} created for ${marketplace || "marketplace"}.`,
        user: "System",
        createdAt
      }
    ],
    status: shadow.status || "Draft",
    notes: shadow.notes || "",
    createdAt,
    updatedAt: shadow.updatedAt || createdAt
  };
}

function normalizeProductAlias(alias = {}, parent = {}) {
  const aliasSku = String(alias.aliasSku || alias.sku || alias.value || "").trim();
  if (!aliasSku) return null;
  const createdAt = alias.createdAt || new Date().toISOString();
  return {
    id: alias.id || crypto.randomUUID(),
    parentSku: alias.parentSku || parent.sku || "",
    aliasSku,
    source: String(alias.source || alias.marketplace || "").trim(),
    type: String(alias.type || alias.mode || "direct").trim().toLowerCase(),
    active: alias.active !== false,
    createdFromOrderId: alias.createdFromOrderId || alias.orderId || "",
    createdFromOrderNumber: alias.createdFromOrderNumber || alias.orderNumber || "",
    createdFromLineIndex: Number(alias.createdFromLineIndex ?? alias.lineIndex ?? -1),
    createdAt,
    updatedAt: alias.updatedAt || createdAt,
    notes: String(alias.notes || "").trim()
  };
}

function normalizeProductAliases(aliases = [], parent = {}) {
  const seen = new Set();
  return (Array.isArray(aliases) ? aliases : [])
    .map((alias) => normalizeProductAlias(alias, parent))
    .filter(Boolean)
    .filter((alias) => {
      const key = alias.aliasSku.toLowerCase();
      if (key === String(parent.sku || "").toLowerCase()) return false;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
}

function skuMatchesProduct(product = {}, sku = "") {
  const key = String(sku || "").trim().toLowerCase();
  if (!key) return false;
  if (String(product.sku || "").trim().toLowerCase() === key) return true;
  if ((product.aliases || []).some((alias) => alias.active !== false && String(alias.aliasSku || "").trim().toLowerCase() === key)) return true;
  if ((product.shadowSkus || []).some((shadow) => String(shadow.shadowSku || "").trim().toLowerCase() === key)) return true;
  return Object.values(product.sources || {}).some((value) => String(value || "").trim().toLowerCase() === key);
}

function findInventoryBySkuOrAlias(db = {}, sku = "") {
  return (db.inventory || []).find((product) => skuMatchesProduct(product, sku)) || null;
}

function findAliasOwner(db = {}, aliasSku = "") {
  const key = String(aliasSku || "").trim().toLowerCase();
  if (!key) return null;
  for (const product of db.inventory || []) {
    const alias = (product.aliases || []).find((row) => String(row.aliasSku || "").trim().toLowerCase() === key);
    if (alias) return { product, alias };
  }
  return null;
}

function addProductAlias(db, product, aliasSku, body = {}) {
  const value = String(aliasSku || "").trim();
  if (!value || String(product.sku || "").toLowerCase() === value.toLowerCase()) return null;
  const owner = findAliasOwner(db, value);
  if (owner && owner.product.id !== product.id) throw new Error(`Alias SKU ${value} already belongs to ${owner.product.sku}.`);
  product.aliases = normalizeProductAliases(product.aliases, product);
  const existing = product.aliases.find((alias) => String(alias.aliasSku || "").toLowerCase() === value.toLowerCase());
  if (existing) {
    existing.active = true;
    existing.updatedAt = new Date().toISOString();
    return existing;
  }
  const alias = normalizeProductAlias({
    aliasSku: value,
    parentSku: product.sku,
    source: body.source || body.marketplace || "",
    type: body.type || body.mode || "direct",
    createdFromOrderId: body.createdFromOrderId || "",
    createdFromOrderNumber: body.createdFromOrderNumber || "",
    createdFromLineIndex: body.createdFromLineIndex,
    notes: body.notes || ""
  }, product);
  product.aliases.push(alias);
  product.updatedAt = new Date().toISOString();
  return alias;
}

function backfillAliasesFromMappedOrders(db = {}) {
  let changed = false;
  for (const order of db.orders || []) {
    const items = orderLineItems(order);
    for (let index = 0; index < items.length; index += 1) {
      const line = items[index];
      const aliasSku = String(line.originalSku || line.mappedFromSku || line.shadowSku || "").trim();
      const parentSku = String(line.parentSku || line.sku || "").trim();
      if (!aliasSku || !parentSku || aliasSku.toLowerCase() === parentSku.toLowerCase()) continue;
      const product = (db.inventory || []).find((item) => String(item.sku || "").toLowerCase() === parentSku.toLowerCase());
      if (!product) continue;
      try {
        const before = (product.aliases || []).length;
        addProductAlias(db, product, aliasSku, {
          source: order.source,
          type: String(line.skuMappingMode || "").includes("shadow") ? "shadow" : "direct",
          createdFromOrderId: order.id,
          createdFromOrderNumber: order.orderNumber,
          createdFromLineIndex: index,
          notes: "Backfilled from mapped order line"
        });
        if ((product.aliases || []).length !== before) changed = true;
      } catch {
        // Alias conflicts are left for manual review instead of blocking app startup.
      }
    }
  }
  return changed;
}

function normalizeChannel(channel = {}) {
  const rawSettings = channel.settings || {};
  const isShopify = String(channel.name || "").trim().toLowerCase() === "shopify";
  const settings = {
    ...DEFAULT_CHANNEL_SETTINGS,
    ...rawSettings,
    ...(isShopify ? { priceMarkupPercent: SHOPIFY_PRICE_MARKUP_PERCENT } : {})
  };
  if (rawSettings.pricingRuleVersion !== 1 && Number(settings.priceMarkupPercent || 0) <= 0) {
    settings.priceMarkupPercent = isShopify ? SHOPIFY_PRICE_MARKUP_PERCENT : DEFAULT_CHANNEL_SETTINGS.priceMarkupPercent;
  }
  settings.pricingRuleVersion = 1;
  for (const field of ["defaultHandlingTimeDays", "defaultSafetyQty", "defaultMaxSellableQty", "priceMarkupPercent", "pricingRuleVersion", "minMarginPercent", "ebayMaxImages", "shopifyStatusSyncLimit", "shopifyOrderImportLimit"]) {
    settings[field] = Number(settings[field] || 0);
  }
  for (const field of ["priceUpdateEnabled", "inventoryUpdateEnabled", "orderDownloadEnabled", "trackingUpdateEnabled", "cancellationNotificationEnabled", "autoCreateShadow", "ebayAutoPublish", "ebayRequireImage", "ebayBestOfferEnabled", "shopifySyncStatusEnabled", "shopifyAutoSyncStatus", "shopifyCloseoutsEnabled", "shopifyOrderImportEnabled", "shopifyOrderImportIncludeCanceled", "shopifyInventoryPushEnabled"]) {
    settings[field] = settings[field] === true || String(settings[field]).toLowerCase() === "true";
  }
  for (const field of ["inventoryScheduleEnabled", "inventoryScheduleRequireSuccessfulDump", "shopifySkuMapScheduleEnabled"]) {
    settings[field] = settings[field] === true || String(settings[field]).toLowerCase() === "true";
  }
  settings.inventoryScheduleMode = String(settings.inventoryScheduleMode || "dry-run").toLowerCase() === "apply" ? "apply" : "dry-run";
  settings.inventoryScheduleType = String(settings.inventoryScheduleType || "times").toLowerCase() === "interval" ? "interval" : "times";
  settings.inventoryScheduleEveryHours = Math.max(1, Math.min(24, Number(settings.inventoryScheduleEveryHours || 12) || 12));
  settings.inventoryScheduleTimes = normalizeChannelScheduleTimes(settings.inventoryScheduleTimes || DEFAULT_CHANNEL_SETTINGS.inventoryScheduleTimes);
  settings.shopifySkuMapScheduleTime = normalizeChannelScheduleTimes(settings.shopifySkuMapScheduleTime || DEFAULT_CHANNEL_SETTINGS.shopifySkuMapScheduleTime).split(",")[0];
  settings.shopifyShippingProfiles = normalizeShopifyShippingProfiles(settings.shopifyShippingProfiles);
  settings.shopifyShippingProfilesSyncedAt = String(settings.shopifyShippingProfilesSyncedAt || "");
  return {
    id: channel.id || crypto.randomUUID(),
    name: channel.name || "Marketplace",
    connected: Boolean(channel.connected),
    status: channel.status || (channel.connected ? "active" : "inactive"),
    lastSync: channel.lastSync || null,
    logoUrl: channel.logoUrl || "",
    logoDataUrl: channel.logoDataUrl || "",
    notes: channel.notes || "",
    settings
  };
}

function normalizeShopifyShippingProfiles(value = []) {
  const rows = Array.isArray(value) ? value : [];
  const byId = new Map();
  for (const row of rows) {
    if (!row || typeof row !== "object") continue;
    const id = String(row.id || row.gid || "").trim();
    const name = String(row.name || row.title || "").trim();
    if (!id && !name) continue;
    const normalized = {
      id,
      name: name || id,
      default: row.default === true || String(row.default || "").toLowerCase() === "true",
      profileLocationGroupsCount: Number(row.profileLocationGroupsCount || row.locationGroupsCount || 0) || 0,
      productVariantsCount: Number(row.productVariantsCount || row.variantsCount || 0) || 0
    };
    byId.set(id || normalized.name.toLowerCase(), normalized);
  }
  return [...byId.values()].sort((a, b) => String(a.name || "").localeCompare(String(b.name || "")));
}

function normalizeChannelScheduleTimes(value = "") {
  const values = (Array.isArray(value) ? value : String(value || "").split(/[,;\s]+/))
    .map((item) => String(item || "").trim())
    .filter(Boolean)
    .map((item) => {
      const match = item.match(/^(\d{1,2}):([0-5]\d)$/);
      if (!match) return "";
      const hour = Number(match[1]);
      if (hour < 0 || hour > 23) return "";
      return `${String(hour).padStart(2, "0")}:${match[2]}`;
    })
    .filter(Boolean);
  return [...new Set(values)].join(",") || DEFAULT_CHANNEL_SETTINGS.inventoryScheduleTimes;
}

function findChannelByName(db, name = "") {
  const key = String(name).toLowerCase();
  return (db.connections || []).find((channel) => String(channel.name || "").toLowerCase() === key);
}

function resolveShopifyInventoryLocation(db, body = {}) {
  const settings = findChannelByName(db, "Shopify")?.settings || DEFAULT_CHANNEL_SETTINGS;
  const warehouses = Array.isArray(db.warehouses) ? db.warehouses.map(normalizeWarehouse) : [];
  const requestedWarehouse = warehouses.find((warehouse) => warehouse.id === body.warehouseId)
    || warehouses.find((warehouse) => warehouse.id === settings.shopifyInventoryWarehouseId)
    || null;
  const enabledWarehouse = warehouses.find((warehouse) => warehouse.shopifyInventoryPushEnabled && normalizeShopifyLocationGid(warehouse.shopifyLocationId));
  const defaultReceivingWarehouse = warehouses.find((warehouse) => warehouse.isDefaultReceiving && normalizeShopifyLocationGid(warehouse.shopifyLocationId));
  const warehouse = requestedWarehouse || enabledWarehouse || defaultReceivingWarehouse || null;
  const locationId = normalizeShopifyLocationGid(body.locationId)
    || normalizeShopifyLocationGid(settings.shopifyInventoryLocationId)
    || normalizeShopifyLocationGid(warehouse?.shopifyLocationId);
  return {
    settings,
    warehouse,
    locationId,
    locationName: warehouse?.shopifyLocationName || ""
  };
}

async function queueShopifyInventoryUpdateJob(db, body = {}, options = {}) {
  const apply = body.apply !== false && body.dryRun !== true;
  const limit = Math.max(0, Number(body.limit || 0) || 0);
  const productBatchSize = Math.max(1, Math.min(50, Number(body.productBatchSize || 35) || 35));
  const batchSize = Math.max(1, Math.min(250, Number(body.batchSize || 100) || 100));
  const packMode = ["divide", "export"].includes(String(body.packMode || "").toLowerCase()) ? String(body.packMode).toLowerCase() : "export";
  const inventoryTarget = resolveShopifyInventoryLocation(db, body);
  if (apply && !inventoryTarget.settings.shopifyInventoryPushEnabled) {
    const error = new Error("Enable DataPlus inventory push in Shopify channel settings before applying inventory.");
    error.statusCode = 400;
    throw error;
  }
  if (apply && !inventoryTarget.locationId) {
    const error = new Error("Map a DataPlus warehouse to a Shopify location before applying inventory.");
    error.statusCode = 400;
    throw error;
  }
  const workerPayload = {
    apply,
    dryRun: !apply,
    limit,
    productBatchSize,
    batchSize,
    packMode,
    locationId: inventoryTarget.locationId || "",
    warehouseId: inventoryTarget.warehouse?.id || "",
    warehouseName: inventoryTarget.warehouse?.name || "",
    locationName: inventoryTarget.locationName || "",
    scheduleKey: options.scheduleKey || "",
    scheduled: options.scheduled === true
  };
  const operation = options.operation || (apply ? "Shopify inventory update" : "Shopify inventory dry run");
  const duplicate = await findActiveDuplicateImportJob(db, {
    section: "Products",
    operation,
    direction: "sync",
    fileName: "shopify-inventory-report.json",
    workerTask: "shopify-inventory-update",
    workerPayload
  });
  if (duplicate) {
    if (!options.scheduled) {
      appendChannelApiLog({
        channel: "Shopify",
        transport: "Job",
        method: "QUEUE",
        path: "shopify-inventory-update",
        operation: apply ? "Inventory update already queued" : "Inventory dry run already queued",
        statusCode: 202,
        ok: true,
        jobId: duplicate.id,
        message: `${duplicate.operation || operation} is already ${String(duplicate.status || "queued").toLowerCase()}${inventoryTarget.warehouse?.name ? ` for ${inventoryTarget.warehouse.name}` : ""}.`
      });
    }
    return { duplicate, job: duplicate, workerPayload, inventoryTarget };
  }
  const schedulePrefix = options.scheduled ? "Scheduled " : "";
  const job = createImportJob(db, {
    section: "Products",
    operation,
    direction: "sync",
    status: "queued",
    fileName: "shopify-inventory-report.json",
    totalRows: limit || 50000,
    processedRows: 0,
    progressPercent: 0,
    phase: "queued",
    workerTask: "shopify-inventory-update",
    workerPayload,
    message: apply
      ? `${schedulePrefix}Shopify inventory update queued from the latest data dump${inventoryTarget.warehouse?.name ? ` for ${inventoryTarget.warehouse.name}` : ""}.`
      : `${schedulePrefix}Shopify inventory dry run queued from the latest data dump${inventoryTarget.warehouse?.name ? ` for ${inventoryTarget.warehouse.name}` : ""}.`
  });
  upsertImportJobStore(job);
  if (postgres.isPostgresEnabled()) await postgres.upsertOperationJob(job);
  appendChannelApiLog({
    channel: "Shopify",
    transport: "Job",
    method: "QUEUE",
    path: "shopify-inventory-update",
    operation: apply ? "Inventory update queued" : "Inventory dry run queued",
    statusCode: 202,
    ok: true,
    jobId: job.id,
    message: `${job.message} Location ${inventoryTarget.locationId || "not mapped"}; batch ${batchSize}; product batch ${productBatchSize};${limit ? ` limit ${limit};` : ""} pack mode ${packMode}.`
  });
  return { job, workerPayload, inventoryTarget };
}

async function queueShopifySkuMapSyncJob(db, body = {}, options = {}) {
  const limit = Math.max(0, Math.min(500000, Number(body.limit || 0) || 0));
  const pageSize = Math.max(1, Math.min(250, Number(body.pageSize || 250) || 250));
  const channel = findChannelByName(db, "Shopify");
  if (!channel) {
    const error = new Error("Shopify channel was not found.");
    error.statusCode = 404;
    throw error;
  }
  const workerPayload = {
    limit,
    pageSize,
    scheduled: options.scheduled === true,
    scheduleKey: options.scheduleKey || ""
  };
  const operation = options.operation || "Shopify SKU pair audit";
  const duplicate = await findActiveDuplicateImportJob(db, {
    section: "Products",
    operation,
    direction: "sync",
    fileName: "shopify-sku-map-sync.json",
    workerTask: "shopify-sku-map-sync",
    workerPayload
  });
  if (duplicate) return { duplicate: true, job: duplicate, workerPayload };

  const job = createImportJob(db, {
    section: "Products",
    operation,
    direction: "sync",
    status: "queued",
    fileName: "shopify-sku-map-sync.json",
    totalRows: limit || pageSize,
    processedRows: 0,
    progressPercent: 0,
    phase: "queued",
    workerTask: shouldRunJobsInline() ? "" : "shopify-sku-map-sync",
    workerPayload: shouldRunJobsInline() ? {} : workerPayload,
    message: limit
      ? `Shopify SKU pair audit queued for up to ${limit.toLocaleString()} variant${limit === 1 ? "" : "s"}.`
      : "Shopify SKU pair audit queued for the full Shopify variant catalog."
  });
  upsertImportJobStore(job);
  if (postgres.isPostgresEnabled()) await postgres.upsertOperationJob(job);
  appendChannelApiLog({
    channel: "Shopify",
    transport: "Job",
    method: "QUEUE",
    path: "shopify-sku-map-sync",
    operation: "SKU product and variant pair audit queued",
    statusCode: 202,
    ok: true,
    jobId: job.id,
    message: `${job.message} Each matched SKU records both its Shopify product ID and Shopify variant ID.`
  });
  if (shouldRunJobsInline()) {
    setTimeout(() => runShopifySkuMapSyncWorkerJob(job, workerPayload).catch((error) => {
      finishImportJob(job, {
        status: "failed",
        message: error.message || "Shopify SKU pair audit failed.",
        errors: [error.message || "Shopify SKU pair audit failed."],
        missingCount: 1,
        phase: "failed",
        estimatedSecondsRemaining: 0
      });
      upsertImportJobStore(job);
    }), 250);
  }
  return { duplicate: false, job, workerPayload };
}

function applyChannelDefaultsToShadow(db, shadow, marketplace) {
  const channel = findChannelByName(db, marketplace);
  const settings = channel?.settings || DEFAULT_CHANNEL_SETTINGS;
  if (shadow.status === undefined) shadow.status = settings.defaultShadowStatus;
  if (shadow.handlingTimeDays === undefined) shadow.handlingTimeDays = settings.defaultHandlingTimeDays;
  if (shadow.safetyQty === undefined) shadow.safetyQty = settings.defaultSafetyQty;
  if (shadow.maxSellableQty === undefined) shadow.maxSellableQty = settings.defaultMaxSellableQty;
  if (shadow.shippingProfile === undefined) shadow.shippingProfile = settings.defaultShippingProfile;
  if (shadow.shippingService === undefined) shadow.shippingService = settings.defaultShippingService;
  return shadow;
}

function parseTemplateList(value) {
  if (Array.isArray(value)) return value.map(String).map((item) => item.trim()).filter(Boolean);
  return String(value || "")
    .split(/\r?\n|,/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeMarketplaceTemplate(template = {}) {
  const requiredAttributes = parseTemplateList(template.requiredAttributes);
  const fieldDefinitions = normalizeTemplateFields(template.fieldDefinitions, requiredAttributes, template.optionLists);
  return {
    id: template.id || crypto.randomUUID(),
    marketplace: String(template.marketplace || "").trim(),
    requiredAttributes,
    fieldDefinitions,
    optionLists: template.optionLists && typeof template.optionLists === "object" ? template.optionLists : Object.fromEntries(fieldDefinitions.filter((field) => field.options?.length).map((field) => [field.key, field.options])),
    categoryMappings: Array.isArray(template.categoryMappings) ? template.categoryMappings.map((mapping) => ({
      id: mapping.id || crypto.randomUUID(),
      internalCategory: mapping.internalCategory || "",
      marketplaceCategory: mapping.marketplaceCategory || "",
      marketplaceCategoryId: mapping.marketplaceCategoryId || ""
    })) : [],
    titleMaxLength: Number(template.titleMaxLength || 120),
    minImages: Number(template.minImages || 1),
    requireShippingProfile: template.requireShippingProfile !== false,
    requireHandlingTime: template.requireHandlingTime !== false,
    requirePrice: template.requirePrice !== false,
    notes: template.notes || "",
    updatedAt: template.updatedAt || new Date().toISOString()
  };
}

function normalizeTemplateFields(fields, requiredAttributes = [], optionLists = {}) {
  const source = Array.isArray(fields) && fields.length ? fields : requiredAttributes.map((key) => ({ key }));
  return source.map((field) => {
    const key = String(field.key || field.name || "").trim();
    const options = Array.isArray(field.options)
      ? field.options.map(String).filter(Boolean)
      : parseTemplateList(optionLists?.[key] || field.options || "");
    return {
      key,
      type: field.type || (options.length ? "select" : "text"),
      options,
      required: field.required !== false
    };
  }).filter((field) => field.key);
}

function parseTemplateFields(value) {
  if (Array.isArray(value)) return normalizeTemplateFields(value);
  return String(value || "")
    .split(/\r?\n/)
    .map((line) => {
      const [key, type = "text", options = ""] = line.split("|").map((part) => part.trim());
      return key ? { key, type, options: parseTemplateList(options.replaceAll(";", ",")), required: true } : null;
    })
    .filter(Boolean);
}

function addShadowTimeline(shadow, event) {
  shadow.timeline = Array.isArray(shadow.timeline) ? shadow.timeline : [];
  shadow.timeline.push({
    id: crypto.randomUUID(),
    type: "edited",
    title: "Shadow updated",
    message: "",
    user: "Luis",
    createdAt: new Date().toISOString(),
    ...event
  });
}

function normalizeMarketplaceTemplates(templates = []) {
  const existing = new Map((Array.isArray(templates) ? templates : []).map((template) => [String(template.marketplace || "").toLowerCase(), template]));
  const merged = DEFAULT_MARKETPLACE_TEMPLATES.map((defaults) => normalizeMarketplaceTemplate({ ...defaults, ...(existing.get(defaults.marketplace.toLowerCase()) || {}) }));
  for (const template of Array.isArray(templates) ? templates : []) {
    const key = String(template.marketplace || "").toLowerCase();
    if (key && !DEFAULT_MARKETPLACE_TEMPLATES.some((defaults) => defaults.marketplace.toLowerCase() === key)) {
      merged.push(normalizeMarketplaceTemplate(template));
    }
  }
  return merged;
}

function parseMappingRows(rows) {
  if (Array.isArray(rows)) return rows;
  return String(rows || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      const [externalColumn, productField, defaultValue = ""] = line.split("|").map((part) => part.trim());
      return { externalColumn, productField, defaultValue };
    });
}

function normalizeExportMappingRow(row = {}) {
  return {
    id: row.id || crypto.randomUUID(),
    externalColumn: String(row.externalColumn || row.column || "").trim(),
    productField: String(row.productField || row.field || "").trim(),
    defaultValue: row.defaultValue === undefined ? "" : String(row.defaultValue),
    transform: String(row.transform || "").trim(),
    required: Boolean(row.required)
  };
}

function normalizeExportMapping(template = {}) {
  const mappings = parseMappingRows(template.mappings).map(normalizeExportMappingRow).filter((row) => row.externalColumn);
  const formatType = String(template.formatType || template.exportFormat || template.marketplaceFormat || "normal").trim().toLowerCase() || "normal";
  return {
    id: template.id || crypto.randomUUID(),
    name: String(template.name || template.source || "Product Export Mapping").trim(),
    source: String(template.source || template.channel || "Custom").trim(),
    format: "csv",
    formatType,
    mode: template.mode || "both",
    status: template.status || "active",
    mappings,
    notes: template.notes || "",
    omitSyntheticShopifyVariantMetafields: template.omitSyntheticShopifyVariantMetafields === true,
    createdAt: template.createdAt || new Date().toISOString(),
    updatedAt: template.updatedAt || template.createdAt || new Date().toISOString()
  };
}

function mergeDefaultExportMappings(defaultTemplate = {}, existingTemplate = {}) {
  const existing = normalizeExportMapping({ ...defaultTemplate, ...existingTemplate });
  const existingByColumn = new Map(existing.mappings.map((row) => [row.externalColumn.toLowerCase(), row]));
  const orderedDefaults = parseMappingRows(defaultTemplate.mappings)
    .map(normalizeExportMappingRow)
    .filter((row) => row.externalColumn)
    .map((row) => existingByColumn.get(row.externalColumn.toLowerCase()) || row);
  const defaultColumns = new Set(orderedDefaults.map((row) => row.externalColumn.toLowerCase()));
  const customRows = existing.mappings.filter((row) => !defaultColumns.has(row.externalColumn.toLowerCase()));
  return normalizeExportMapping({
    ...existing,
    mappings: [...orderedDefaults, ...customRows]
  });
}

function normalizeExportMappings(templates = []) {
  const input = Array.isArray(templates) ? templates : [];
  const existing = new Map(input.map((template) => [String(template.id || template.name || "").toLowerCase(), template]));
  const merged = DEFAULT_EXPORT_MAPPINGS.map((defaults) => mergeDefaultExportMappings(defaults, existing.get(defaults.id.toLowerCase()) || {}));
  for (const template of input) {
    const key = String(template.id || "").toLowerCase();
    if (!DEFAULT_EXPORT_MAPPINGS.some((defaults) => defaults.id.toLowerCase() === key)) merged.push(normalizeExportMapping(template));
  }
  return merged;
}

function readExportMappingsStore(fallback = []) {
  if (fs.existsSync(EXPORT_MAPPINGS_FILE)) {
    try {
      const parsed = JSON.parse(fs.readFileSync(EXPORT_MAPPINGS_FILE, "utf8"));
      return normalizeExportMappings(Array.isArray(parsed) ? parsed : parsed.exportMappings || []);
    } catch {
      return normalizeExportMappings(fallback);
    }
  }
  return normalizeExportMappings(fallback);
}

function readExportMappingsFastStore() {
  if (fs.existsSync(EXPORT_MAPPINGS_FILE)) return readExportMappingsStore([]);
  const normalized = normalizeExportMappings([]);
  try {
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    fs.writeFileSync(EXPORT_MAPPINGS_FILE, JSON.stringify(normalized, null, 2));
  } catch {
    // Keep serving built-in mappings if the sidecar cannot be created yet.
  }
  return normalized;
}

async function readExportMappingsApiStore() {
  if (fs.existsSync(EXPORT_MAPPINGS_FILE)) return readExportMappingsStore([]);
  let fallback = [];
  if (postgres.isPostgresEnabled()) {
    try {
      fallback = await postgres.readStateField("exportMappings") || [];
    } catch {
      fallback = [];
    }
  }
  const normalized = normalizeExportMappings(fallback);
  try {
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    fs.writeFileSync(EXPORT_MAPPINGS_FILE, JSON.stringify(normalized, null, 2));
  } catch {
    // The API can still return built-ins/legacy mappings even if the sidecar write fails.
  }
  return normalized;
}

async function writeExportMappingsStore(exportMappings = []) {
  const normalized = normalizeExportMappings(exportMappings);
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.writeFileSync(EXPORT_MAPPINGS_FILE, JSON.stringify(normalized, null, 2));
  return normalized;
}

function normalizeSystemSettings(settings = {}) {
  const normalized = { ...DEFAULT_SYSTEM_SETTINGS, ...(settings && typeof settings === "object" ? settings : {}) };
  if (settings.backgroundJobsMode === undefined && process.env.DATAPLUS_BACKGROUND_JOBS_MODE) normalized.backgroundJobsMode = process.env.DATAPLUS_BACKGROUND_JOBS_MODE;
  if (settings.backupIncludeSourceCatalog === undefined && process.env.DATAPLUS_BACKUP_INCLUDE_SOURCE_CATALOG) normalized.backupIncludeSourceCatalog = ["1", "true", "yes"].includes(String(process.env.DATAPLUS_BACKUP_INCLUDE_SOURCE_CATALOG).toLowerCase());
  if (settings.backupRetentionDays === undefined && process.env.DATAPLUS_BACKUP_RETENTION_DAYS) normalized.backupRetentionDays = Number(process.env.DATAPLUS_BACKUP_RETENTION_DAYS || 30);
  if (settings.autoDataQualityScanAfterImports === undefined && process.env.DATAPLUS_AUTO_DATA_QUALITY_SCAN_AFTER_IMPORTS) normalized.autoDataQualityScanAfterImports = ["1", "true", "yes"].includes(String(process.env.DATAPLUS_AUTO_DATA_QUALITY_SCAN_AFTER_IMPORTS).toLowerCase());
  if (settings.dataQualityWorkerEnabled === undefined && process.env.DATAPLUS_DATA_QUALITY_WORKER_ENABLED) normalized.dataQualityWorkerEnabled = ["1", "true", "yes"].includes(String(process.env.DATAPLUS_DATA_QUALITY_WORKER_ENABLED).toLowerCase());
  if (!["inline", "worker"].includes(String(normalized.backgroundJobsMode || "").toLowerCase())) normalized.backgroundJobsMode = "inline";
  if (!["new-and-update", "new-only", "update-existing"].includes(String(normalized.sourceCatalogDefaultImportMode || "").toLowerCase())) normalized.sourceCatalogDefaultImportMode = "new-and-update";
  normalized.backgroundJobsMode = String(normalized.backgroundJobsMode || "inline").toLowerCase();
  normalized.sourceCatalogDefaultImportMode = String(normalized.sourceCatalogDefaultImportMode || "new-and-update").toLowerCase();
  normalized.shopifyDailyInventoryUpdateEnabled = normalized.shopifyDailyInventoryUpdateEnabled === true || String(normalized.shopifyDailyInventoryUpdateEnabled).toLowerCase() === "true";
  normalized.shopifyDailyInventoryUpdateMode = String(normalized.shopifyDailyInventoryUpdateMode || "dry-run").toLowerCase() === "apply" ? "apply" : "dry-run";
  normalized.shopifyDailyInventoryRequireSuccessfulDump = normalized.shopifyDailyInventoryRequireSuccessfulDump !== false;
  normalized.shopifyDailyInventoryUpdateTime = /^([01]\d|2[0-3]):[0-5]\d$/.test(String(normalized.shopifyDailyInventoryUpdateTime || "")) ? String(normalized.shopifyDailyInventoryUpdateTime) : "06:00";
  normalized.backupRetentionDays = Math.max(1, Math.min(365, Number(normalized.backupRetentionDays || 30) || 30));
  normalized.jobsRetentionDays = IMPORT_JOB_FILE_RETENTION_DAYS;
  normalized.jobsRetentionAutoCleanupEnabled = normalized.jobsRetentionAutoCleanupEnabled !== false;
  normalized.systemUsers = (Array.isArray(normalized.systemUsers) ? normalized.systemUsers : DEFAULT_SYSTEM_SETTINGS.systemUsers)
    .map((user, index) => ({
      id: String(user.id || crypto.randomUUID?.() || `user-${index + 1}`),
      name: sourceTextValue(user.name || user.displayName || ""),
      email: sourceTextValue(user.email || ""),
      role: sourceTextValue(user.role || "Operator"),
      status: ["active", "inactive"].includes(String(user.status || "").toLowerCase()) ? String(user.status).toLowerCase() : "active"
    }))
    .filter((user) => user.name || user.email);
  const activeUserIds = new Set(normalized.systemUsers.map((user) => String(user.id || "")));
  normalized.activeSystemUserId = activeUserIds.has(String(normalized.activeSystemUserId || ""))
    ? String(normalized.activeSystemUserId)
    : (normalized.systemUsers[0]?.id || "owner");
  normalized.permissionRoles = (Array.isArray(normalized.permissionRoles) ? normalized.permissionRoles : DEFAULT_SYSTEM_SETTINGS.permissionRoles)
    .map((role, index) => ({
      id: String(role.id || `role-${index + 1}`),
      name: sourceTextValue(role.name || ""),
      permissions: Array.isArray(role.permissions) ? role.permissions.map(sourceTextValue).filter(Boolean) : parseList(role.permissions)
    }))
    .filter((role) => role.name);
  return normalized;
}

function readSystemSettingsStore(fallback = {}) {
  if (postgres.isPostgresEnabled() && fallback && typeof fallback === "object" && Object.keys(fallback).length) {
    return normalizeSystemSettings(fallback);
  }
  if (fs.existsSync(SYSTEM_SETTINGS_FILE)) {
    try {
      return normalizeSystemSettings(JSON.parse(fs.readFileSync(SYSTEM_SETTINGS_FILE, "utf8")));
    } catch {
      return normalizeSystemSettings(fallback);
    }
  }
  return normalizeSystemSettings(fallback);
}

function writeSystemSettingsStore(settings = {}) {
  const normalized = normalizeSystemSettings(settings);
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.writeFileSync(SYSTEM_SETTINGS_FILE, JSON.stringify(normalized, null, 2));
  if (postgres.isPostgresEnabled()) {
    postgres.writeStateDocuments({ systemSettings: normalized }).catch((error) => {
      console.error("Unable to persist system settings to Postgres", error.message || error);
    });
  }
  return normalized;
}

const TABLE_PREFERENCE_IDS = new Set(["orders", "catalog.products", "catalog.inventory"]);
const TABLE_PREFERENCE_SORT_DIRECTIONS = new Set(["asc", "desc"]);

function normalizeTablePreference(preference = {}) {
  const source = preference && typeof preference === "object" ? preference : {};
  const visibleColumns = Array.isArray(source.visibleColumns)
    ? [...new Set(source.visibleColumns.map(sourceTextValue).filter(Boolean))]
    : [];
  const sortSource = source.sort && typeof source.sort === "object" ? source.sort : {};
  const sortKey = sourceTextValue(sortSource.key || "");
  const sortDirection = TABLE_PREFERENCE_SORT_DIRECTIONS.has(String(sortSource.direction || "").toLowerCase())
    ? String(sortSource.direction).toLowerCase()
    : "";
  const normalized = {};
  if (visibleColumns.length) normalized.visibleColumns = visibleColumns;
  if (sortKey) normalized.sort = { key: sortKey, direction: sortDirection || "asc" };
  if (["compact", "comfortable"].includes(String(source.density || "").toLowerCase())) normalized.density = String(source.density).toLowerCase();
  if (Array.isArray(source.pinnedColumns)) normalized.pinnedColumns = [...new Set(source.pinnedColumns.map(sourceTextValue).filter(Boolean))];
  return normalized;
}

function normalizeUserTablePreferences(preferences = {}) {
  if (!preferences || typeof preferences !== "object") return {};
  return Object.entries(preferences).reduce((users, [userId, userPrefs]) => {
    const normalizedUserId = sourceTextValue(userId);
    if (!normalizedUserId || !userPrefs || typeof userPrefs !== "object") return users;
    const normalizedTables = {};
    for (const [tableId, preference] of Object.entries(userPrefs)) {
      if (!TABLE_PREFERENCE_IDS.has(tableId)) continue;
      normalizedTables[tableId] = normalizeTablePreference(preference);
    }
    if (Object.keys(normalizedTables).length) users[normalizedUserId] = normalizedTables;
    return users;
  }, {});
}

function readUserTablePreferencesFile(fallback = {}) {
  if (fs.existsSync(USER_TABLE_PREFERENCES_FILE)) {
    try {
      return normalizeUserTablePreferences(JSON.parse(fs.readFileSync(USER_TABLE_PREFERENCES_FILE, "utf8")));
    } catch {
      return normalizeUserTablePreferences(fallback);
    }
  }
  return normalizeUserTablePreferences(fallback);
}

async function readUserTablePreferencesStore(fallback = {}) {
  if (postgres.isPostgresEnabled()) {
    try {
      return normalizeUserTablePreferences(await postgres.readUserTablePreferences());
    } catch (error) {
      console.error("Unable to read user table preferences from Postgres", error.message || error);
    }
  }
  return readUserTablePreferencesFile(fallback);
}

async function writeUserTablePreferenceStore(userId, tableId, preference = {}) {
  const normalizedUserId = sourceTextValue(userId) || "owner";
  const normalizedTableId = sourceTextValue(tableId);
  if (!TABLE_PREFERENCE_IDS.has(normalizedTableId)) {
    const error = new Error("Unknown table preference.");
    error.statusCode = 400;
    throw error;
  }
  const normalizedPreference = normalizeTablePreference(preference);
  if (postgres.isPostgresEnabled()) {
    await postgres.upsertUserTablePreference(normalizedUserId, normalizedTableId, normalizedPreference);
    return normalizedPreference;
  }
  const preferences = readUserTablePreferencesFile();
  preferences[normalizedUserId] = preferences[normalizedUserId] || {};
  preferences[normalizedUserId][normalizedTableId] = normalizedPreference;
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  fs.writeFileSync(USER_TABLE_PREFERENCES_FILE, JSON.stringify(normalizeUserTablePreferences(preferences), null, 2));
  return normalizedPreference;
}

async function readWorkerStatus(settings = readSystemSettingsStore({})) {
  settings = settings && typeof settings === "object" && !Array.isArray(settings) ? settings : {};
  const docs = postgres.isPostgresEnabled() ? await postgres.readStateDocuments().catch(() => ({})) : {};
  const heartbeat = docs?.workerHeartbeat && typeof docs.workerHeartbeat === "object" ? docs.workerHeartbeat : {};
  const lastSeenAt = heartbeat.lastSeenAt || "";
  const lastSeenMs = lastSeenAt ? new Date(lastSeenAt).getTime() : 0;
  const ageSeconds = lastSeenMs ? Math.max(0, Math.round((Date.now() - lastSeenMs) / 1000)) : null;
  const staleAfterSeconds = Math.max(30, Math.ceil((Number(heartbeat.heartbeatMs || heartbeat.pollMs || 5000) * 3) / 1000));
  const configured = String(settings.backgroundJobsMode || "inline").toLowerCase() === "worker";
  const heartbeatStatus = String(heartbeat.status || "unknown").toLowerCase();
  const online = configured && ageSeconds !== null && ageSeconds <= staleAfterSeconds && !["stopped", "failed", "exited"].includes(heartbeatStatus);
  return {
    configured,
    online,
    stale: configured && !online,
    status: heartbeat.status || "unknown",
    workerId: heartbeat.workerId || "",
    currentJobId: heartbeat.currentJobId || "",
    currentTask: heartbeat.currentTask || "",
    lastSeenAt,
    ageSeconds,
    staleAfterSeconds,
    supportedTasks: Array.isArray(heartbeat.supportedTasks) ? heartbeat.supportedTasks : [],
    pollMs: Number(heartbeat.pollMs || 0) || 0,
    heartbeatMs: Number(heartbeat.heartbeatMs || 0) || 0,
    runOnce: heartbeat.runOnce === true
  };
}

function workerJobLooksAbandoned(job = {}, workerStatus = {}) {
  if (!isExternalWorkerJob(job)) return false;
  const status = String(job.status || "").toLowerCase();
  if (status !== "running") return false;
  if (workerStatus.online) return false;
  const updatedMs = Math.max(
    new Date(job.workerLastSeenAt || 0).getTime() || 0,
    new Date(job.updatedAt || 0).getTime() || 0,
    new Date(job.startedAt || 0).getTime() || 0
  );
  if (!updatedMs) return true;
  const graceSeconds = Math.max(600, Number(workerStatus.staleAfterSeconds || 30) * 4);
  return Date.now() - updatedMs > graceSeconds * 1000;
}

function jobFileRetentionCutoff() {
  return Date.now() - (IMPORT_JOB_FILE_RETENTION_DAYS * 24 * 60 * 60 * 1000);
}

function jobCompletedBeforeRetentionCutoff(job = {}) {
  const status = String(job.status || "").toLowerCase();
  if (!["success", "warning", "failed", "stopped"].includes(status)) return false;
  const completedAt = new Date(job.finishedAt || job.updatedAt || job.startedAt || job.createdAt || 0).getTime();
  return Number.isFinite(completedAt) && completedAt > 0 && completedAt < jobFileRetentionCutoff();
}

function importJobArtifactPaths(job = {}) {
  const paths = [
    job.originalFilePath,
    job.filePath,
    job.errorFilePath,
    job.manifestFilePath,
    ...(Array.isArray(job.artifacts) ? job.artifacts.map((artifact) => artifact.filePath) : [])
  ].map((filePath) => String(filePath || "").trim()).filter(Boolean);
  return [...new Set(paths)];
}

function removeImportJobArtifactFiles(job = {}) {
  let removedFiles = 0;
  const root = path.resolve(IMPORT_JOB_FILE_DIR);
  const touchedDirs = new Set();
  for (const filePath of importJobArtifactPaths(job)) {
    const resolved = path.resolve(filePath);
    if (!resolved.startsWith(root + path.sep)) continue;
    if (!fs.existsSync(resolved)) continue;
    const stat = fs.statSync(resolved);
    if (!stat.isFile()) continue;
    fs.rmSync(resolved, { force: true });
    removedFiles += 1;
    touchedDirs.add(path.dirname(resolved));
  }
  for (const dir of touchedDirs) {
    try {
      if (dir !== root && fs.existsSync(dir) && fs.readdirSync(dir).length === 0) fs.rmdirSync(dir);
    } catch {
      // Retention cleanup must not block Jobs maintenance.
    }
  }
  return removedFiles;
}

async function pruneExpiredImportJobArtifacts(jobs = []) {
  let expiredJobs = 0;
  let removedFiles = 0;
  for (const job of jobs || []) {
    if (!jobCompletedBeforeRetentionCutoff(job)) continue;
    if (!importJobArtifactPaths(job).length) continue;
    removedFiles += removeImportJobArtifactFiles(job);
    job.artifacts = [];
    job.originalFilePath = "";
    job.filePath = "";
    job.errorFilePath = "";
    job.manifestFilePath = "";
    job.originalFileName = job.originalFileName || job.fileName || "";
    job.errorFileName = "";
    job.manifestFileName = "";
    job.details = [
      job.details,
      `Download files expired after ${IMPORT_JOB_FILE_RETENTION_DAYS} days and were removed by Jobs cleanup.`
    ].filter(Boolean).join(" ");
    job.updatedAt = new Date().toISOString();
    upsertImportJobStore(job);
    if (postgres.isPostgresEnabled()) {
      await postgres.deleteOperationArtifactsForJob(job.id).catch((error) => {
        console.error("Unable to delete expired job artifacts", error.message || error);
      });
      await postgres.upsertOperationJob(job).catch((error) => {
        console.error("Unable to persist expired job artifact cleanup", error.message || error);
      });
    }
    expiredJobs += 1;
  }
  return { expiredJobs, removedFiles };
}

function pruneOrphanImportJobDirectories(jobs = []) {
  if (!fs.existsSync(IMPORT_JOB_FILE_DIR)) return { orphanDirs: 0, orphanFiles: 0 };
  const knownJobIds = new Set((jobs || []).map((job) => String(job.id || "")).filter(Boolean));
  const cutoff = jobFileRetentionCutoff();
  let orphanDirs = 0;
  let orphanFiles = 0;
  for (const entry of fs.readdirSync(IMPORT_JOB_FILE_DIR, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    if (knownJobIds.has(entry.name)) continue;
    const dir = path.join(IMPORT_JOB_FILE_DIR, entry.name);
    const stat = fs.statSync(dir);
    if (!(stat.mtimeMs < cutoff)) continue;
    try {
      const files = fs.readdirSync(dir, { recursive: true });
      fs.rmSync(dir, { recursive: true, force: true });
      orphanDirs += 1;
      orphanFiles += files.length;
    } catch {
      // Retention cleanup must not block Jobs maintenance.
    }
  }
  return { orphanDirs, orphanFiles };
}

function categoryMappingForProduct(db, item, channel = "shopify") {
  const category = effectiveMainCategoryName(item, readSystemSettingsStore(db.systemSettings || {})).toLowerCase();
  if (!category) return null;
  const settings = normalizeCategorySettings(db.categorySettings);
  const match = settings.find((row) => formatCategoryName(row.name || "").toLowerCase() === category || String(row.categoryId || "").trim().toLowerCase() === category);
  return match?.mappings?.[channel] || null;
}

function shopifyProductTypeForProduct(db, item = {}) {
  const mapping = categoryMappingForProduct(db, item, "shopify") || {};
  const category = effectiveMainCategoryName(item, readSystemSettingsStore(db.systemSettings || {}));
  return sourceTextValue(
    mapping.productType
    || categoryTypeValue(category)
    || item.productType
    || item.shopifyProductType
    || categoryTypeValue(item.category || item.mainCategory || "")
  );
}

function slugPart(value) {
  return String(value || "")
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function verifiedBrandForHandle(item = {}) {
  const explicitBrand = item.verifiedBrand || item.verified_brand;
  if (String(explicitBrand || "").trim()) return explicitBrand;
  return item.brandLocked && String(item.brand || "").trim() ? item.brand : "";
}

function shopifyHandleForProduct(item) {
  const formattedTitle = shopifyExportTitle(item);
  return slugPart(formattedTitle || item.sku || item.id || "product");
}

function productExportCache(db, item = {}) {
  if (item.__exportCache && typeof item.__exportCache === "object") return item.__exportCache;
  const cache = {
    shopifyTitle: shopifyExportTitle(item),
    shopifyHandle: "",
    shopifyMapping: categoryMappingForProduct(db, item, "shopify") || null,
    uomInfo: productUomInfo(item),
    sellUnitCost: productSellUnitCost(item, db),
    imageUrls: productImageUrls(item)
  };
  cache.shopifyHandle = slugPart(cache.shopifyTitle || item.sku || item.id || "product");
  Object.defineProperty(item, "__exportCache", {
    value: cache,
    enumerable: true,
    configurable: true
  });
  return cache;
}

function decodeHtmlEntities(value) {
  return String(value || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;|&apos;/gi, "'")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&#(\d+);/g, (_, code) => {
      const number = Number(code);
      return Number.isFinite(number) ? String.fromCharCode(number) : "";
    });
}

function stripHtml(value) {
  return decodeHtmlEntities(value)
    .replace(/<\s*br\s*\/?>/gi, "\n")
    .replace(/<\/\s*(p|div|li|h[1-6]|tr)\s*>/gi, "\n")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]+>/g, " ");
}

function normalizeContentWhitespace(value) {
  return String(value || "")
    .replace(/\r/g, "\n")
    .replace(/[ \t]+/g, " ")
    .replace(/\n[ \t]+/g, "\n")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function isMostlyAllCaps(value) {
  const letters = String(value || "").replace(/[^a-z]/gi, "");
  if (letters.length < 12) return false;
  const upper = letters.replace(/[^A-Z]/g, "").length;
  const lower = letters.replace(/[^a-z]/g, "").length;
  return upper / letters.length > 0.85 && lower < 3;
}

function smartLowerWord(word) {
  if (/^\d/.test(word) || /^[A-Z]{1,4}\d/i.test(word)) return word;
  if (/^(sku|upc|usb|led|pvc|hvac|api|seo|sds|ul|ce)$/i.test(word)) return word.toUpperCase();
  if (/^(usa|us)$/i.test(word)) return word.toUpperCase();
  return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
}

function titleCaseAllCaps(value) {
  return String(value || "").split(/(\s+|[-/])/).map((part) => {
    if (!/[A-Z]/i.test(part) || /^[-/]$/.test(part)) return part;
    return smartLowerWord(part);
  }).join("");
}

function sentenceCaseAllCaps(value) {
  const text = String(value || "").toLowerCase();
  return text.replace(/(^|[.!?]\s+)([a-z])/g, (match, prefix, letter) => `${prefix}${letter.toUpperCase()}`)
    .replace(/\b(usb|led|pvc|hvac|api|seo|sds|ul|ce|usa|upc|sku)\b/g, (match) => match.toUpperCase());
}

function sanitizeProductTitle(value) {
  const text = normalizeContentWhitespace(stripHtml(value));
  return isMostlyAllCaps(text) ? titleCaseAllCaps(text) : text;
}

function sanitizeProductText(value) {
  const text = normalizeContentWhitespace(stripHtml(value));
  return isMostlyAllCaps(text) ? sentenceCaseAllCaps(text) : text;
}

function sanitizeProductHtml(value) {
  const text = sanitizeProductText(value);
  if (!text) return "";
  return text.split(/\n{2,}/).map((paragraph) => `<p>${escapeHtml(paragraph.trim())}</p>`).join("");
}

function shopifyMoneyValue(value) {
  const number = Number(sourceNumberValue(value));
  if (!(number > 0)) return "";
  return number.toFixed(2);
}

function shopifyReferenceValue(value, type = "") {
  const text = sourceTextValue(value);
  if (!text) return "";
  if (type === "product_reference") return /^gid:\/\/shopify\/Product\/\d+$/i.test(text) ? text : "";
  if (type === "variant_reference") return /^gid:\/\/shopify\/ProductVariant\/\d+$/i.test(text) ? text : "";
  return text;
}

function shopifyDumpMetafieldValue(item = {}, metafieldKey = "") {
  const entry = Object.entries(SHOPIFY_DUMP_FIELD_METAFIELDS)
    .find(([, config]) => String(config.key || "").toLowerCase() === String(metafieldKey || "").toLowerCase());
  if (!entry) return undefined;
  const [field, config] = entry;
  const value = SHOPIFY_SHIPPING_CLASSIFICATION_METAFIELDS[field]
    ? shopifyShippingMetafieldRawValue(item, field, config)
    : item[field] ?? item.productManagerFields?.[config.key.replace(/^custom\./, "")] ?? item.productManagerFields?.[config.key.replace(/^custom\./, "").replace(/_/g, "")];
  if (value === undefined || value === null || value === "") return "";
  if (config.type === "money") return shopifyMoneyValue(value);
  if (config.type === "dimension" || config.type === "weight") return shopifyMoneyValue(value);
  if (config.type === "number_integer") {
    const number = Math.round(Number(sourceNumberValue(value)));
    return number > 0 ? String(number) : "";
  }
  if (config.type === "number_decimal") {
    const number = Number(sourceNumberValue(value));
    return Number.isFinite(number) ? String(number) : "";
  }
  if (config.type === "date_time") {
    const date = new Date(value);
    return Number.isFinite(date.getTime()) ? date.toISOString() : "";
  }
  if (config.type === "boolean") return sourceBooleanValue(value, false) ? "TRUE" : "FALSE";
  if (config.type === "json") return typeof value === "string" ? value : JSON.stringify(value);
  if (config.type === "product_reference" || config.type === "variant_reference") return shopifyReferenceValue(value, config.type);
  if (config.type.startsWith("list.")) {
    const values = Array.isArray(value) ? value : String(value).split(/[|,]/).map((part) => part.trim()).filter(Boolean);
    return JSON.stringify(values);
  }
  return sourceTextValue(value);
}

function shopifyShippingMetafieldRawValue(item = {}, field = "", config = {}) {
  if (["shippingClass", "shippingMethod", "shippingClassReason", "dimensionalWeight"].includes(field)) {
    if (!productHasShippingMeasurements(item)) return "";
    const classification = productShippingClassification(item);
    if (field === "shippingClassReason") return classification.shippingClassReason;
    return classification[field];
  }
  if (field === "itemHeight") return productShippingDimensionValue(item, "itemHeight", "item_height");
  if (field === "itemLength") return productShippingDimensionValue(item, "itemLength", "item_length");
  if (field === "itemWeight") return productShippingDimensionValue(item, "itemWeight", "item_weight");
  if (field === "itemWidth") return productShippingDimensionValue(item, "itemWidth", "item_width");
  if (field === "packageHeight") return productShippingDimensionValue(item, "packageHeight", "package_height");
  if (field === "packageLength") return productShippingDimensionValue(item, "packageLength", "package_length");
  if (field === "packageWeight") return productShippingDimensionValue(item, "packageWeight", "package_weight");
  if (field === "packageWidth") return productShippingDimensionValue(item, "packageWidth", "package_width");
  return item[field] ?? item.productManagerFields?.[config.key?.replace(/^custom\./, "") || ""] ?? "";
}

function shopifyAdminMetafieldValue(value, type = "") {
  if (value === undefined || value === null || value === "") return "";
  if (type === "dimension") {
    const amount = Number(sourceNumberValue(value));
    return amount > 0 ? JSON.stringify({ value: amount, unit: "INCHES" }) : "";
  }
  if (type === "weight") {
    const amount = Number(sourceNumberValue(value));
    return amount > 0 ? JSON.stringify({ value: amount, unit: "POUNDS" }) : "";
  }
  if (type === "number_decimal") {
    const amount = Number(sourceNumberValue(value));
    return amount > 0 ? String(amount) : "";
  }
  if (type === "number_integer") {
    const amount = Math.round(Number(sourceNumberValue(value)));
    return amount > 0 ? String(amount) : "";
  }
  if (type === "boolean") return sourceBooleanValue(value, false) ? "true" : "false";
  if (type === "json") return typeof value === "string" ? value : JSON.stringify(value);
  if (type.startsWith("list.")) {
    const values = Array.isArray(value) ? value.map((part) => sourceTextValue(part)).filter(Boolean) : [sourceTextValue(value)].filter(Boolean);
    return values.length ? JSON.stringify(values) : "";
  }
  return sourceTextValue(value);
}

function shopifyShippingClassificationMetafields(item = {}) {
  const metafields = [];
  for (const [field, config] of Object.entries(SHOPIFY_SHIPPING_CLASSIFICATION_METAFIELDS)) {
    if (!config?.key) continue;
    const [namespace, key] = config.key.split(".");
    const rawValue = shopifyShippingMetafieldRawValue(item, field, config);
    const value = shopifyAdminMetafieldValue(rawValue, config.type);
    if (!value) continue;
    metafields.push({ namespace, key, type: config.type, value });
  }
  return metafields;
}

function shopifyVariantPrice(item = {}, db = null) {
  const settings = {
    ...DEFAULT_CHANNEL_SETTINGS,
    ...(db ? findChannelByName(db, "Shopify")?.settings || {} : {}),
    priceMarkupPercent: SHOPIFY_PRICE_MARKUP_PERCENT
  };
  const variant = systemProductVariants(item, db)[0] || {};
  return shopifyMoneyValue(shopifyVariantWebsitePrice(item, variant, settings.priceMarkupPercent, db));
}

function deterministicMarkupPercent(seed = "") {
  const hash = crypto.createHash("sha1").update(String(seed || "")).digest();
  const bucket = hash.readUInt16BE(0) / 65535;
  return 20 + (bucket * 20);
}

function shopifyCompareAtPrice(item = {}) {
  if (!isClearanceItem(item)) return "";
  const price = Number(sourceNumberValue(item.websitePrice ?? item.price));
  if (!(price > 0)) return "";
  const percent = deterministicMarkupPercent(item.sku || item.id || item.title);
  return shopifyMoneyValue(price * (1 + percent / 100));
}

function shopifyExportTitle(item = {}) {
  return [item.brand, item.mfrPartNumber, item.marketplaceTitle || item.title || item.sku]
    .map((part) => sanitizeProductTitle(part))
    .filter(Boolean)
    .join(" ");
}

const SHOPIFY_SINGLE_MUSIC_INVENTORY_COLUMNS_TO_REMOVE = new Set([
  "inventory committed: single music",
  "inventory reserved: single music",
  "inventory damaged: single music",
  "inventory damaged adjust: single music",
  "inventory safety stock: single music",
  "inventory safety stock adjust: single music",
  "inventory quality control: single music",
  "inventory quality control adjust: single music"
]);

function isShopifyTemplate(template = {}) {
  const formatType = String(template.formatType || template.exportFormat || "").trim().toLowerCase();
  if (formatType === "shopify" || formatType === "matrixify") return true;
  const source = String(template.source || "").trim().toLowerCase();
  const name = String(template.name || template.id || "").trim().toLowerCase();
  if (source === "shopify" || name.includes("shopify")) return true;
  const columns = new Set((template.mappings || []).map((mapping) => String(mapping.externalColumn || "").trim().toLowerCase()));
  const matrixifySignals = [
    "handle",
    "variant sku",
    "option1 name",
    "option1 value",
    "variant command"
  ].filter((column) => columns.has(column)).length;
  return matrixifySignals >= 3;
}

function shouldOmitShopifyExportColumn(mapping = {}, template = {}) {
  if (!isShopifyTemplate(template)) return false;
  return SHOPIFY_SINGLE_MUSIC_INVENTORY_COLUMNS_TO_REMOVE.has(String(mapping.externalColumn || "").trim().toLowerCase());
}

function exportMappingsForTemplate(template = {}) {
  const mappings = (template.mappings || []).filter((mapping) => !shouldOmitShopifyExportColumn(mapping, template));
  if (!isShopifyTemplate(template)) return mappings;
  if (template.omitSyntheticShopifyVariantMetafields === true) return mappings;
  const columns = new Set(mappings.map((mapping) => String(mapping.externalColumn || "").trim().toLowerCase()));
  const synthetic = [
    { externalColumn: "Variant Metafield: custom.purchase_unit [single_line_text_field]", productField: "" },
    { externalColumn: "Variant Metafield: custom.uom [single_line_text_field]", productField: "" },
    { externalColumn: "Variant Metafield: custom.uom_qty [number_integer]", productField: "" },
    { externalColumn: "Variant Metafield: custom.sell_unit_cost [number_decimal]", productField: "" }
  ].filter((mapping) => !columns.has(mapping.externalColumn.toLowerCase()));
  return [...mappings, ...synthetic];
}

function exportValueTemplateSource(template = {}) {
  if (isShopifyTemplate(template)) return "Shopify";
  const formatType = String(template.formatType || "").trim().toLowerCase();
  if (formatType === "ebay") return "eBay";
  if (formatType === "amazon") return "Amazon";
  return template.source || "Custom";
}

function normalizedWarehouseToken(value = "") {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]/g, "");
}

function warehouseAliasesForColumn(warehouseName = "") {
  const token = normalizedWarehouseToken(warehouseName);
  const aliases = new Set([token]);
  if (token === "siwarehouse" || token === "si") {
    aliases.add("statenisland");
    aliases.add("whsi");
  }
  if (token === "bkwarehouse" || token === "bk") {
    aliases.add("brooklyn");
    aliases.add("whbk");
  }
  return aliases;
}

function warehouseMatchesColumn(warehouse = {}, columnWarehouseName = "") {
  const aliases = warehouseAliasesForColumn(columnWarehouseName);
  return [warehouse.id, warehouse.code, warehouse.name, warehouse.warehouseName]
    .map((value) => normalizedWarehouseToken(value))
    .some((token) => token && aliases.has(token));
}

function warehouseNameFromInventoryColumn(column = "") {
  const match = String(column || "").match(/^Inventory\s+[^:]+:\s*(.+)$/i);
  return match ? match[1].trim() : "";
}

function productSkuKeys(item = {}) {
  return new Set([
    item.sku,
    item.internalSku,
    item.mfrPartNumber,
    ...(Array.isArray(item.aliases) ? item.aliases.map((alias) => alias.sku || alias.alias || alias.value || alias) : []),
    ...(Array.isArray(item.shadowSkus) ? item.shadowSkus.map((shadow) => shadow.sku || shadow.shadowSku || shadow.value || shadow) : [])
  ].map((value) => String(value || "").trim().toLowerCase()).filter(Boolean));
}

function lineMatchesProduct(line = {}, item = {}) {
  const keys = productSkuKeys(item);
  if (!keys.size) return false;
  return [line.sku, line.internalSku, line.mappedSku, line.productSku, line.vendorSku, line.shadowSku]
    .map((value) => String(value || "").trim().toLowerCase())
    .some((value) => value && keys.has(value));
}

function purchaseOrderIncomingQtyForWarehouse(db, item = {}, warehouseName = "") {
  const aliases = warehouseAliasesForColumn(warehouseName);
  let total = 0;
  for (const po of db.purchaseOrders || []) {
    const status = String(po.status || "").trim().toLowerCase();
    if (["closed", "canceled", "cancelled", "received"].includes(status)) continue;
    const poWarehouse = (db.warehouses || []).find((warehouse) => warehouse.id === po.warehouseId);
    const poWarehouseTokens = [po.warehouseId, po.warehouseName, poWarehouse?.code, poWarehouse?.name]
      .map((value) => normalizedWarehouseToken(value))
      .filter(Boolean);
    if (!poWarehouseTokens.some((token) => aliases.has(token))) continue;
    for (const line of po.items || []) {
      if (!lineMatchesProduct(line, item)) continue;
      const ordered = Number(line.qty ?? line.quantity ?? line.orderedQty ?? 0);
      const received = Number(line.receivedQty ?? line.receivedQuantity ?? line.received ?? 0);
      if (Number.isFinite(ordered) && ordered > received) total += ordered - Math.max(0, received);
    }
  }
  return total > 0 ? total : "";
}

function inventoryReservedQtyForWarehouse(item = {}, warehouseName = "") {
  const rows = Array.isArray(item.warehouseStock) ? item.warehouseStock : [];
  const row = rows.find((entry) => warehouseMatchesColumn(entry, warehouseName));
  const value = Number(row?.reserved || 0);
  return Number.isFinite(value) ? value : 0;
}

function inventoryOnHandQtyForWarehouse(item = {}, warehouseName = "") {
  const rows = Array.isArray(item.warehouseStock) ? item.warehouseStock : [];
  const row = rows.find((entry) => warehouseMatchesColumn(entry, warehouseName));
  const value = Number(row?.qty || 0);
  return Number.isFinite(value) ? value : 0;
}

function inventoryAvailableQtyForWarehouse(item = {}, warehouseName = "") {
  return Math.max(0, inventoryOnHandQtyForWarehouse(item, warehouseName) - inventoryReservedQtyForWarehouse(item, warehouseName));
}

function shopifyInventoryColumnValue(db, item = {}, column = "") {
  const warehouseName = warehouseNameFromInventoryColumn(column);
  if (!warehouseName) return undefined;
  if (/single\s+music/i.test(warehouseName)) return 0;
  if (/^Inventory\s+Available:/i.test(column)) {
    const replenishableQty = productReplenishableQty(item, db);
    return replenishableQty > 0 ? replenishableQty : inventoryAvailableQtyForWarehouse(item, warehouseName);
  }
  if (/^Inventory\s+On Hand:/i.test(column)) return inventoryOnHandQtyForWarehouse(item, warehouseName);
  if (/^Inventory\s+Incoming:/i.test(column)) return "";
  if (/^Inventory\s+(Committed|Reserved):/i.test(column)) return inventoryReservedQtyForWarehouse(item, warehouseName);
  return undefined;
}

function shopifyVariantSku(baseSku = "", suffix = "EA") {
  const sku = String(baseSku || "").trim();
  return sku && !sku.toUpperCase().endsWith(`-${suffix}`) ? `${sku}-${suffix}` : sku;
}

function shopifyVariantBaseSku(item = {}) {
  return String(item.sku || item.vendorSku || item.mfrPartNumber || "").trim();
}

function shopifyUomVariantSku(baseSku = "", uom = {}) {
  const sku = String(baseSku || "").trim();
  const qty = Number(uom.qty || 1);
  if (!sku || !(qty > 1)) return sku;
  return shopifyVariantSku(sku, `${Math.floor(qty)}PC`);
}

function shopifyPurchaseVariants(item = {}, db = null) {
  const settings = {
    ...DEFAULT_CHANNEL_SETTINGS,
    ...(db ? findChannelByName(db, "Shopify")?.settings || {} : {}),
    priceMarkupPercent: SHOPIFY_PRICE_MARKUP_PERCENT
  };
  const statusMatches = item.shopifyVariantMatches && typeof item.shopifyVariantMatches === "object" ? item.shopifyVariantMatches : {};
  const variants = systemProductVariants(item, db);
  return variants.map((variant) => {
    const matchKey = String(variant.sku || "").trim().toLowerCase();
    const liveMatch = statusMatches[matchKey] || (variants.length === 1 ? shopifyStatusForSku(statusMatches, item.sku) : null) || null;
    const unitCost = shopifyVariantPriceBasis(item, variant, db);
    const price = shopifyVariantWebsitePrice(item, variant, settings.priceMarkupPercent, db);
    return {
      ...variant,
      shopifyId: liveMatch?.shopifyId || variant.shopifyId || "",
      shopifyVariantId: liveMatch?.shopifyVariantId || variant.shopifyVariantId || "",
      shopifyHandle: liveMatch?.shopifyHandle || variant.shopifyHandle || "",
      shopifyVariantSku: liveMatch?.shopifyVariantSku || liveMatch?.sku || variant.shopifyVariantSku || "",
      shopifyLivePrice: liveMatch?.shopifyVariantPrice !== undefined && liveMatch?.shopifyVariantPrice !== "" ? Number(liveMatch.shopifyVariantPrice) : null,
      shopifyLiveCompareAtPrice: liveMatch?.shopifyVariantCompareAtPrice !== undefined && liveMatch?.shopifyVariantCompareAtPrice !== "" ? Number(liveMatch.shopifyVariantCompareAtPrice) : null,
      shopifyLiveInventoryQuantity: liveMatch?.shopifyVariantInventoryQuantity ?? null,
      shopifyStatus: liveMatch?.shopifyStatus || variant.shopifyStatus || "",
      shopifyPublished: liveMatch?.shopifyPublished ?? variant.shopifyPublished,
      key: variant.key || "sell-unit",
      optionName: variant.optionName || (Number(variant.uomQty || 1) > 1 ? "Purchase Unit" : "Title"),
      optionValue: variant.optionValue || (Number(variant.uomQty || 1) > 1 ? `Pack of ${Number(variant.uomQty || 1)}` : "Default Title"),
      unitCost,
      price,
      compareAtPrice: isClearanceItem(item) ? shopifyMoneyValue(price * 1.2) : "",
      note: variant.note || "Actual DataPlus system variant."
    };
  });
}

function shopifyPriceComparison(item = {}, db = null) {
  const variants = shopifyPurchaseVariants(item, db);
  const matched = variants.find((variant) => variant.shopifyVariantId && variant.shopifyLivePrice !== null && variant.shopifyLivePrice !== undefined)
    || variants.find((variant) => variant.shopifyVariantId)
    || variants[0]
    || {};
  const systemPrice = Number(matched.price ?? item.websitePrice ?? item.price ?? 0);
  const livePrice = matched.shopifyLivePrice !== null && matched.shopifyLivePrice !== undefined ? Number(matched.shopifyLivePrice) : null;
  const delta = livePrice !== null && Number.isFinite(livePrice) ? Math.round((systemPrice - livePrice) * 100) / 100 : null;
  return {
    systemPrice,
    livePrice,
    delta,
    mismatch: livePrice !== null && Number.isFinite(livePrice) && Math.abs(delta) >= 0.01,
    variantSku: matched.shopifyVariantSku || matched.sku || item.shopifyVariantSku || item.sku || "",
    variantId: matched.shopifyVariantId || item.shopifyVariantId || "",
    handle: matched.shopifyHandle || item.shopifyHandle || "",
    compareAtPrice: matched.shopifyLiveCompareAtPrice ?? null,
    inventoryQuantity: matched.shopifyLiveInventoryQuantity ?? null
  };
}

function productIsCloseout(item = {}) {
  if (item.toBeDiscontinued === true || item.closeoutEligible === true) return true;
  const tags = sourceListValue(item.tags || []);
  return tags.some((tag) => ["closeout", "to-be-discontinued"].includes(String(tag || "").trim().toLowerCase()));
}

function productBlockedFromShopifyWebsite(item = {}, db = null) {
  return productIsCloseout(item) && productSellableQty(item, db) <= 0;
}

function productExportTags(item = {}) {
  const tags = sourceListValue(item.tags || []).map((tag) => String(tag || "").trim()).filter(Boolean);
  if (productIsCloseout(item)) {
    tags.push("closeout", "to-be-discontinued");
  }
  if (productHasShippingMeasurements(item)) {
    const shipping = productShippingClassification(item);
    if (shipping.shippingClass === "ltl") tags.push("shipping-ltl", "freight-required");
    if (shipping.shippingClass === "oversize_parcel") tags.push("shipping-oversize-parcel", "oversize-parcel");
    if (shipping.shippingClass === "parcel") tags.push("shipping-parcel", "ground-eligible");
  }
  const seen = new Set();
  return tags.filter((tag) => {
    const key = tag.toLowerCase();
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function productFieldValue(db, item, field, mapping = {}) {
  const column = String(mapping.externalColumn || "").trim();
  const source = String(mapping.templateSource || mapping.source || "").trim().toLowerCase();
  const variant = item.__shopifyVariant || null;
  const variantRow = Number(item.__shopifyVariantRow || 1);
  const cache = source === "shopify" ? productExportCache(db, item) : null;
  if (source === "shopify" && /^Row #$/i.test(column)) return Number(item.__shopifyVariantRow || 1);
  if (source === "shopify" && /^Top Row$/i.test(column)) return variantRow === 1 ? "TRUE" : "FALSE";
  if (source === "shopify" && /^ID$/i.test(column)) return shopifyLegacyId(variant?.shopifyId || item.shopifyId);
  if (source === "shopify" && /^Variant ID$/i.test(column)) return shopifyLegacyId(variant?.shopifyVariantId || item.shopifyVariantId);
  if (source === "shopify" && /^Handle$/i.test(column)) return variant?.shopifyHandle || item.shopifyHandle || cache?.shopifyHandle || shopifyHandleForProduct(item);
  if (source === "shopify" && /^Type$/i.test(column)) return shopifyProductTypeForProduct(db, item);
  if (source === "shopify" && /^Inventory\s+/.test(column)) {
    const inventoryValue = shopifyInventoryColumnValue(db, item, column);
    if (inventoryValue !== undefined) return inventoryValue;
  }
  if (source === "shopify" && /^Metafield:/i.test(column) && variantRow > 1) return "";
  if (source === "shopify" && /^Metafield:\s*custom\./i.test(column)) {
    const metafieldKey = column.replace(/^Metafield:\s*/i, "").trim().split(/\s/)[0];
    const value = shopifyDumpMetafieldValue(item, metafieldKey);
    if (value !== undefined) return value;
  }
  if (source === "shopify" && /^Variant Metafield:\s*custom\.purchase_unit\s/i.test(column)) return variant?.optionValue || cache.uomInfo.display;
  if (source === "shopify" && /^Variant Metafield:\s*custom\.uom\s/i.test(column)) return variant?.uom || cache.uomInfo.code;
  if (source === "shopify" && /^Variant Metafield:\s*custom\.uom_qty\s/i.test(column)) return variant?.uomQty || cache.uomInfo.qty;
  if (source === "shopify" && /^Variant Metafield:\s*custom\.sell_unit_cost\s/i.test(column)) return variant?.unitCost !== undefined ? Number(variant.unitCost).toFixed(2) : productSellUnitCost(item, db).toFixed(2);
  if (source === "shopify" && /^Option1 Name$/i.test(column)) return variant?.optionName || (cache.uomInfo.isMultiUnit ? "Purchase Unit" : "Title");
  if (source === "shopify" && /^Option1 Value$/i.test(column)) return variant?.optionValue || (cache.uomInfo.isMultiUnit ? cache.uomInfo.display : "Default Title");
  if (source === "shopify" && /^Variant SKU$/i.test(column)) return variant?.shopifyVariantSku || variant?.sku || item.sku || "";
  if (source === "shopify" && /^Variant Price$/i.test(column)) return variant?.price !== undefined ? shopifyMoneyValue(variant.price) : shopifyVariantPrice(item, db);
  if (source === "shopify" && /^Variant Compare At Price$/i.test(column)) return variant?.compareAtPrice !== undefined ? shopifyMoneyValue(variant.compareAtPrice) : shopifyCompareAtPrice(item);
  if (source === "shopify" && /^(Variant Cost|Cost per item)$/i.test(column)) return variant?.unitCost !== undefined ? shopifyMoneyValue(variant.unitCost) : shopifyMoneyValue(productSellUnitCost(item, db));
  if (source === "shopify" && /^Variant Weight$/i.test(column)) return shopifyVariantWeightValue(item, variant);
  if (source === "shopify" && /^Variant Inventory Qty$/i.test(column)) return variant?.quantity ?? productSellableQty(item, db);
  if (source === "shopify" && /^Metafield:\s*custom\.uom\s/i.test(column)) return variant?.uom || cache.uomInfo.code;
  if (source === "shopify" && /^Metafield:\s*custom\.uom_qty\s/i.test(column)) return variant?.uomQty || cache.uomInfo.qty;
  if (source === "shopify" && /^Metafield:\s*custom\.item_height\s/i.test(column)) return shopifyDimensionSourceValue(item, "height", false);
  if (source === "shopify" && /^Metafield:\s*custom\.item_length\s/i.test(column)) return shopifyDimensionSourceValue(item, "length", false);
  if (source === "shopify" && /^Metafield:\s*custom\.item_width\s/i.test(column)) return shopifyDimensionSourceValue(item, "width", false);
  if (source === "shopify" && /^Metafield:\s*custom\.item_weight\s/i.test(column)) return shopifyWeightSourceValue(item, false);
  if (source === "shopify" && /^Metafield:\s*custom\.package_height\s/i.test(column)) return shopifyDimensionSourceValue(item, "height", true);
  if (source === "shopify" && /^Metafield:\s*custom\.package_length\s/i.test(column)) return shopifyDimensionSourceValue(item, "length", true);
  if (source === "shopify" && /^Metafield:\s*custom\.package_width\s/i.test(column)) return shopifyDimensionSourceValue(item, "width", true);
  if (source === "shopify" && /^Metafield:\s*custom\.package_weight\s/i.test(column)) return shopifyWeightSourceValue(item, true);
  if (String(mapping.externalColumn || "").trim().toLowerCase() === "handle") return cache?.shopifyHandle || shopifyHandleForProduct(item);
  if (source === "shopify" && /^Title$/i.test(column)) return cache.shopifyTitle;
  if (source === "shopify" && /^Image Alt Text$/i.test(column)) return cache.shopifyTitle;
  if (/^Variant Price$/i.test(column)) return shopifyVariantPrice(item, db);
  if (/^Variant Compare At Price$/i.test(column) || field === "shopifyCompareAtPrice") return shopifyCompareAtPrice(item);
  if (field === "available") return productSellableQty(item, db);
  if (field === "vendor") return item.vendor ?? item.supplier ?? "";
  if (field === "qty") return item.qty ?? item.stockQty ?? "";
  if (field === "shopifyHandle") return cache?.shopifyHandle || shopifyHandleForProduct(item);
  if (field === "images") return (item.images || []).join("|");
  if (field === "tags") return productExportTags(item).join("|");
  if (field === "toBeDiscontinued") return productIsCloseout(item) ? "TRUE" : "FALSE";
  if (field === "closeoutEligible") return productIsCloseout(item) ? "TRUE" : "FALSE";
  if (field === "listPrice" || field === "msrp") return isClearanceItem(item) ? item[field] ?? "" : "";
  if (field === "bulletPoints") return (item.bulletPoints || []).join("|");
  if (field === "sources") return Object.entries(item.sources || {}).map(([source, id]) => `${source}:${id}`).join(";");
  if (field === "shopifyCategoryId") return (cache?.shopifyMapping || categoryMappingForProduct(db, item, "shopify"))?.categoryId || "";
  if (field === "shopifyCategoryPath") return (cache?.shopifyMapping || categoryMappingForProduct(db, item, "shopify"))?.categoryPath || "";
  if (field === "googleCategoryId") return (cache?.shopifyMapping || categoryMappingForProduct(db, item, "shopify"))?.googleCategory?.id || "";
  if (field === "googleCategoryBreadcrumb") {
    const shopifyMapping = cache?.shopifyMapping || categoryMappingForProduct(db, item, "shopify");
    return shopifyMapping?.googleCategory?.breadcrumb || shopifyMapping?.googleCategory?.fullName || "";
  }
  if (field === "title" || field === "marketplaceTitle") return sanitizeProductTitle(item[field]);
  if (["shortDescription", "longDescription", "vendorDescription"].includes(field)) {
    return /html/i.test(String(mapping.externalColumn || "")) ? sanitizeProductHtml(item[field]) : sanitizeProductText(item[field]);
  }
  return item[field] ?? "";
}

function firstPositiveNumber(...values) {
  for (const value of values) {
    const number = Number(sourceNumberValue(value));
    if (Number.isFinite(number) && number > 0) return number;
  }
  return 0;
}

const SYSTEM_DEFAULT_DIMENSION_IN = 5;
const SYSTEM_DEFAULT_WEIGHT_LB = 5;
const DIMENSION_WEIGHT_FIELDS = new Set(["itemHeight", "itemLength", "itemWeight", "itemWidth", "packageHeight", "packageLength", "packageWeight", "packageWidth"]);

function productSourceContainers(item = {}) {
  return [
    { container: item, source: "manual_entered", label: "Manual entered" },
    { container: item.productManagerFields || {}, source: "data_dump", label: "Data dump" },
    { container: item.productManagerFields?.original || {}, source: "data_dump", label: "Data dump" },
    { container: item.original || {}, source: "data_dump", label: "Data dump" },
    ...(Array.isArray(item.sourceCatalogMatches)
      ? item.sourceCatalogMatches.flatMap((match) => [
        { container: match, source: "data_dump", label: "Data dump" },
        { container: match?.raw || {}, source: "data_dump", label: "Data dump" }
      ])
      : [])
  ];
}

function productSourceNumberDetail(item = {}, keys = [], options = {}) {
  const defaultValue = Number(options.defaultValue || 0);
  for (const entry of productSourceContainers(item)) {
    const container = entry.container;
    if (!container || typeof container !== "object") continue;
    for (const key of keys) {
      const number = Number(sourceNumberValue(container[key]));
      if (Number.isFinite(number) && number > 0) {
        const sourceOverride = item.dimensionWeightSources?.[key]?.source || item.dimensionWeightSource?.[key];
        if (entry.source === "manual_entered" && sourceOverride) {
          return { value: number, source: sourceOverride, label: sourceOverride === "manual_import" ? "Manual import" : "Manual entered", verified: true, defaulted: false };
        }
        if (entry.source === "manual_entered") {
          const dataDumpMatch = productSourceContainers(item).some((candidate) => {
            if (candidate.source !== "data_dump" || !candidate.container || typeof candidate.container !== "object") return false;
            const candidateValue = Number(sourceNumberValue(candidate.container[key]));
            return Number.isFinite(candidateValue) && Math.abs(candidateValue - number) < 0.0001;
          });
          if (dataDumpMatch) return { value: number, source: "data_dump", label: "Data dump", verified: true, defaulted: false };
        }
        return { value: number, source: entry.source, label: entry.label, verified: true, defaulted: false };
      }
    }
  }
  return defaultValue > 0
    ? { value: defaultValue, source: "system_default", label: "System default", verified: false, defaulted: true }
    : { value: 0, source: "missing", label: "Missing", verified: false, defaulted: false };
}

function productSourceNumber(item = {}, keys = []) {
  return productSourceNumberDetail(item, keys).value || 0;
}

function shopifyVariantUsesPackageWeight(item = {}, variant = null) {
  if (!variant) return false;
  if (variant.key === "each") return false;
  const qty = Number(variant.uomQty || 1);
  return qty > 1 || (variant.key === "sell-unit" && productUomInfo(item).isMultiUnit);
}

function shopifyVariantWeightValue(item = {}, variant = null) {
  const preferPackage = shopifyVariantUsesPackageWeight(item, variant);
  const detail = shopifyWeightSourceDetail(item, preferPackage);
  return detail.value > 0 ? cleanExportNumber(detail.value, 3) : "";
}

function shopifyWeightSourceDetail(item = {}, preferPackage = false) {
  if (preferPackage) {
    return productSourceNumberDetail(item, ["packageWeight", "package_weight"], { defaultValue: SYSTEM_DEFAULT_WEIGHT_LB });
  }
  const pounds = productSourceNumberDetail(item, ["itemWeight", "item_weight", "weightLb", "weight_lbs"]);
  if (pounds.value > 0) return pounds;
  const ounces = productSourceNumberDetail(item, ["weightOz", "weight_oz"]);
  if (ounces.value > 0) return { ...ounces, value: ounces.value / 16 };
  return productSourceNumberDetail(item, [], { defaultValue: SYSTEM_DEFAULT_WEIGHT_LB });
}

function shopifyWeightSourceValue(item = {}, preferPackage = false) {
  return shopifyWeightSourceDetail(item, preferPackage).value || 0;
}

function shopifyDimensionSourceValue(item = {}, axis = "length", preferPackage = false) {
  const title = axis.charAt(0).toUpperCase() + axis.slice(1);
  const packageKeys = [`package${title}`, `package_${axis}`];
  const itemKeys = [`item${title}`, `item_${axis}`, `${axis}In`, `${axis}_in`];
  return productSourceNumberDetail(item, preferPackage ? packageKeys : itemKeys, { defaultValue: SYSTEM_DEFAULT_DIMENSION_IN }).value || 0;
}

function cleanExportNumber(value, decimals = 3) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "";
  return Number(number.toFixed(decimals)).toString();
}

function shopifyDimensionValue(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "";
  return `${cleanExportNumber(number, 3)} in`;
}

function shopifyWeightValue(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "";
  return `${cleanExportNumber(number, 3)} lb`;
}

function shopifyJsonNumber(value, decimals = 3) {
  const number = Number(sourceNumberValue(value));
  if (!Number.isFinite(number) || number <= 0) return "";
  const cleaned = Number(number.toFixed(decimals));
  return Number.isInteger(cleaned) ? `${cleaned}.0` : String(cleaned);
}

function shopifyDimensionMetafieldValue(value) {
  const number = shopifyJsonNumber(value, 3);
  return number ? `{"value":${number},"unit":"INCHES"}` : "";
}

function shopifyWeightMetafieldUnit(column = "") {
  return "POUNDS";
}

function shopifyWeightMetafieldValue(value, column = "") {
  const number = shopifyJsonNumber(value, 3);
  return number ? `{"value":${number},"unit":"${shopifyWeightMetafieldUnit(column)}"}` : "";
}

function shopifyBooleanValue(value, item = {}) {
  if (typeof value === "boolean") return value ? "TRUE" : "FALSE";
  const text = String(value ?? "").trim().toLowerCase();
  if (["true", "1", "yes", "y", "active", "in stock", "instock", "available", "received"].includes(text)) return "TRUE";
  if (["false", "0", "no", "n", "inactive", "out of stock", "outofstock", "unavailable", "discontinued", "deleted"].includes(text)) return "FALSE";
  if (Number.isFinite(Number(value))) return Number(value) > 0 ? "TRUE" : "FALSE";
  return Number(item.stockQty ?? item.qty ?? 0) > 0 ? "TRUE" : "FALSE";
}

function padDatePart(value) {
  return String(value).padStart(2, "0");
}

function shopifyDateTimeValue(value) {
  if (!value) return "";
  const text = String(value).trim();
  const dmy = text.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?)?$/);
  if (dmy) {
    const [, day, month, year, hour = "0", minute = "0"] = dmy;
    return `${year}-${padDatePart(month)}-${padDatePart(day)} ${padDatePart(hour)}:${padDatePart(minute)}`;
  }
  const date = new Date(text);
  if (Number.isNaN(date.getTime())) return "";
  return `${date.getUTCFullYear()}-${padDatePart(date.getUTCMonth() + 1)}-${padDatePart(date.getUTCDate())} ${padDatePart(date.getUTCHours())}:${padDatePart(date.getUTCMinutes())}`;
}

function shopifyJsonValue(value) {
  if (value === undefined || value === null || value === "") return "";
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed || trimmed === "[object Object]") return "";
    try {
      return JSON.stringify(JSON.parse(trimmed));
    } catch {
      return JSON.stringify(trimmed);
    }
  }
  return JSON.stringify(value);
}

function barcodeTextValue(value) {
  const raw = String(value ?? "").trim();
  if (!raw) return "";
  let text = raw;
  if (/^\d+(?:\.\d+)?e\+\d+$/i.test(text)) {
    const number = Number(text);
    if (Number.isFinite(number)) {
      text = number.toLocaleString("fullwide", { useGrouping: false, maximumFractionDigits: 0 });
    }
  }
  const digits = text.replace(/\D/g, "");
  if (!digits) return "";
  return digits.length > 7 && digits.length < 12 ? digits.padStart(12, "0") : digits;
}

function shopifyProductStatusValue(value, item = {}, mapping = {}) {
  const raw = String(item.shopifyStatus || value || mapping.defaultValue || item.status || "").trim().toLowerCase();
  if (["active", "published", "publish"].includes(raw)) return "Active";
  if (["archived", "archive", "deleted", "discontinued"].includes(raw)) return "Archived";
  return "Draft";
}

function shopifyPublishedValue(item = {}, mapping = {}) {
  if (item.shopifyPublished === true) return "TRUE";
  if (item.shopifyPublished === false && item.shopifyStatus) return "FALSE";
  return shopifyProductStatusValue(item.status, item, mapping) === "Active" ? "TRUE" : "FALSE";
}

function categoryTypeValue(value) {
  const parts = String(value || "")
    .split(">")
    .map((part) => part.trim())
    .filter(Boolean);
  return parts.slice(-2).join(" > ") || parts[0] || "";
}

function smartCollectionTitle(productType = "") {
  const parts = String(productType || "")
    .split(">")
    .map((part) => part.trim())
    .filter(Boolean);
  return parts.at(-1) || String(productType || "").trim();
}

function smartCollectionHandle(productType = "") {
  return String(productType || "")
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/&/g, " and ")
    .replace(/[^a-zA-Z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-{2,}/g, "-")
    .toLowerCase()
    .slice(0, 240);
}

function cleanSeoText(value = "") {
  return String(value || "")
    .replace(/\s+/g, " ")
    .replace(/\s+([,.;:!?])/g, "$1")
    .trim();
}

function truncateSeoText(value = "", max = 155) {
  const text = cleanSeoText(value);
  if (text.length <= max) return text;
  const sliced = text.slice(0, max + 1);
  const cut = sliced.lastIndexOf(" ");
  return cleanSeoText(`${sliced.slice(0, cut > 60 ? cut : max).replace(/[,.;&-]+$/g, "")}.`);
}

function smartCollectionSeoTitle(title = "") {
  const cleanTitle = cleanSeoText(title);
  const suffix = "on Sale";
  const value = cleanTitle.toLowerCase().includes("sale") ? cleanTitle : `${cleanTitle} ${suffix}`;
  return truncateSeoText(value, 70);
}

function smartCollectionSeoDescription(title = "", productType = "") {
  const cleanTitle = cleanSeoText(title);
  const typeParts = String(productType || "")
    .split(">")
    .map((part) => cleanSeoText(part))
    .filter(Boolean);
  const parent = typeParts.length > 1 ? typeParts[typeParts.length - 2] : "";
  const base = parent && parent.toLowerCase() !== cleanTitle.toLowerCase()
    ? `${cleanTitle} on sale for ${parent}. Shop quality ${cleanTitle.toLowerCase()} with fast ordering, reliable supply, and sharp everyday pricing.`
    : `${cleanTitle} on sale. Shop quality ${cleanTitle.toLowerCase()} with fast ordering, reliable supply, and sharp everyday pricing.`;
  return truncateSeoText(base, 155);
}

function normalizeSmartCollectionProfile(profile = {}, categoryName = "") {
  const productType = categoryTypeValue(profile.productType || profile.ruleCondition || categoryName);
  const title = String(profile.title || smartCollectionTitle(productType)).trim();
  const legacyTitle = title;
  const legacyDescription = `${title} products from DataPlus. Browse ${productType} with current catalog availability.`.slice(0, 155);
  const titleTag = !profile.titleTag || profile.titleTag === legacyTitle
    ? smartCollectionSeoTitle(title)
    : profile.titleTag;
  const descriptionTag = !profile.descriptionTag || profile.descriptionTag === legacyDescription || /dataplus/i.test(profile.descriptionTag)
    ? smartCollectionSeoDescription(title, productType)
    : profile.descriptionTag;
  return {
    enabled: profile.enabled !== false,
    productType,
    handle: smartCollectionHandle(profile.handle || productType),
    title,
    bodyHtml: profile.bodyHtml || profile.bodyHTML || "",
    sortOrder: profile.sortOrder || "Best Selling",
    templateSuffix: profile.templateSuffix || "",
    published: profile.published === undefined ? true : Boolean(profile.published),
    publishedScope: profile.publishedScope || "global",
    mustMatch: profile.mustMatch || "all conditions",
    ruleProductColumn: profile.ruleProductColumn || "Type",
    ruleRelation: profile.ruleRelation || "Equals",
    imageSrc: profile.imageSrc || profile.image || "",
    imageAltText: profile.imageAltText || title,
    titleTag,
    descriptionTag
  };
}

function productImageUrl(item = {}) {
  const images = [
    item.defaultImage,
    item.checkedImageUrl,
    item.originalImage,
    item.checkedImage?.url,
    item.productManagerFields?.default_image,
    item.productManagerFields?.checked_image?.url,
    ...(Array.isArray(item.images) ? item.images : []),
    ...(Array.isArray(item.productManagerFields?.images) ? item.productManagerFields.images : [])
  ];
  return images.map((image) => String(image || "").trim()).find((image) => /^https?:\/\//i.test(image)) || "";
}

function productImageUrls(item = {}) {
  const images = [
    item.defaultImage,
    item.default_image,
    item.checkedImageUrl,
    item.originalImage,
    item.original_image,
    item.checkedImage?.url,
    item.productManagerFields?.default_image,
    item.productManagerFields?.checked_image?.url,
    ...(Array.isArray(item.images) ? item.images : parseList(item.images)),
    ...(Array.isArray(item.imageUrls) ? item.imageUrls : parseList(item.imageUrls)),
    ...(Array.isArray(item.productManagerFields?.images) ? item.productManagerFields.images : [])
  ];
  return [...new Set(images.map((image) => String(image || "").trim()).filter((image) => /^https?:\/\//i.test(image)))];
}

function productTimestamp(item = {}) {
  for (const value of [
    item.updatedAt,
    item.productDumpUpdatedAt,
    item.validatedAt,
    item.productManagerFields?.updated_at,
    item.createdAt,
    item.productDumpCreatedAt,
    item.productManagerFields?.created_at
  ]) {
    const timestamp = Date.parse(value || "");
    if (Number.isFinite(timestamp)) return timestamp;
  }
  return 0;
}

async function latestCatalogImagesByProductType() {
  const byType = new Map();
  if (!fs.existsSync(CATALOG_FILE)) return byType;
  const rl = readline.createInterface({
    input: fs.createReadStream(CATALOG_FILE, { encoding: "utf8" }),
    crlfDelay: Infinity
  });
  for await (const line of rl) {
    if (!line.trim()) continue;
    let item;
    try {
      item = JSON.parse(line);
    } catch {
      continue;
    }
    const productType = categoryTypeValue(item.category || item.mainCategory || item.productManagerFields?.category || "");
    if (!productType) continue;
    const image = productImageUrl(item);
    if (!image) continue;
    const timestamp = productTimestamp(item);
    const current = byType.get(productType);
    if (!current || timestamp > current.timestamp) byType.set(productType, { image, timestamp });
  }
  return byType;
}

function matrixifySmartCollectionCacheByType() {
  if (!fs.existsSync(MATRIXIFY_SMART_COLLECTION_DATA_FILE)) return new Map();
  try {
    const data = JSON.parse(fs.readFileSync(MATRIXIFY_SMART_COLLECTION_DATA_FILE, "utf8"));
    return new Map((data.rows || [])
      .filter((row) => row.productType)
      .map((row) => [row.productType, row]));
  } catch {
    return new Map();
  }
}

async function matrixifySmartCollectionRows() {
  const categoryData = await publicCategoriesFast("", "main");
  const cachedRowsByType = matrixifySmartCollectionCacheByType();
  const seenHandles = new Set();
  const rows = (categoryData.categories || [])
    .filter((category) => Number(category.productCount || 0) > 0)
    .filter((category) => category.mappings?.shopify?.categoryId || category.mappings?.shopify?.categoryPath)
    .map((category) => {
      const productType = categoryTypeValue(category.name);
      const profile = normalizeSmartCollectionProfile(category.smartCollection || {}, category.name);
      const ruleCondition = profile.productType || productType;
      const title = profile.title || smartCollectionTitle(ruleCondition);
      const handle = profile.handle || smartCollectionHandle(ruleCondition);
      const image = profile.imageSrc || cachedRowsByType.get(ruleCondition)?.image || "";
      return {
        "Handle": handle,
        "Command": "MERGE",
        "Title": title,
        "Body HTML": profile.bodyHtml || "",
        "Sort Order": profile.sortOrder || "Best Selling",
        "Template Suffix": profile.templateSuffix || "",
        "Published": profile.published ? "TRUE" : "FALSE",
        "Published Scope": profile.publishedScope || "global",
        "Image Src": image,
        "Image Alt Text": profile.imageAltText || title,
        "Must Match": profile.mustMatch || "all conditions",
        "Rule: Product Column": profile.ruleProductColumn || "Type",
        "Rule: Relation": profile.ruleRelation || "Equals",
        "Rule: Condition": ruleCondition,
        "Product: ID": "",
        "Product: Handle": "",
        "Product: Position": "",
        "Metafield: title_tag [string]": profile.titleTag || title,
        "Metafield: description_tag [string]": profile.descriptionTag || smartCollectionSeoDescription(title, ruleCondition),
        "Metafield: custom.fda_approved [boolean]": ""
      };
    })
    .filter((row) => row.Handle && row.Title && row["Rule: Condition"])
    .filter((row) => {
      if (seenHandles.has(row.Handle)) return false;
      seenHandles.add(row.Handle);
      return true;
    });
  rows.push(closeoutSmartCollectionRow());
  return rows
    .filter((row) => {
      if (seenHandles.has(row.Handle)) return false;
      seenHandles.add(row.Handle);
      return true;
    })
    .sort((a, b) => a.Handle.localeCompare(b.Handle));
}

function closeoutSmartCollectionRow() {
  return {
    "Handle": "closeouts",
    "Command": "MERGE",
    "Title": "Closeouts",
    "Body HTML": "",
    "Sort Order": "Best Selling",
    "Template Suffix": "",
    "Published": "TRUE",
    "Published Scope": "global",
    "Image Src": "",
    "Image Alt Text": "Closeouts",
    "Must Match": "all conditions",
    "Rule: Product Column": "Tag",
    "Rule: Relation": "Equals",
    "Rule: Condition": "closeout",
    "Product: ID": "",
    "Product: Handle": "",
    "Product: Position": "",
    "Metafield: title_tag [string]": "Closeouts on Sale",
    "Metafield: description_tag [string]": "Closeout deals on discontinued products while supplies last.",
    "Metafield: custom.fda_approved [boolean]": ""
  };
}

const MATRIXIFY_MENU_COLUMNS = [
  "ID",
  "Handle",
  "Command",
  "Title",
  "Is Default",
  "Top Row",
  "Row #",
  "Menu Item: ID",
  "Menu Item: Title",
  "Menu Item: Command",
  "Menu Item: Resource Type",
  "Menu Item: Resource ID",
  "Menu Item: Resource Handle",
  "Menu Item: Collection Tags",
  "Menu Item: URL",
  "Menu Item: Parent ID",
  "Menu Item: Parent Title",
  "Menu Item: Position"
];

function readShopifyMenuCollectionMapping() {
  if (!fs.existsSync(MATRIXIFY_MENU_MAPPING_FILE)) return [];
  try {
    return parseCsv(fs.readFileSync(MATRIXIFY_MENU_MAPPING_FILE, "utf8"));
  } catch {
    return [];
  }
}

function menuMappingLookup(rows = []) {
  const map = new Map();
  const add = (key, row) => {
    const normalized = String(key || "").trim().toLowerCase();
    if (normalized && !map.has(normalized)) map.set(normalized, row);
  };
  for (const row of rows) {
    add(row["Product Type Rule"], row);
    add(row["Original Full Category Path"], row);
    add(row["Collection Handle"], row);
    add(row["Collection URL"], row);
    add(row["Menu Path"], row);
  }
  return map;
}

function readMatrixifyMenuImportTemplate() {
  if (!fs.existsSync(MATRIXIFY_MENU_IMPORT_TEMPLATE_FILE)) return [];
  try {
    return parseCsv(fs.readFileSync(MATRIXIFY_MENU_IMPORT_TEMPLATE_FILE, "utf8"));
  } catch {
    return [];
  }
}

function matrixifyMenuTemplateIds(rows = []) {
  const ids = new Map();
  let maxId = 999;
  const add = (key, value) => {
    const id = String(value || "").trim();
    if (!key || !id) return;
    ids.set(key, id);
    const numeric = Number(id);
    if (Number.isFinite(numeric)) maxId = Math.max(maxId, numeric);
  };
  for (const row of rows) {
    const id = row["Menu Item: ID"];
    const title = String(row["Menu Item: Title"] || "").trim();
    const parentId = String(row["Menu Item: Parent ID"] || "").trim();
    const parentTitle = String(row["Menu Item: Parent Title"] || "").trim();
    const resourceHandle = String(row["Menu Item: Resource Handle"] || "").trim();
    const resourceType = String(row["Menu Item: Resource Type"] || "").trim().toUpperCase();
    if (resourceType === "COLLECTION" && resourceHandle) add(`collection|${resourceHandle.toLowerCase()}`, id);
    if (resourceType === "HTTP" && title && !parentId && !parentTitle) add(`department|${title.toLowerCase()}`, id);
    if (resourceType === "HTTP" && title && (parentId || parentTitle)) add(`group|${parentTitle.toLowerCase()}|${title.toLowerCase()}`, id);
  }
  return {
    next() {
      maxId += 1;
      return String(maxId);
    },
    getOrCreate(key) {
      const normalized = String(key || "").toLowerCase();
      if (ids.has(normalized)) return ids.get(normalized);
      const id = this.next();
      ids.set(normalized, id);
      return id;
    }
  };
}

function matrixifyMenuTemplateOrder(rows = []) {
  const order = new Map();
  let index = 0;
  const add = (key) => {
    const normalized = String(key || "").toLowerCase();
    if (normalized && !order.has(normalized)) {
      index += 1;
      order.set(normalized, index);
    }
  };
  for (const row of rows) {
    const title = String(row["Menu Item: Title"] || "").trim();
    const parentTitle = String(row["Menu Item: Parent Title"] || "").trim();
    const resourceHandle = String(row["Menu Item: Resource Handle"] || "").trim();
    const resourceType = String(row["Menu Item: Resource Type"] || "").trim().toUpperCase();
    if (resourceType === "COLLECTION" && resourceHandle) add(`collection|${resourceHandle}`);
    if (resourceType === "HTTP" && title && !parentTitle) add(`department|${title}`);
    if (resourceType === "HTTP" && title && parentTitle) add(`group|${parentTitle}|${title}`);
  }
  return {
    value(key) {
      return order.get(String(key || "").toLowerCase()) || 999999;
    }
  };
}

function matrixifyMenuTemplateTitles(rows = []) {
  const titles = new Map();
  const add = (key, value) => {
    const normalized = String(key || "").toLowerCase();
    const title = String(value || "").trim();
    if (normalized && title && !titles.has(normalized)) titles.set(normalized, title);
  };
  for (const row of rows) {
    const title = String(row["Menu Item: Title"] || "").trim();
    const parentTitle = String(row["Menu Item: Parent Title"] || "").trim();
    const resourceHandle = String(row["Menu Item: Resource Handle"] || "").trim();
    const resourceType = String(row["Menu Item: Resource Type"] || "").trim().toUpperCase();
    if (resourceType === "COLLECTION" && resourceHandle) add(`collection|${resourceHandle}`, title);
    if (resourceType === "HTTP" && title && !parentTitle) add(`department|${title}`, title);
    if (resourceType === "HTTP" && title && parentTitle) add(`group|${parentTitle}|${title}`, title);
  }
  return {
    value(key, fallback = "") {
      return titles.get(String(key || "").toLowerCase()) || fallback;
    }
  };
}

function matrixifyMenuEntryMap(entries = []) {
  const map = new Map();
  for (const entry of entries) {
    if (entry.collectionHandle) map.set(String(entry.collectionHandle).toLowerCase(), entry);
  }
  return map;
}

function categoryMenuDefaults(category = {}, profile = {}) {
  const parts = String(category.name || profile.productType || "")
    .split(">")
    .map((part) => part.trim())
    .filter(Boolean);
  const productTypeParts = String(profile.productType || categoryTypeValue(category.name))
    .split(">")
    .map((part) => part.trim())
    .filter(Boolean);
  const top = parts[0] || productTypeParts[0] || "Catalog";
  const group = parts[1] || productTypeParts[0] || top;
  const title = profile.title || smartCollectionTitle(profile.productType || category.name);
  return {
    topDepartment: top,
    menuGroup: group,
    collectionTitle: title,
    menuPath: [top, group, title].filter(Boolean).join(" > "),
    label: title,
    productType: profile.productType || categoryTypeValue(category.name),
    originalCategoryPath: category.name || ""
  };
}

function matrixifyMenuItemId(...parts) {
  return smartCollectionHandle(parts.filter(Boolean).join("-"));
}

function uniqueMatrixifyMenuEntries(entries = []) {
  const byHandle = new Map();
  for (const entry of entries) {
    const handle = String(entry?.collectionHandle || "").trim().toLowerCase();
    if (!handle) continue;
    const existing = byHandle.get(handle);
    if (!existing || Number(entry.productCount || 0) > Number(existing.productCount || 0)) {
      byHandle.set(handle, entry);
    }
  }
  return [...byHandle.values()];
}

async function matrixifyMenuRows() {
  const categoryData = await publicCategoriesFast("", "main");
  const seedMap = menuMappingLookup(readShopifyMenuCollectionMapping());
  const templateRows = readMatrixifyMenuImportTemplate();
  const idRegistry = matrixifyMenuTemplateIds(templateRows);
  const orderRegistry = matrixifyMenuTemplateOrder(templateRows);
  const titleRegistry = matrixifyMenuTemplateTitles(templateRows);
  const entries = uniqueMatrixifyMenuEntries((categoryData.categories || [])
    .filter((category) => Number(category.productCount || 0) > 0)
    .filter((category) => category.mappings?.shopify?.categoryId || category.mappings?.shopify?.categoryPath)
    .map((category) => {
      const profile = normalizeSmartCollectionProfile(category.smartCollection || {}, category.name);
      const handle = profile.handle || smartCollectionHandle(profile.productType || category.name);
      const seed = seedMap.get(String(profile.productType || "").toLowerCase())
        || seedMap.get(String(category.name || "").toLowerCase())
        || seedMap.get(String(handle || "").toLowerCase())
        || null;
      const defaults = categoryMenuDefaults(category, profile);
      const topDepartment = seed?.["Top Menu Department"] || defaults.topDepartment;
      const menuGroup = seed?.["Menu Group"] || defaults.menuGroup;
      const collectionHandle = seed?.["Collection Handle"] || handle;
      return {
        topDepartment,
        menuGroup,
        collectionTitle: seed?.["Collection Title"] || defaults.collectionTitle,
        label: titleRegistry.value(`collection|${collectionHandle}`, seed?.["Shopify Menu Item Label"] || seed?.["Collection Title"] || defaults.label),
        linkType: seed?.["Shopify Link Type"] || "Collection",
        collectionUrl: seed?.["Collection URL"] || `/collections/${handle}`,
        collectionHandle,
        productType: seed?.["Product Type Rule"] || defaults.productType,
        originalCategoryPath: seed?.["Original Full Category Path"] || defaults.originalCategoryPath,
        menuPath: seed?.["Menu Path"] || defaults.menuPath,
        productCount: Number(category.productCount || 0)
      };
    })
    .filter((entry) => entry.collectionHandle && entry.label))
    .sort((a, b) => {
      const departmentDiff = orderRegistry.value(`department|${a.topDepartment}`) - orderRegistry.value(`department|${b.topDepartment}`);
      if (departmentDiff) return departmentDiff;
      const groupDiff = orderRegistry.value(`group|${a.topDepartment}|${a.menuGroup}`) - orderRegistry.value(`group|${b.topDepartment}|${b.menuGroup}`);
      if (groupDiff) return groupDiff;
      const collectionDiff = orderRegistry.value(`collection|${a.collectionHandle}`) - orderRegistry.value(`collection|${b.collectionHandle}`);
      if (collectionDiff) return collectionDiff;
      return [a.topDepartment, a.menuGroup, a.label].join(" > ").localeCompare([b.topDepartment, b.menuGroup, b.label].join(" > "));
    });
  if (templateRows.length) {
    const entryByHandle = matrixifyMenuEntryMap(entries);
    const rows = templateRows.map((row, index) => {
      const next = Object.fromEntries(MATRIXIFY_MENU_COLUMNS.map((column) => [column, row[column] ?? ""]));
      next["Row #"] = index + 1;
      const handle = String(next["Menu Item: Resource Handle"] || "").trim().toLowerCase();
      const entry = handle ? entryByHandle.get(handle) : null;
      if (entry) {
        next["Menu Item: Resource Handle"] = entry.collectionHandle;
        next["Menu Item: Title"] = titleRegistry.value(`collection|${entry.collectionHandle}`, next["Menu Item: Title"] || entry.label);
        next["Menu Item: Resource Type"] = "COLLECTION";
        next["Menu Item: URL"] = "";
        entryByHandle.delete(handle);
      }
      return next;
    });
    const departmentIds = new Map();
    const groupIds = new Map();
    const leafPosition = new Map();
    let rowNumber = rows.length;
    for (const row of rows) {
      const type = String(row["Menu Item: Resource Type"] || "").trim().toUpperCase();
      const title = String(row["Menu Item: Title"] || "").trim();
      const parentTitle = String(row["Menu Item: Parent Title"] || "").trim();
      const id = String(row["Menu Item: ID"] || "").trim();
      if (!title || !id) continue;
      if (type === "HTTP" && !parentTitle) departmentIds.set(title.toLowerCase(), id);
      if (type === "HTTP" && parentTitle) groupIds.set(`${parentTitle.toLowerCase()}|${title.toLowerCase()}`, id);
      if (type === "COLLECTION" && parentTitle) {
        const key = `${String(row["Menu Item: Parent ID"] || "").trim()}|${parentTitle.toLowerCase()}`;
        leafPosition.set(key, Math.max(leafPosition.get(key) || 0, Number(row["Menu Item: Position"] || 0)));
      }
    }
    for (const entry of entryByHandle.values()) {
      const departmentTitle = titleRegistry.value(`department|${entry.topDepartment}`, entry.topDepartment);
      let departmentId = departmentIds.get(departmentTitle.toLowerCase());
      if (!departmentId) {
        departmentId = idRegistry.getOrCreate(`department|${departmentTitle}`);
        departmentIds.set(departmentTitle.toLowerCase(), departmentId);
        const position = [...departmentIds.keys()].length;
        rows.push({
          "Handle": "main-menu",
          "Command": "MERGE",
          "Title": "Main menu",
          "Row #": ++rowNumber,
          "Menu Item: ID": departmentId,
          "Menu Item: Title": departmentTitle,
          "Menu Item: Command": "MERGE",
          "Menu Item: Resource Type": "HTTP",
          "Menu Item: URL": "#",
          "Menu Item: Position": position
        });
      }
      const groupTitle = titleRegistry.value(`group|${entry.topDepartment}|${entry.menuGroup}`, entry.menuGroup);
      const groupKey = `${departmentTitle.toLowerCase()}|${groupTitle.toLowerCase()}`;
      let groupId = groupIds.get(groupKey);
      if (!groupId) {
        groupId = idRegistry.getOrCreate(`group|${departmentTitle}|${groupTitle}`);
        groupIds.set(groupKey, groupId);
        rows.push({
          "Handle": "main-menu",
          "Command": "MERGE",
          "Title": "Main menu",
          "Row #": ++rowNumber,
          "Menu Item: ID": groupId,
          "Menu Item: Title": groupTitle,
          "Menu Item: Command": "MERGE",
          "Menu Item: Resource Type": "HTTP",
          "Menu Item: URL": "#",
          "Menu Item: Parent ID": departmentId,
          "Menu Item: Parent Title": departmentTitle,
          "Menu Item: Position": [...groupIds.keys()].filter((key) => key.startsWith(`${departmentTitle.toLowerCase()}|`)).length
        });
      }
      const leafKey = `${groupId}|${groupTitle.toLowerCase()}`;
      const position = (leafPosition.get(leafKey) || 0) + 1;
      leafPosition.set(leafKey, position);
      rows.push({
        "Handle": "main-menu",
        "Command": "MERGE",
        "Title": "Main menu",
        "Row #": ++rowNumber,
        "Menu Item: ID": idRegistry.getOrCreate(`collection|${entry.collectionHandle}`),
        "Menu Item: Title": entry.label,
        "Menu Item: Command": "MERGE",
        "Menu Item: Resource Type": "COLLECTION",
        "Menu Item: Resource Handle": entry.collectionHandle,
        "Menu Item: Parent ID": groupId,
        "Menu Item: Parent Title": groupTitle,
        "Menu Item: Position": position
      });
    }
    return rows.map((row, index) => Object.fromEntries(MATRIXIFY_MENU_COLUMNS.map((column) => [column, column === "Row #" ? index + 1 : row[column] ?? ""])));
  }
  const rows = [];
  let rowNumber = 1;
  rows.push({
    "ID": "",
    "Handle": "main-menu",
    "Command": "MERGE",
    "Title": "Main menu",
    "Is Default": "",
    "Top Row": "",
    "Row #": rowNumber
  });
  const seenDepartments = new Set();
  const seenGroups = new Set();
  const departmentPosition = new Map();
  const groupPosition = new Map();
  const leafPosition = new Map();
  for (const entry of entries) {
    const departmentId = idRegistry.getOrCreate(`department|${entry.topDepartment}`);
    const departmentTitle = titleRegistry.value(`department|${entry.topDepartment}`, entry.topDepartment);
    if (!seenDepartments.has(departmentId)) {
      seenDepartments.add(departmentId);
      const position = (departmentPosition.size || 0) + 1;
      departmentPosition.set(entry.topDepartment, position);
      rows.push({
        "Handle": "main-menu",
        "Command": "MERGE",
        "Title": "Main menu",
        "Is Default": "",
        "Top Row": "",
        "Row #": ++rowNumber,
        "Menu Item: ID": departmentId,
        "Menu Item: Title": departmentTitle,
        "Menu Item: Command": "MERGE",
        "Menu Item: Resource Type": "HTTP",
        "Menu Item: URL": "#",
        "Menu Item: Position": position
      });
    }
    const groupId = idRegistry.getOrCreate(`group|${entry.topDepartment}|${entry.menuGroup}`);
    const groupTitle = titleRegistry.value(`group|${entry.topDepartment}|${entry.menuGroup}`, entry.menuGroup);
    if (!seenGroups.has(groupId)) {
      seenGroups.add(groupId);
      const groupKey = entry.topDepartment;
      const position = (groupPosition.get(groupKey) || 0) + 1;
      groupPosition.set(groupKey, position);
      rows.push({
        "Handle": "main-menu",
        "Command": "MERGE",
        "Title": "Main menu",
        "Is Default": "",
        "Top Row": "",
        "Row #": ++rowNumber,
        "Menu Item: ID": groupId,
        "Menu Item: Title": groupTitle,
        "Menu Item: Command": "MERGE",
        "Menu Item: Resource Type": "HTTP",
        "Menu Item: URL": "#",
        "Menu Item: Parent ID": departmentId,
        "Menu Item: Parent Title": departmentTitle,
        "Menu Item: Position": position
      });
    }
    const leafKey = `${entry.topDepartment} > ${entry.menuGroup}`;
    const position = (leafPosition.get(leafKey) || 0) + 1;
    leafPosition.set(leafKey, position);
    rows.push({
      "Handle": "main-menu",
      "Command": "MERGE",
      "Title": "Main menu",
      "Is Default": "",
      "Top Row": "",
      "Row #": ++rowNumber,
      "Menu Item: ID": idRegistry.getOrCreate(`collection|${entry.collectionHandle}`),
      "Menu Item: Title": entry.label,
      "Menu Item: Command": "MERGE",
      "Menu Item: Resource Type": "COLLECTION",
      "Menu Item: Resource Handle": entry.collectionHandle,
      "Menu Item: URL": "",
      "Menu Item: Parent ID": groupId,
      "Menu Item: Parent Title": groupTitle,
      "Menu Item: Position": position
    });
  }
  return rows.map((row) => Object.fromEntries(MATRIXIFY_MENU_COLUMNS.map((column) => [column, row[column] ?? ""])));
}

function matrixifySmartCollectionReadiness(mainRows = [], settings = []) {
  const cachedRowsByType = matrixifySmartCollectionCacheByType();
  const settingForName = (name) => settings.find((row) => formatCategoryName(row.name).toLowerCase() === formatCategoryName(name).toLowerCase());
  const rows = mainRows
    .filter((row) => Number(row.productCount || 0) > 0)
    .map((row) => {
      const setting = settingForName(row.name) || {};
      const shopify = normalizeChannelCategoryMapping(setting.mappings?.shopify || {});
      const profile = normalizeSmartCollectionProfile(setting.smartCollection || {}, row.name);
      const image = profile.imageSrc || cachedRowsByType.get(profile.productType)?.image || "";
      const mapped = Boolean(shopify.categoryId || shopify.categoryPath);
      return {
        category: row.name,
        products: row.productCount || 0,
        shopify_category: shopify.categoryPath || "",
        shopify_category_id: shopify.categoryId || "",
        product_type: profile.productType || "",
        collection_handle: profile.handle || "",
        collection_title: profile.title || "",
        title_tag: profile.titleTag || "",
        description_tag: profile.descriptionTag || "",
        image_src: image,
        ready: Boolean(mapped && profile.productType && profile.handle && profile.title),
        missing_shopify: !mapped,
        missing_product_type: !profile.productType,
        missing_image: !image
      };
    });
  const handleCounts = new Map();
  const titleTagCounts = new Map();
  const descriptionCounts = new Map();
  for (const row of rows.filter((row) => !row.missing_shopify && row.collection_handle)) {
    handleCounts.set(row.collection_handle, (handleCounts.get(row.collection_handle) || 0) + 1);
  }
  for (const row of rows.filter((row) => !row.missing_shopify)) {
    if (row.title_tag) titleTagCounts.set(row.title_tag.toLowerCase(), (titleTagCounts.get(row.title_tag.toLowerCase()) || 0) + 1);
    if (row.description_tag) descriptionCounts.set(row.description_tag.toLowerCase(), (descriptionCounts.get(row.description_tag.toLowerCase()) || 0) + 1);
  }
  for (const row of rows) {
    row.duplicate_handle = Boolean(row.collection_handle && handleCounts.get(row.collection_handle) > 1);
    row.duplicate_title_tag = Boolean(row.title_tag && titleTagCounts.get(row.title_tag.toLowerCase()) > 1);
    row.duplicate_description_tag = Boolean(row.description_tag && descriptionCounts.get(row.description_tag.toLowerCase()) > 1);
    row.weak_title_tag = !row.title_tag || row.title_tag.length < 18 || row.title_tag.length > 70 || /dataplus|products from|browse now/i.test(row.title_tag);
    row.weak_description_tag = !row.description_tag || row.description_tag.length < 80 || row.description_tag.length > 160 || /dataplus|products from|browse now/i.test(row.description_tag);
  }
  const exportable = rows.filter((row) => !row.missing_shopify);
  const notReady = exportable.filter((row) => !row.ready || row.duplicate_handle || row.weak_title_tag || row.weak_description_tag || row.duplicate_title_tag || row.duplicate_description_tag);
  return {
    rows,
    exportableCount: exportable.length,
    readyCount: exportable.length - notReady.length,
    notReadyCount: notReady.length,
    missingShopifyCount: rows.filter((row) => row.missing_shopify).length,
    duplicateHandleCount: rows.filter((row) => row.duplicate_handle).length,
    missingProductTypeCount: exportable.filter((row) => row.missing_product_type).length,
    missingImageCount: exportable.filter((row) => row.missing_image).length,
    weakSeoCount: exportable.filter((row) => row.weak_title_tag || row.weak_description_tag || row.duplicate_title_tag || row.duplicate_description_tag).length
  };
}

function matrixifyMenuReviewRows(rows = []) {
  const itemRows = rows.filter((row) => row["Menu Item: ID"] || row["Menu Item: Title"] || row["Menu Item: Resource Handle"]);
  const idCounts = new Map();
  const parentTitleCounts = new Map();
  const handleCounts = new Map();
  for (const row of itemRows) {
    const id = String(row["Menu Item: ID"] || "").trim();
    const parentKey = `${String(row["Menu Item: Parent ID"] || "").trim()}|${String(row["Menu Item: Parent Title"] || "").trim().toLowerCase()}|${String(row["Menu Item: Title"] || "").trim().toLowerCase()}`;
    const handle = String(row["Menu Item: Resource Handle"] || "").trim().toLowerCase();
    if (id) idCounts.set(id, (idCounts.get(id) || 0) + 1);
    if (row["Menu Item: Title"]) parentTitleCounts.set(parentKey, (parentTitleCounts.get(parentKey) || 0) + 1);
    if (handle) handleCounts.set(handle, (handleCounts.get(handle) || 0) + 1);
  }
  const issues = [];
  for (const row of itemRows) {
    const id = String(row["Menu Item: ID"] || "").trim();
    const title = String(row["Menu Item: Title"] || "").trim();
    const type = String(row["Menu Item: Resource Type"] || "").trim().toUpperCase();
    const handle = String(row["Menu Item: Resource Handle"] || "").trim();
    const url = String(row["Menu Item: URL"] || "").trim();
    const parentKey = `${String(row["Menu Item: Parent ID"] || "").trim()}|${String(row["Menu Item: Parent Title"] || "").trim().toLowerCase()}|${title.toLowerCase()}`;
    const add = (issue, severity = "warning") => issues.push({
      row_number: row["Row #"] || "",
      menu_item_id: id,
      title,
      parent_title: row["Menu Item: Parent Title"] || "",
      resource_type: type,
      resource_handle: handle,
      issue,
      severity
    });
    if (!id) add("Menu item is missing an ID", "error");
    if (id && idCounts.get(id) > 1) add("Duplicate Menu Item ID", "error");
    if (!title) add("Menu item is missing a title", "error");
    if (title && parentTitleCounts.get(parentKey) > 1) add("Duplicate menu title under the same parent", "warning");
    if (type === "COLLECTION" && !handle) add("Collection menu item is missing Resource Handle", "error");
    if (type === "COLLECTION" && url) add("Collection menu item should use Resource Handle, not URL", "warning");
    if (handle && handleCounts.get(handle.toLowerCase()) > 1) add("Duplicate collection handle in menu", "warning");
    if (type === "HTTP" && !url) add("HTTP menu item is missing URL", "warning");
    if (!["", "HTTP", "COLLECTION"].includes(type)) add("Unsupported Matrixify menu resource type", "error");
  }
  return issues;
}

function formatMappedExportValue(value, mapping = {}, item = {}) {
  const column = String(mapping.externalColumn || "");
  if (/^Variant Barcode$/i.test(column) && item.__shopifyVariant && productUomInfo(item).isMultiUnit) {
    return item.__shopifyVariant.key === "each" ? barcodeTextValue(value) : "";
  }
  if (/^(Variant Barcode|Barcode|UPC|GTIN|EAN)$/i.test(column)) return barcodeTextValue(value);
  if (/^Type$/i.test(column)) return categoryTypeValue(value);
  if (/^Status$/i.test(column)) return shopifyProductStatusValue(value, item, mapping);
  if (/^Published$/i.test(column)) return shopifyPublishedValue(item, mapping);
  if (/^Variant Inventory Tracker$/i.test(column)) return "shopify";
  if (/^Metafield:\s*custom\..*\[dimension\]/i.test(column)) {
    if (Number(item.__shopifyVariantRow || 1) > 1) return "";
    const derived = /^Metafield:\s*custom\.item_height\s/i.test(column) ? shopifyDimensionSourceValue(item, "height", false)
      : /^Metafield:\s*custom\.item_length\s/i.test(column) ? shopifyDimensionSourceValue(item, "length", false)
        : /^Metafield:\s*custom\.item_width\s/i.test(column) ? shopifyDimensionSourceValue(item, "width", false)
          : /^Metafield:\s*custom\.package_height\s/i.test(column) ? shopifyDimensionSourceValue(item, "height", true)
            : /^Metafield:\s*custom\.package_length\s/i.test(column) ? shopifyDimensionSourceValue(item, "length", true)
              : /^Metafield:\s*custom\.package_width\s/i.test(column) ? shopifyDimensionSourceValue(item, "width", true)
                : value;
    return shopifyDimensionMetafieldValue(derived || value);
  }
  if (/^Metafield:\s*custom\..*\[weight\]/i.test(column)) {
    if (Number(item.__shopifyVariantRow || 1) > 1) return "";
    const derived = /^Metafield:\s*custom\.item_weight\s/i.test(column) ? shopifyWeightSourceValue(item, false)
      : /^Metafield:\s*custom\.package_weight\s/i.test(column) ? shopifyWeightSourceValue(item, true)
        : value;
    return shopifyWeightMetafieldValue(derived || value, column);
  }
  if (/^Metafield:\s*custom\..*\[boolean\]/i.test(column)) return shopifyBooleanValue(value, item);
  if (/^Metafield:\s*custom\..*\[date_time\]/i.test(column)) return shopifyDateTimeValue(value);
  if (/^Metafield:\s*custom\..*\[json\]/i.test(column)) return shopifyJsonValue(value);
  if (Array.isArray(value)) return value.join("|");
  if (value && typeof value === "object") return JSON.stringify(value);
  return value;
}

function castMappedProductValue(field, value) {
  const definition = PRODUCT_MAPPING_FIELDS.find((item) => item.key === field);
  if (!definition) return value;
  if (definition.type === "number") return Number.isFinite(Number(value)) ? Number(value) : undefined;
  if (definition.type === "boolean") return value === true || ["true", "1", "yes", "active"].includes(String(value || "").trim().toLowerCase());
  if (definition.type === "list") return parseList(value);
  return value;
}

function mappedRecordToProductPayload(record, template) {
  const payload = {};
  for (const mapping of template.mappings || []) {
    if (!record || record[mapping.externalColumn] === undefined) continue;
    const field = mapping.productField;
    if (!PRODUCT_MAPPING_FIELDS.some((definition) => definition.key === field) || field === "available" || field === "shopifyHandle" || field.startsWith("google")) continue;
    const value = castMappedProductValue(field, record[mapping.externalColumn]);
    if (value !== undefined) {
      payload[field] = value;
      if (DIMENSION_WEIGHT_FIELDS.has(field)) {
        payload.dimensionWeightSources = {
          ...(payload.dimensionWeightSources || {}),
          [field]: { source: "manual_import", verified: true, updatedAt: new Date().toISOString() }
        };
      }
    }
  }
  return payload;
}

function mappedProductsCsv(db, template, items, options = {}) {
  const mappings = exportMappingsForTemplate(template);
  const headers = mappings.map((mapping) => mapping.externalColumn);
  const templateSource = exportValueTemplateSource(template);
  const shopifyStatusMap = isShopifyTemplate(template) ? (options.shopifyStatusMap || readShopifyStatusMapSync()) : {};
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const exportItems = items.flatMap((item) => isShopifyTemplate(template)
    ? (() => {
      const shopifyItem = withShopifyStatus(sourceEnrichedItem(item, sourceEnrichmentMap), shopifyStatusMap, db);
      const pricedItem = shopifyPricedExportItem(shopifyItem, null, db);
      productExportCache(db, pricedItem);
      return shopifyPurchaseVariants(pricedItem, db).map((variant, index) => ({ ...pricedItem, __shopifyVariant: variant, __shopifyVariantRow: index + 1 }));
    })()
    : [item]);
  const rows = exportItems.map((item) => mappings.map((mapping) => {
    const value = productFieldValue(db, item, mapping.productField, { ...mapping, templateSource, templateId: template.id });
    const formatted = formatMappedExportValue(value, mapping, item);
    return formatted === "" || formatted === undefined || formatted === null ? mapping.defaultValue || "" : formatted;
  }));
  return [headers, ...rows].map((row) => row.map(escapeCsv).join(",")).join("\n");
}

function hasUsableShopifyExportPricing(item = {}) {
  const cost = sourceCatalogCost(item);
  const sellUnitCost = productSellUnitCost({ ...item, sourceCost: cost });
  return websitePriceFromRule(item, sellUnitCost || cost, SHOPIFY_PRICE_MARKUP_PERCENT) > 0;
}

function titleLooksLikeSku(value = "", sku = "") {
  const title = sourceTextValue(value).toLowerCase();
  const key = sourceTextValue(sku).toLowerCase();
  return Boolean(title && key && title === key);
}

function mergeSourceCatalogExportFallback(item = {}, sourceItem = null) {
  if (!sourceItem) return item;
  const source = normalizeCatalogProductForInventory(sourceItem);
  if (!source?.sku) return item;
  const merged = { ...item };
  for (const field of [
    "title", "marketplaceTitle", "brand", "sourceBrand", "manufacturer", "mfrPartNumber",
    "vendorSku", "supplier", "supplierCode", "barcode", "uom", "uomQty", "minQuantity",
    "quantityIncrements", "stockStatus", "countryOfOrigin", "sourceCategory", "vendorCategory",
    "defaultImage", "originalImage", "shortDescription", "longDescription", "vendorDescription"
  ]) {
    const current = sourceTextValue(merged[field]);
    const incoming = sourceTextValue(source[field]);
    if (!incoming) continue;
    if (!current || titleLooksLikeSku(current, item.sku)) merged[field] = source[field];
  }
  for (const field of ["stockQty", "qty", "toBeDiscontinued", "closeoutEligible"]) {
    if (source[field] !== undefined && source[field] !== null && source[field] !== "") merged[field] = source[field];
  }
  for (const field of [
    "cost", "sourceCost", "sellUnitCost", "price", "websitePrice", "vendorWebsitePrice",
    "minimumAllowedPrice", "fobPrice", "listPrice", "msrp",
    "itemHeight", "itemLength", "itemWeight", "itemWidth",
    "packageHeight", "packageLength", "packageWeight", "packageWidth",
    "dimensionalWeight"
  ]) {
    if (!(Number(sourceNumberValue(merged[field])) > 0) && Number(sourceNumberValue(source[field])) > 0) {
      merged[field] = source[field];
    }
  }
  if ((!Array.isArray(merged.images) || !merged.images.length) && Array.isArray(source.images)) merged.images = source.images;
  merged.productManagerFields = Object.keys(merged.productManagerFields || {}).length ? merged.productManagerFields : source.productManagerFields;
  merged.original = merged.original || source.original;
  merged.sources = { ...(source.sources || {}), ...(merged.sources || {}), sourceCatalogExportFallback: source.sku };
  return merged;
}

async function sourceCatalogExportFallbackMap(items = []) {
  if (!postgres.isPostgresEnabled()) return new Map();
  const needsFallback = (Array.isArray(items) ? items : []).filter((item) => {
    if (!item?.sku) return false;
    const vendorWebsitePrice = Number(sourceNumberValue(item.vendorWebsitePrice ?? item.vendor_website_price ?? item.productManagerFields?.vendor_website_price ?? 0));
    const missingText = ["shortDescription", "longDescription"].some((field) => !sourceTextValue(item[field]));
    const missingMeasurement = [
      "itemHeight", "itemLength", "itemWeight", "itemWidth",
      "packageHeight", "packageLength", "packageWeight", "packageWidth"
    ].some((field) => !(Number(sourceNumberValue(item[field])) > 0));
    const missingCore = ["brand", "manufacturer", "mfrPartNumber", "vendorSku", "uom", "uomQty"].some((field) => !sourceTextValue(item[field]));
    return !hasUsableShopifyExportPricing(item) || !(vendorWebsitePrice > 0) || missingText || missingMeasurement || missingCore;
  });
  if (!needsFallback.length) return new Map();
  const rows = await postgres.readVendorCatalogItemsBySkus(needsFallback.map((item) => item.sku)).catch((error) => {
    console.warn("Unable to load source catalog export fallback pricing:", error.message);
    return [];
  });
  const map = new Map();
  for (const row of rows || []) {
    for (const key of [row.sku, row.sourceSku, row.internalSku, row.vendorSku]) {
      const normalized = sourceTextValue(key).toLowerCase();
      if (normalized && !map.has(normalized)) map.set(normalized, row);
    }
  }
  return map;
}

function shopifyPricedExportItem(item = {}, sourceFallbackMap = null, db = null) {
  const fallback = sourceFallbackMap?.get?.(sourceTextValue(item.sku).toLowerCase()) || null;
  const exportItem = mergeSourceCatalogExportFallback(item, fallback);
  const cost = sourceCatalogCost(exportItem);
  const pricedItem = { ...exportItem, cost, sourceCost: cost };
  const variant = systemProductVariants(pricedItem, db)[0] || {};
  const websitePrice = shopifyVariantWebsitePrice(pricedItem, variant, SHOPIFY_PRICE_MARKUP_PERCENT, db);
  return {
    ...pricedItem,
    price: websitePrice || pricedItem.price,
    websitePrice: websitePrice || pricedItem.websitePrice,
    sellUnitCost: shopifyVariantPriceBasis(pricedItem, variant, db)
  };
}

function mappedProductsCsvRowCount(db, template, items = []) {
  if (!isShopifyTemplate(template)) return items.length;
  return items.reduce((sum, item) => sum + shopifyPurchaseVariants(item, db).length, 0);
}

async function mappedProductsCsvAsync(db, template, items, options = {}) {
  const mappings = exportMappingsForTemplate(template);
  const headers = mappings.map((mapping) => mapping.externalColumn);
  const templateSource = exportValueTemplateSource(template);
  const lines = [headers.map(escapeCsv).join(",")];
  const total = items.length;
  const batchSize = Number(options.batchSize || 500) || 500;
  const progress = typeof options.progress === "function" ? options.progress : () => {};
  const isCanceled = typeof options.isCanceled === "function" ? options.isCanceled : () => false;
  const shopifyStatusMap = isShopifyTemplate(template) ? (options.shopifyStatusMap || readShopifyStatusMapSync()) : {};
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const shopifySourceFallbackMap = isShopifyTemplate(template) ? await sourceCatalogExportFallbackMap(items) : null;
  for (let index = 0; index < total; index += 1) {
    if (isCanceled()) throw new Error("Job was canceled.");
    const sourceItem = isShopifyTemplate(template) ? withShopifyStatus(sourceEnrichedItem(items[index], sourceEnrichmentMap), shopifyStatusMap, db) : sourceEnrichedItem(items[index], sourceEnrichmentMap);
    const item = isShopifyTemplate(template) ? shopifyPricedExportItem(sourceItem, shopifySourceFallbackMap, db) : sourceItem;
    if (isShopifyTemplate(template)) productExportCache(db, item);
    const exportItems = isShopifyTemplate(template)
      ? shopifyPurchaseVariants(item, db).map((variant, variantIndex) => ({ ...item, __shopifyVariant: variant, __shopifyVariantRow: variantIndex + 1 }))
      : [item];
    for (const exportItem of exportItems) {
      const row = mappings.map((mapping) => {
        const value = productFieldValue(db, exportItem, mapping.productField, { ...mapping, templateSource, templateId: template.id });
        const formatted = formatMappedExportValue(value, mapping, exportItem);
        return formatted === "" || formatted === undefined || formatted === null ? mapping.defaultValue || "" : formatted;
      });
      lines.push(row.map(escapeCsv).join(","));
    }
    const processed = index + 1;
    if (processed === total || processed % batchSize === 0) {
      progress({ processedRows: processed, totalRows: total, phase: "building_csv" });
      await new Promise((resolve) => setImmediate(resolve));
    }
  }
  return lines.join("\n");
}

function writeStreamText(stream, text) {
  return new Promise((resolve, reject) => {
    stream.write(text, "utf8", (error) => error ? reject(error) : resolve());
  });
}

function endWriteStream(stream) {
  return new Promise((resolve, reject) => {
    stream.end((error) => error ? reject(error) : resolve());
  });
}

async function mappedProductsCsvFileAsync(db, template, items, filePath, options = {}) {
  const mappings = exportMappingsForTemplate(template);
  const headers = mappings.map((mapping) => mapping.externalColumn);
  const templateSource = exportValueTemplateSource(template);
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  const stream = fs.createWriteStream(filePath, { encoding: "utf8" });
  const total = items.length;
  const batchSize = Number(options.batchSize || 250) || 250;
  const progress = typeof options.progress === "function" ? options.progress : () => {};
  const isCanceled = typeof options.isCanceled === "function" ? options.isCanceled : () => false;
  const shopifyStatusMap = isShopifyTemplate(template) ? (options.shopifyStatusMap || readShopifyStatusMapSync()) : {};
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const shopifySourceFallbackMap = isShopifyTemplate(template) ? await sourceCatalogExportFallbackMap(items) : null;
  let outputRows = 0;
  const lineBuffer = [];
  const flushLineBuffer = async () => {
    if (!lineBuffer.length) return;
    await writeStreamText(stream, lineBuffer.join(""));
    lineBuffer.length = 0;
  };
  try {
    await writeStreamText(stream, `${headers.map(escapeCsv).join(",")}\n`);
    for (let index = 0; index < total; index += 1) {
      if (isCanceled()) throw new Error("Job was canceled.");
      const sourceItem = isShopifyTemplate(template) ? withShopifyStatus(sourceEnrichedItem(items[index], sourceEnrichmentMap), shopifyStatusMap, db) : sourceEnrichedItem(items[index], sourceEnrichmentMap);
      const item = isShopifyTemplate(template) ? shopifyPricedExportItem(sourceItem, shopifySourceFallbackMap, db) : sourceItem;
      if (isShopifyTemplate(template)) productExportCache(db, item);
      const exportItems = isShopifyTemplate(template)
        ? shopifyPurchaseVariants(item, db).map((variant, variantIndex) => ({ ...item, __shopifyVariant: variant, __shopifyVariantRow: variantIndex + 1 }))
        : [item];
      for (const exportItem of exportItems) {
        const row = mappings.map((mapping) => {
          const value = productFieldValue(db, exportItem, mapping.productField, { ...mapping, templateSource, templateId: template.id });
          const formatted = formatMappedExportValue(value, mapping, exportItem);
          return formatted === "" || formatted === undefined || formatted === null ? mapping.defaultValue || "" : formatted;
        });
        lineBuffer.push(`${row.map(escapeCsv).join(",")}\n`);
        outputRows += 1;
        if (lineBuffer.length >= 1000) await flushLineBuffer();
      }
      const processed = index + 1;
      if (processed === total || processed % batchSize === 0) {
        await flushLineBuffer();
        progress({ processedRows: processed, totalRows: total, phase: "building_csv" });
        await new Promise((resolve) => setImmediate(resolve));
      }
    }
    await flushLineBuffer();
    await endWriteStream(stream);
    return { filePath, outputRows };
  } catch (error) {
    stream.destroy();
    try {
      if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
    } catch {
      // Best-effort cleanup only.
    }
    throw error;
  }
}

async function mappedProductsCsvPostgresFileAsync(db, template, filePath, options = {}) {
  const mappings = exportMappingsForTemplate(template);
  const headers = mappings.map((mapping) => mapping.externalColumn);
  const templateSource = exportValueTemplateSource(template);
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  const stream = fs.createWriteStream(filePath, { encoding: "utf8" });
  const shopifyTemplate = isShopifyTemplate(template);
  const batchSize = Math.max(50, Math.min(2000, Number(options.batchSize || (shopifyTemplate ? 250 : 500))));
  const yieldEvery = Math.max(1, Math.min(batchSize, Number(options.yieldEvery || (shopifyTemplate ? 1 : 100))));
  const progress = typeof options.progress === "function" ? options.progress : () => {};
  const isCanceled = typeof options.isCanceled === "function" ? options.isCanceled : () => false;
  const shopifyStatusMap = shopifyTemplate ? (options.shopifyStatusMap || readShopifyStatusMapSync()) : {};
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const filters = options.filters || {};
  const query = options.query || "";
  const selectedSkus = Array.isArray(options.skus) ? [...new Set(options.skus.map((sku) => String(sku || "").trim()).filter(Boolean))] : [];
  const totalProducts = selectedSkus.length || await postgres.countProducts({ q: query, filters });
  let processedProducts = 0;
  let outputRows = 0;
  const lineBuffer = [];
  const flushLineBuffer = async () => {
    if (!lineBuffer.length) return;
    await writeStreamText(stream, lineBuffer.join(""));
    lineBuffer.length = 0;
  };
  const checkpoint = async (phaseTotal = totalProducts) => {
    await flushLineBuffer();
    progress({ processedRows: processedProducts, totalRows: phaseTotal || totalProducts, phase: "building_csv" });
    await new Promise((resolve) => setImmediate(resolve));
    if (isCanceled()) throw new Error("Job was canceled.");
  };
  const writeProduct = async (sourceItem, sourceFallbackMap = null) => {
    const enrichedItem = shopifyTemplate
      ? withShopifyStatus(sourceEnrichedItem(sourceItem, sourceEnrichmentMap), shopifyStatusMap, db)
      : sourceEnrichedItem(sourceItem, sourceEnrichmentMap);
    const item = shopifyTemplate ? shopifyPricedExportItem(enrichedItem, sourceFallbackMap, db) : enrichedItem;
    if (shopifyTemplate && !options.includeBlockedShopifyProducts && productBlockedFromShopifyWebsite(item)) return;
    if (shopifyTemplate) productExportCache(db, item);
    const exportItems = shopifyTemplate
      ? shopifyPurchaseVariants(item, db).map((variant, variantIndex) => ({ ...item, __shopifyVariant: variant, __shopifyVariantRow: variantIndex + 1 }))
      : [item];
    for (const exportItem of exportItems) {
      const row = mappings.map((mapping) => {
        const value = productFieldValue(db, exportItem, mapping.productField, { ...mapping, templateSource, templateId: template.id });
        const formatted = formatMappedExportValue(value, mapping, exportItem);
        return formatted === "" || formatted === undefined || formatted === null ? mapping.defaultValue || "" : formatted;
      });
      lineBuffer.push(`${row.map(escapeCsv).join(",")}\n`);
      outputRows += 1;
      if (lineBuffer.length >= 1000) await flushLineBuffer();
      if (shopifyTemplate && exportItems.length > 1) {
        await new Promise((resolve) => setImmediate(resolve));
        if (isCanceled()) throw new Error("Job was canceled.");
      }
    }
  };
  try {
    await writeStreamText(stream, `${headers.map(escapeCsv).join(",")}\n`);
    if (selectedSkus.length) {
      const selectedFallbackMap = shopifyTemplate ? await sourceCatalogExportFallbackMap(selectedSkus.map((sku) => ({ sku }))) : null;
      for (const sku of selectedSkus) {
        if (isCanceled()) throw new Error("Job was canceled.");
        const item = await postgres.readProductByKey(sku);
        if (!item) continue;
        await writeProduct(item, selectedFallbackMap);
        processedProducts += 1;
        if (processedProducts % yieldEvery === 0) await checkpoint(totalProducts);
        if (processedProducts === totalProducts || processedProducts % batchSize === 0) {
          await checkpoint(totalProducts);
        }
      }
    } else {
      for (let page = 1; processedProducts < totalProducts || page === 1; page += 1) {
        if (isCanceled()) throw new Error("Job was canceled.");
        const result = await postgres.listProducts({ q: query, filters, page, limit: batchSize });
        const items = result?.items || result?.inventory || [];
        if (!items.length) break;
        const pageFallbackMap = shopifyTemplate ? await sourceCatalogExportFallbackMap(items) : null;
        for (const item of items) {
          if (isCanceled()) throw new Error("Job was canceled.");
          await writeProduct(item, pageFallbackMap);
          processedProducts += 1;
          if (processedProducts % yieldEvery === 0) await checkpoint(result.total || totalProducts);
        }
        await checkpoint(result.total || totalProducts);
        if (processedProducts >= Number(result.total || totalProducts || 0)) break;
      }
    }
    await flushLineBuffer();
    await endWriteStream(stream);
    return { filePath, outputRows, productCount: processedProducts, totalProducts };
  } catch (error) {
    stream.destroy();
    try {
      if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
    } catch {
      // Best-effort cleanup only.
    }
    throw error;
  }
}

async function mappedSourceCatalogCsvPostgresFileAsync(db, template, filePath, options = {}) {
  const mappings = exportMappingsForTemplate(template);
  const headers = mappings.map((mapping) => mapping.externalColumn);
  const templateSource = exportValueTemplateSource(template);
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  const stream = fs.createWriteStream(filePath, { encoding: "utf8" });
  const batchSize = Math.max(100, Math.min(500, Number(options.batchSize || 500)));
  const maxItems = Math.max(1, Math.min(25000, Number(options.limit || 10000)));
  const progress = typeof options.progress === "function" ? options.progress : () => {};
  const isCanceled = typeof options.isCanceled === "function" ? options.isCanceled : () => false;
  const filters = options.filters || {};
  const query = options.query || "";
  const shopifyStatusMap = isShopifyTemplate(template) ? (options.shopifyStatusMap || readShopifyStatusMapSync()) : {};
  const sourceEnrichmentMap = options.sourceEnrichmentMap || readProductSourceEnrichmentSync();
  const overrides = sourceCatalogOverrideMap(db);
  const vendorMappings = vendorCategoryMappingMap(db);
  const productsBySku = inventoryBySkuMap(db);
  let processedProducts = 0;
  let outputRows = 0;
  let matched = 0;
  let totalTarget = maxItems;
  let limited = false;
  const lineBuffer = [];
  const flushLineBuffer = async () => {
    if (!lineBuffer.length) return;
    await writeStreamText(stream, lineBuffer.join(""));
    lineBuffer.length = 0;
  };
  const writeProduct = async (sourceItem) => {
    const decorated = decorateSourceCatalogProduct(normalizeCatalogProductForInventory(sourceItem), overrides, productsBySku, vendorMappings);
    if (!decorated || decorated.sourceCatalogDeleted) return;
    const sourceProduct = catalogSummary(decorated);
    const enrichedItem = isShopifyTemplate(template)
      ? withShopifyStatus(sourceEnrichedItem(sourceProduct, sourceEnrichmentMap), shopifyStatusMap, db)
      : sourceEnrichedItem(sourceProduct, sourceEnrichmentMap);
    const item = isShopifyTemplate(template) ? shopifyPricedExportItem(enrichedItem, null, db) : enrichedItem;
    if (isShopifyTemplate(template)) productExportCache(db, item);
    const exportItems = isShopifyTemplate(template)
      ? shopifyPurchaseVariants(item, db).map((variant, variantIndex) => ({ ...item, __shopifyVariant: variant, __shopifyVariantRow: variantIndex + 1 }))
      : [item];
    for (const exportItem of exportItems) {
      const row = mappings.map((mapping) => {
        const value = productFieldValue(db, exportItem, mapping.productField, { ...mapping, templateSource, templateId: template.id });
        const formatted = formatMappedExportValue(value, mapping, exportItem);
        return formatted === "" || formatted === undefined || formatted === null ? mapping.defaultValue || "" : formatted;
      });
      lineBuffer.push(`${row.map(escapeCsv).join(",")}\n`);
      outputRows += 1;
      if (lineBuffer.length >= 1000) await flushLineBuffer();
    }
  };
  try {
    await writeStreamText(stream, `${headers.map(escapeCsv).join(",")}\n`);
    for (let page = 1; processedProducts < maxItems; page += 1) {
      if (isCanceled()) throw new Error("Job was canceled.");
      const result = await postgres.listVendorCatalogItems({ query, filters: catalogFiltersWithIndexedSupplierKeys(filters), page, limit: Math.min(batchSize, maxItems - processedProducts) });
      const items = result?.items || [];
      if (page === 1) {
        matched = Number(result?.total || 0);
        totalTarget = Math.min(maxItems, matched || maxItems);
        limited = matched > maxItems;
      }
      if (!items.length) break;
      for (const item of items) {
        if (isCanceled()) throw new Error("Job was canceled.");
        await writeProduct(item);
        processedProducts += 1;
        if (processedProducts >= maxItems) break;
      }
      await flushLineBuffer();
      progress({ processedRows: processedProducts, totalRows: totalTarget, phase: "building_csv" });
      await new Promise((resolve) => setImmediate(resolve));
      if (items.length < batchSize || processedProducts >= totalTarget) break;
    }
    await flushLineBuffer();
    await endWriteStream(stream);
    return { filePath, outputRows, productCount: processedProducts, matched, limited };
  } catch (error) {
    stream.destroy();
    try {
      if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
    } catch {
      // Best-effort cleanup only.
    }
    throw error;
  }
}

function exportFilenameDateStamp(date = new Date()) {
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  const year = String(date.getFullYear()).slice(-2);
  return `${month}-${day}-${year}`;
}

function exportFilenameStem(value, fallback = "product-export") {
  const base = path.basename(String(value || fallback));
  const withoutExtension = base.replace(/\.[^.\\/]+$/g, "");
  return String(withoutExtension || fallback).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || fallback;
}

function mappedExportFilename(template, dataFileName = "") {
  const templateStem = exportFilenameStem(template?.name || "product-export", "product-export");
  const dataStem = exportFilenameStem(dataFileName || template?.source || "products", "products");
  const nameStem = templateStem.endsWith(`-${dataStem}`) || templateStem === dataStem
    ? templateStem
    : `${templateStem}-${dataStem}`;
  return `${nameStem}-${exportFilenameDateStamp()}.csv`;
}

function csvValue(record, names = []) {
  for (const name of names) {
    if (record[name] !== undefined) return String(record[name] ?? "").trim();
  }
  const normalized = Object.fromEntries(Object.entries(record || {}).map(([key, value]) => [key.trim().toLowerCase(), value]));
  for (const name of names) {
    const value = normalized[String(name).trim().toLowerCase()];
    if (value !== undefined) return String(value ?? "").trim();
  }
  return "";
}

function normalizedHandle(value) {
  return String(value || "").trim().toLowerCase();
}

function normalizeShopifyStatus(value) {
  const text = String(value || "").trim().toLowerCase();
  if (["active", "published"].includes(text)) return "Active";
  if (["archived", "archive"].includes(text)) return "Archived";
  if (["draft", "unpublished", ""].includes(text)) return "Draft";
  return String(value || "").trim();
}

function normalizeShopifyPublished(value, status = "") {
  const text = String(value || "").trim().toLowerCase();
  if (["true", "1", "yes", "y"].includes(text)) return true;
  if (["false", "0", "no", "n"].includes(text)) return false;
  return normalizeShopifyStatus(status) === "Active";
}

function buildShopifyLookupMaps(db) {
  const bySku = new Map();
  const byProductId = new Map();
  for (const item of db.inventory || []) {
    if (item.sku) bySku.set(String(item.sku).trim().toLowerCase(), item);
    if (item.shopifyId) {
      byProductId.set(String(item.shopifyId).trim(), item);
      byProductId.set(normalizeShopifyProductGid(item.shopifyId), item);
      const legacyId = shopifyLegacyId(item.shopifyId);
      if (legacyId) byProductId.set(legacyId, item);
    }
  }
  return { bySku, byProductId };
}

function shopifyStatusPayloadFromRecord(record) {
  const status = normalizeShopifyStatus(csvValue(record, ["Status"]));
  const productId = csvValue(record, ["ID", "Product ID"]);
  return {
    sku: csvValue(record, ["Variant SKU", "Variant: SKU", "SKU"]),
    handle: csvValue(record, ["Handle"]),
    shopifyId: normalizeShopifyProductGid(productId),
    shopifyVariantId: normalizeShopifyVariantGid(csvValue(record, ["Variant ID", "Variant: ID"])),
    shopifyHandle: csvValue(record, ["Handle"]),
    shopifyStatus: status,
    shopifyPublished: normalizeShopifyPublished(csvValue(record, ["Published"]), status),
    shopifyPublishedAt: csvValue(record, ["Published At", "Published: At"]),
    shopifyUpdatedAt: csvValue(record, ["Updated At", "Updated: At"]),
    shopifySyncedAt: new Date().toISOString(),
    shopifySyncSource: "manual_upload"
  };
}

function shopifyStatusTemplateRows() {
  return [{
    "Variant SKU": "BUS192408TRV",
    "Handle": "lam-woven-pp-shop-bag",
    "ID": "gid://shopify/Product/1234567890",
    "Variant ID": "gid://shopify/ProductVariant/9876543210",
    "Status": "ACTIVE",
    "Published": "TRUE",
    "Published At": "2026-05-15T12:00:00-04:00",
    "Updated At": "2026-05-15T12:15:00-04:00"
  }];
}

function findProductForShopifyRecord(record, maps) {
  const payload = shopifyStatusPayloadFromRecord(record);
  const skuKey = String(payload.sku || "").trim().toLowerCase();
  if (skuKey && maps.bySku.has(skuKey)) return { item: maps.bySku.get(skuKey), payload, matchBy: "Variant SKU" };
  if (skuKey) return { item: null, payload, matchBy: "Variant SKU" };
  if (payload.shopifyId && maps.byProductId.has(payload.shopifyId)) return { item: maps.byProductId.get(payload.shopifyId), payload, matchBy: "Shopify ID" };
  const legacyId = shopifyLegacyId(payload.shopifyId);
  if (legacyId && maps.byProductId.has(legacyId)) return { item: maps.byProductId.get(legacyId), payload, matchBy: "Shopify ID" };
  return { item: null, payload, matchBy: "" };
}
function normalizeCategorySettings(settings = []) {
  return (Array.isArray(settings) ? settings : []).map((category) => {
    const name = formatCategoryName(category.name || "Uncategorized");
    return {
      id: category.id || crypto.randomUUID(),
      categoryId: category.categoryId || category.id || "",
      name,
      status: category.status || "needs_review",
      owner: category.owner || "",
      notes: category.notes || "",
      mappings: {
        shopify: normalizeChannelCategoryMapping(category.mappings?.shopify),
        temu: normalizeChannelCategoryMapping(category.mappings?.temu),
        tiktok: normalizeChannelCategoryMapping(category.mappings?.tiktok),
        ebay: normalizeChannelCategoryMapping(category.mappings?.ebay),
        whatnot: normalizeChannelCategoryMapping(category.mappings?.whatnot)
      },
      smartCollection: normalizeSmartCollectionProfile(category.smartCollection || category.shopifyCollection || {}, name),
      defaults: {
        condition: category.defaults?.condition || "New",
        countryOfOrigin: category.defaults?.countryOfOrigin || "",
        hazardousAllowed: Boolean(category.defaults?.hazardousAllowed),
        packageWeightRequired: category.defaults?.packageWeightRequired !== false,
        shippingProfile: category.defaults?.shippingProfile || "",
        returnPolicy: category.defaults?.returnPolicy || ""
      },
      requiredAttributes: Array.isArray(category.requiredAttributes) ? category.requiredAttributes : [],
      createdBy: category.createdBy || "",
      updatedBy: category.updatedBy || category.createdBy || "",
      createdSource: category.createdSource || category.source || "",
      updatedAt: category.updatedAt || category.createdAt || new Date().toISOString(),
      createdAt: category.createdAt || new Date().toISOString()
    };
  });
}

function categoryIdentity(value, scope = "source") {
  const name = formatCategoryName(value || "Uncategorized") || "Uncategorized";
  const hash = crypto.createHash("sha1").update(name.toLowerCase()).digest("hex").slice(0, 16);
  return { id: `${scope}-${hash}`, name };
}

function normalizeChannelCategoryMapping(mapping = {}) {
  const attributeMappings = Array.isArray(mapping.attributeMappings) ? mapping.attributeMappings.map((row) => ({
    id: row.id || crypto.randomUUID(),
    attributeId: row.attributeId || row.attributeName || row.attributeHandle || "",
    attributeName: row.attributeName || row.attributeId || row.attributeHandle || "",
    attributeHandle: row.attributeHandle || "",
    sourceField: row.sourceField || "",
    fallbackValue: row.fallbackValue || "",
    transform: row.transform || "",
    required: Boolean(row.required),
    recommended: Boolean(row.recommended),
    enabled: row.enabled !== false,
    notes: row.notes || ""
  })).filter((row) => row.attributeId || row.attributeName || row.attributeHandle) : [];
  return {
    categoryId: mapping.categoryId || "",
    categoryPath: mapping.categoryPath || "",
    categoryHandle: mapping.categoryHandle || "",
    collectionHandle: mapping.collectionHandle || "",
    taxonomyVersion: mapping.taxonomyVersion || "",
    googleCategory: mapping.googleCategory && typeof mapping.googleCategory === "object" ? {
      id: mapping.googleCategory.id || "",
      fullName: mapping.googleCategory.fullName || mapping.googleCategory.breadcrumb || "",
      breadcrumb: mapping.googleCategory.breadcrumb || mapping.googleCategory.fullName || "",
      taxonomy: mapping.googleCategory.taxonomy || ""
    } : null,
    attributes: Array.isArray(mapping.attributes) ? mapping.attributes.map((attribute) => ({
      id: attribute.id || "",
      name: attribute.name || "",
      handle: attribute.handle || "",
      description: attribute.description || "",
      extended: Boolean(attribute.extended),
      required: Boolean(attribute.required),
      recommended: Boolean(attribute.recommended),
      usage: attribute.usage || "",
      valueMode: attribute.valueMode || "",
      values: Array.isArray(attribute.values) ? attribute.values.slice(0, 20).map((value) => String(value || "").trim()).filter(Boolean) : []
    })).filter((attribute) => attribute.id || attribute.name) : [],
    attributeMappings,
    status: mapping.status || (mapping.categoryId || mapping.categoryPath ? "mapped" : "missing"),
    notes: mapping.notes || ""
  };
}

function attributeMappingStoreKey(categoryName = "", channel = "", mapping = {}) {
  const categoryKey = formatCategoryName(categoryName).toLowerCase();
  const channelKey = String(channel || "").trim().toLowerCase();
  const attributeKey = [mapping.attributeId, mapping.attributeName, mapping.attributeHandle]
    .map((value) => String(value || "").trim().toLowerCase())
    .find(Boolean);
  return categoryKey && channelKey && attributeKey ? `${categoryKey}::${channelKey}::${attributeKey}` : "";
}

function normalizeAttributeMappingStore(rows = []) {
  const source = Array.isArray(rows) ? rows : Object.values(rows || {});
  const result = {};
  for (const row of source) {
    const mapping = normalizeChannelCategoryMapping({ attributeMappings: [row] }).attributeMappings[0];
    const categoryName = formatCategoryName(row.categoryName || row.mainCategory || row["Main Category"] || "");
    const channel = String(row.channel || row.marketplace || row.Marketplace || "").trim().toLowerCase();
    const key = attributeMappingStoreKey(categoryName, channel, mapping);
    if (!key) continue;
    result[key] = {
      ...mapping,
      categoryName,
      channel,
      updatedAt: row.updatedAt || new Date().toISOString(),
      createdAt: row.createdAt || row.updatedAt || new Date().toISOString()
    };
  }
  return result;
}

function readAttributeMappingStore() {
  if (!fs.existsSync(ATTRIBUTE_MAPPINGS_FILE)) return {};
  try {
    return normalizeAttributeMappingStore(JSON.parse(fs.readFileSync(ATTRIBUTE_MAPPINGS_FILE, "utf8")));
  } catch {
    return {};
  }
}

function writeAttributeMappingStore(store = {}) {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  const normalized = normalizeAttributeMappingStore(store);
  fs.writeFileSync(ATTRIBUTE_MAPPINGS_FILE, JSON.stringify(Object.values(normalized), null, 2));
  return normalized;
}

const DEFAULT_ATTRIBUTE_GROUPS = [
  { id: "color", label: "Color", aliases: ["color", "colors", "colour", "colours", "finish color", "product color"] },
  { id: "dimensions", label: "Dimensions", aliases: ["dim", "dims", "dimension", "dimensions", "length", "width", "height", "depth"] },
  { id: "weight", label: "Weight", aliases: ["weight", "weights", "mass", "wt", "lbs", "pounds"] },
  { id: "features", label: "Features / functionality", aliases: ["function", "functions", "feature", "features", "functionality", "functionalities", "functional", "air fryer functions"] },
  { id: "material", label: "Material", aliases: ["material", "materials", "primary material"] },
  { id: "size", label: "Size", aliases: ["size", "product size", "item size"] },
  { id: "brand", label: "Brand", aliases: ["brand", "brand name"] },
  { id: "model", label: "Model", aliases: ["model", "model number"] },
  { id: "mpn", label: "MPN", aliases: ["mpn", "manufacturer part number", "part number"] },
  { id: "barcode", label: "Barcode", aliases: ["upc", "ean", "gtin", "barcode"] },
  { id: "capacity", label: "Capacity / volume", aliases: ["capacity", "volume"] },
  { id: "electrical", label: "Electrical", aliases: ["watt", "watts", "wattage", "voltage", "amp", "amps", "power"] }
];

function attributeGroupToken(value = "") {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, "");
}

function normalizeAttributeGroup(row = {}) {
  const label = String(row.label || row.name || row.id || "").trim();
  const id = attributeGroupToken(row.id || label);
  const aliasSource = Array.isArray(row.aliases) ? row.aliases : String(row.aliases || "").split(/[\n,]/);
  const aliases = [...new Set([label, ...aliasSource].map((alias) => String(alias || "").trim()).filter(Boolean))];
  return id && label ? {
    id,
    label,
    aliases,
    updatedAt: row.updatedAt || new Date().toISOString(),
    createdAt: row.createdAt || row.updatedAt || new Date().toISOString()
  } : null;
}

function normalizeAttributeGroups(rows = []) {
  const merged = new Map();
  for (const row of DEFAULT_ATTRIBUTE_GROUPS) {
    const group = normalizeAttributeGroup(row);
    if (group) merged.set(group.id, group);
  }
  for (const row of Array.isArray(rows) ? rows : []) {
    const group = normalizeAttributeGroup(row);
    if (!group) continue;
    const existing = merged.get(group.id);
    merged.set(group.id, existing ? { ...existing, ...group, aliases: [...new Set([...(existing.aliases || []), ...(group.aliases || [])])] } : group);
  }
  return [...merged.values()].sort((a, b) => a.label.localeCompare(b.label));
}

function readAttributeGroups() {
  if (!fs.existsSync(ATTRIBUTE_GROUPS_FILE)) return normalizeAttributeGroups();
  try {
    return normalizeAttributeGroups(JSON.parse(fs.readFileSync(ATTRIBUTE_GROUPS_FILE, "utf8")));
  } catch {
    return normalizeAttributeGroups();
  }
}

function writeAttributeGroups(groups = []) {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  const normalized = normalizeAttributeGroups(groups);
  fs.writeFileSync(ATTRIBUTE_GROUPS_FILE, JSON.stringify(normalized, null, 2));
  return normalized;
}

function attributeSemanticKey(value = "") {
  const key = attributeGroupToken(value);
  if (!key) return "";
  for (const group of readAttributeGroups()) {
    const aliases = Array.isArray(group.aliases) ? group.aliases : [];
    if (aliases.some((alias) => attributeGroupToken(alias) === key)) return group.id;
  }
  if (/(length|width|height|depth|dimension|dimensions)/.test(key)) return "dimensions";
  if (/(weight|weights|mass)/.test(key)) return "weight";
  if (/(capacity|volume)/.test(key)) return "capacity";
  if (/(watt|voltage|amp|power)/.test(key)) return "electrical";
  return key;
}

function attributeIdentitySemanticKey(row = {}) {
  for (const value of [row.attributeName, row.attributeHandle, row.attributeId, row.Attribute, row["Attribute Handle"], row["Attribute ID"]]) {
    const key = attributeSemanticKey(value);
    if (key) return key;
  }
  return "";
}

function scheduleAttributeMappingPropagationJob(seed = {}) {
  setTimeout(async () => {
    let db;
    let job;
    try {
      db = normalizeDb(await readDbFast({ skipInventory: postgres.isPostgresEnabled() }));
      job = createImportJob(db, {
        id: seed.jobId,
        section: "Categories",
        operation: "Attribute mapping propagation",
        direction: "mapping",
        status: "running",
        fileName: seed.mainCategory || seed.channel || "attribute-mapping",
        message: `Applying ${seed.channel || "marketplace"} attribute mapping rules in the background.`,
        details: `${seed.mainCategory || ""} | ${seed.attributeName || ""}`.trim()
      });
      if (postgres.isPostgresEnabled()) upsertImportJobStore(job);
      else await writeDb(db);
      const mainCategory = formatCategoryName(seed.mainCategory || "").toLowerCase();
      const categories = Array.isArray(seed.categories) ? seed.categories.map((name) => formatCategoryName(name).toLowerCase()).filter(Boolean) : [];
      const categorySet = new Set([mainCategory, ...categories].filter(Boolean));
      let affectedProducts = 0;
      if (postgres.isPostgresEnabled()) {
        for (const category of categorySet) {
          affectedProducts += await postgres.countProducts({ filters: { category } });
        }
      } else {
        affectedProducts = (db.inventory || []).filter((item) => {
          const itemCategory = formatCategoryName(item.category || item.mainCategory || "").toLowerCase();
          return categorySet.has(itemCategory);
        }).length;
      }
      finishImportJob(job, {
        status: "success",
        totalRows: Number(seed.mappingCount || 1),
        changed: Number(seed.mappingCount || 1),
        message: `Saved ${Number(seed.mappingCount || 1).toLocaleString()} attribute mapping rule${Number(seed.mappingCount || 1) === 1 ? "" : "s"}. ${affectedProducts.toLocaleString()} SKU${affectedProducts === 1 ? "" : "s"} will use them when marketplace output is generated.`,
        details: `${seed.channel || ""} | ${seed.mainCategory || ""} | ${categorySet.size} categor${categorySet.size === 1 ? "y" : "ies"} | ${affectedProducts} affected SKUs`
      });
      if (postgres.isPostgresEnabled()) upsertImportJobStore(job);
      else await writeDb(db);
    } catch (error) {
      try {
        db = db || normalizeDb(await readDbFast({ skipInventory: postgres.isPostgresEnabled() }));
        job = job || createImportJob(db, {
          id: seed.jobId,
          section: "Categories",
          operation: "Attribute mapping propagation",
          direction: "mapping",
          status: "running",
          fileName: seed.mainCategory || seed.channel || "attribute-mapping"
        });
        finishImportJob(job, { status: "failed", message: error.message, errors: [error.message], missingCount: 1 });
        if (postgres.isPostgresEnabled()) upsertImportJobStore(job);
        else await writeDb(db);
      } catch (writeError) {
        console.error("Unable to finish attribute mapping job", writeError);
      }
    }
  }, 0);
}

function applyStoredAttributeMappingsToCategory(category = {}) {
  const categoryName = formatCategoryName(category.name || category.category || "");
  if (!categoryName) return category;
  const store = readAttributeMappingStore();
  const next = { ...category, mappings: { ...(category.mappings || {}) } };
  for (const channel of ["shopify", "ebay", "temu", "tiktok", "whatnot"]) {
    const mapping = normalizeChannelCategoryMapping(next.mappings[channel] || {});
    const rows = Array.isArray(mapping.attributeMappings) ? mapping.attributeMappings.slice() : [];
    for (const stored of Object.values(store).filter((row) => row.channel === channel && formatCategoryName(row.categoryName).toLowerCase() === categoryName.toLowerCase())) {
      const key = attributeMappingStoreKey(categoryName, channel, stored);
      const index = rows.findIndex((row) => attributeMappingStoreKey(categoryName, channel, row) === key);
      if (index >= 0) rows[index] = { ...rows[index], ...stored };
      else rows.push(stored);
    }
    next.mappings[channel] = normalizeChannelCategoryMapping({ ...mapping, attributeMappings: rows });
  }
  return next;
}

function readCatalogCategoryIndex() {
  if (!fs.existsSync(CATALOG_CATEGORY_INDEX_FILE)) return { categories: [], categoryCount: 0, generatedAt: "" };
  try {
    return JSON.parse(fs.readFileSync(CATALOG_CATEGORY_INDEX_FILE, "utf8"));
  } catch {
    return { categories: [], categoryCount: 0, generatedAt: "" };
  }
}

function categorySettingsMap(db) {
  db.categorySettings = normalizeCategorySettings(db.categorySettings);
  const map = new Map();
  for (const category of db.categorySettings) {
    if (category.id) map.set(category.id, category);
    if (category.categoryId) map.set(category.categoryId, category);
    const nameKey = formatCategoryName(category.name || "").toLowerCase();
    if (nameKey) map.set(`name:${nameKey}`, category);
  }
  return map;
}

function readShopifyTaxonomyIndex() {
  if (!fs.existsSync(SHOPIFY_TAXONOMY_INDEX_FILE)) return { categories: [], categoryCount: 0, version: "", generatedAt: "" };
  try {
    return JSON.parse(fs.readFileSync(SHOPIFY_TAXONOMY_INDEX_FILE, "utf8"));
  } catch {
    return { categories: [], categoryCount: 0, version: "", generatedAt: "" };
  }
}

function compactShopifyCategory(category) {
  return {
    id: category.id || "",
    handle: category.handle || String(category.id || "").split("/").pop() || "",
    name: category.name || "",
    fullName: category.fullName || category.name || "",
    path: Array.isArray(category.path) ? category.path : String(category.fullName || category.name || "").split(" > ").filter(Boolean),
    level: Number(category.level || 0),
    vertical: category.vertical || "",
    attributeCount: Number(category.attributeCount || (category.attributes || []).length || 0),
    googleCategory: category.googleCategory || null,
    attributes: Array.isArray(category.attributes) ? category.attributes : []
  };
}

function searchShopifyTaxonomy(query = "", limit = 20) {
  const index = readShopifyTaxonomyIndex();
  const q = String(query || "").trim().toLowerCase();
  const tokens = q.split(/\s+/).filter(Boolean);
  const max = Math.max(1, Math.min(Number(limit || 20), 50));
  let rows = index.categories || [];
  if (tokens.length) {
    rows = rows.map((category) => {
      const haystack = String((category.fullName || "") + " " + (category.name || "") + " " + (category.id || "") + " " + (category.handle || "")).toLowerCase();
      if (!tokens.every((token) => haystack.includes(token))) return null;
      const exact = haystack === q ? 100 : 0;
      const leaf = String(category.name || "").toLowerCase().includes(q) ? 30 : 0;
      const path = String(category.fullName || "").toLowerCase().includes(q) ? 15 : 0;
      return { category, score: exact + leaf + path - Math.max(0, Number(category.level || 0) - 2) };
    }).filter(Boolean).sort((a, b) => b.score - a.score || a.category.fullName.localeCompare(b.category.fullName)).map((row) => row.category);
  }
  return {
    channel: "shopify",
    version: index.version || "",
    generatedAt: index.generatedAt || "",
    total: rows.length,
    categories: rows.slice(0, max).map(compactShopifyCategory)
  };
}

function shopifyTaxonomyMatchTokens(value = "") {
  const stop = new Set([
    "and", "or", "the", "for", "with", "without", "of", "to", "a", "an", "in", "on", "by",
    "other", "misc", "miscellaneous", "accessory", "accessories", "supplies", "products",
    "product", "equipment", "commercial", "general", "category", "categories"
  ]);
  const synonyms = {
    faucets: "faucet",
    sinks: "sink",
    bathrooms: "bathroom",
    cleaners: "cleaner",
    cleaning: "clean",
    mowers: "mower",
    tractors: "tractor",
    trimmers: "trimmer",
    edgers: "edger",
    blowers: "blower",
    fittings: "fitting",
    fasteners: "fastener",
    screws: "screw",
    nails: "nail",
    paints: "paint",
    primers: "primer",
    aerosols: "aerosol",
    brushes: "brush",
    hoses: "hose",
    valves: "valve",
    pipes: "pipe",
    tools: "tool",
    lights: "light",
    lamps: "lamp",
    batteries: "battery",
    knives: "knife",
    cards: "card"
  };
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .split(/\s+/)
    .map((token) => token.trim())
    .filter((token) => token.length > 2 && !stop.has(token))
    .map((token) => synonyms[token] || token.replace(/ies$/, "y").replace(/s$/, ""))
    .filter((token) => token.length > 2 && !stop.has(token));
}

function buildShopifyTaxonomyMatchIndex() {
  const index = readShopifyTaxonomyIndex();
  return {
    version: index.version || "",
    categories: (index.categories || []).map((category) => {
      const compact = compactShopifyCategory(category);
      const leafTokens = shopifyTaxonomyMatchTokens(compact.name);
      const pathTokens = shopifyTaxonomyMatchTokens(compact.fullName);
      return {
        category: compact,
        leafTokens,
        pathTokens,
        tokenSet: new Set([...leafTokens, ...pathTokens]),
        leafSet: new Set(leafTokens),
        pathText: String(compact.fullName || compact.name || "").toLowerCase()
      };
    }).filter((row) => row.category.id && row.category.fullName)
  };
}

function scoreShopifyTaxonomyMatch(sourceCategory = "", row = {}) {
  const sourceParts = String(sourceCategory || "").split(">").map((part) => part.trim()).filter(Boolean);
  const sourceLeaf = sourceParts[sourceParts.length - 1] || sourceCategory;
  const sourceTokens = shopifyTaxonomyMatchTokens(sourceCategory);
  const sourceLeafTokens = shopifyTaxonomyMatchTokens(sourceLeaf);
  if (!sourceTokens.length) return 0;
  const sourceSet = new Set(sourceTokens);
  const sourceLeafSet = new Set(sourceLeafTokens);
  let score = 0;
  for (const token of sourceSet) {
    if (row.leafSet?.has(token)) score += 8;
    else if (row.tokenSet?.has(token)) score += 3;
  }
  for (const token of sourceLeafSet) {
    if (row.leafSet?.has(token)) score += 10;
    else if (row.tokenSet?.has(token)) score += 4;
  }
  const sourceText = String(sourceCategory || "").toLowerCase();
  const leafText = String(sourceLeaf || "").toLowerCase();
  const targetPath = row.pathText || "";
  if (leafText && targetPath.includes(leafText.replace(/[^a-z0-9]+/g, " ").trim())) score += 16;
  if (/paint|primer|stain|aerosol|enamel/.test(sourceText) && /hardware|paint|decor/.test(targetPath)) score += 7;
  if (/plumb|pipe|faucet|sink|valve|fitting/.test(sourceText) && /hardware|plumbing|building materials|kitchen|bath/.test(targetPath)) score += 7;
  if (/lawn|garden|mower|trimmer|edger|blower|outdoor|tractor/.test(sourceText) && /lawn|garden|outdoor|hardware/.test(targetPath)) score += 7;
  if (/fastener|screw|nail|bolt|washer|anchor/.test(sourceText) && /hardware|fastener|building materials/.test(targetPath)) score += 7;
  if (/clean|janitorial|mold|mildew|chemical/.test(sourceText) && /clean|household|hardware/.test(targetPath)) score += 7;
  if (/food service|hospitality|kitchen|storage/.test(sourceText) && /kitchen|dining|food|business/.test(targetPath)) score += 6;
  if (/electrical|lighting|receptacle|switch|battery|wire/.test(sourceText) && /electrical|lighting|hardware/.test(targetPath)) score += 7;
  if (/automotive|vehicle|fleet/.test(sourceText) && /vehicle|automotive/.test(targetPath)) score += 8;
  if (/medical|lab|exercise|fitness|sport/.test(sourceText) && /sport|medical|health/.test(targetPath)) score += 6;
  if (/hardware|farm|plumb|fastener|lawn|garden|paint|electrical|clean/.test(sourceText) && /arts & entertainment|apparel|jewelry|media|software|religious|baby/.test(targetPath)) score -= 28;
  if (/\bcard\b/.test(sourceText) && !/credit|gift|greeting|memory|playing/.test(sourceText) && /\bcard\b/.test(targetPath)) score -= 14;
  score -= Math.max(0, Number(row.category.level || 0) - 4);
  return score;
}

function bestShopifyTaxonomyMatch(sourceCategory = "", matchIndex = buildShopifyTaxonomyMatchIndex()) {
  const sourceTokens = new Set(shopifyTaxonomyMatchTokens(sourceCategory));
  if (!sourceTokens.size) return null;
  let best = null;
  for (const row of matchIndex.categories || []) {
    let hasOverlap = false;
    for (const token of sourceTokens) {
      if (row.tokenSet.has(token)) {
        hasOverlap = true;
        break;
      }
    }
    if (!hasOverlap) continue;
    const score = scoreShopifyTaxonomyMatch(sourceCategory, row);
    if (!best || score > best.score || (score === best.score && row.category.level > best.level)) {
      best = { ...row.category, score };
    }
  }
  return best;
}

async function autoMapShopifyCategories(db, options = {}) {
  const scope = options.scope === "source" ? "source" : "main";
  const overwrite = Boolean(options.overwrite);
  const refreshSuggestions = Boolean(options.refreshSuggestions);
  const limit = Math.max(1, Math.min(Number(options.limit || 10000), 25000));
  const minScore = Math.max(1, Number(options.minScore || 12));
  const rows = publicCategories(db, "", scope).categories
    .filter((category) => {
      const mapping = category.mappings?.shopify || {};
      const autoSuggested = /auto-suggested closest shopify taxonomy/i.test(String(mapping.notes || ""));
      return overwrite || !(mapping.categoryId || mapping.categoryPath) || (refreshSuggestions && autoSuggested);
    })
    .sort((a, b) => Number(b.productCount || 0) - Number(a.productCount || 0) || a.name.localeCompare(b.name))
    .slice(0, limit);
  const matchIndex = buildShopifyTaxonomyMatchIndex();
  const results = [];
  let mapped = 0;
  let missing = 0;
  for (const row of rows) {
    const match = bestShopifyTaxonomyMatch(row.name, matchIndex);
    if (!match || Number(match.score || 0) < minScore) {
      missing += 1;
      results.push({ category: row.name, status: "missing", score: match?.score || 0, message: "No close Shopify taxonomy match found." });
      continue;
    }
    const setting = findOrCreateCategorySetting(db, row.name);
    setting.mappings.shopify = normalizeChannelCategoryMapping({
      ...setting.mappings.shopify,
      categoryId: match.id,
      categoryPath: match.fullName || match.name,
      categoryHandle: match.handle,
      taxonomyVersion: matchIndex.version,
      googleCategory: match.googleCategory,
      attributes: match.attributes,
      status: "needs_review",
      notes: `Auto-suggested closest Shopify taxonomy match from "${row.name}" with score ${Number(match.score || 0).toFixed(1)}. Review before pushing taxonomy to Shopify.`
    });
    setting.status = "needs_review";
    setting.updatedAt = new Date().toISOString();
    mapped += 1;
    results.push({ category: row.name, status: "needs_review", score: match.score, shopifyCategoryId: match.id, shopifyCategoryPath: match.fullName || match.name });
  }
  return { requested: rows.length, mapped, missing, results, scope, taxonomyVersion: matchIndex.version, minScore };
}

function enrichShopifyCategoryMapping(mapping = {}) {
  const next = { ...mapping };
  const shopifyIndex = readShopifyTaxonomyIndex();
  const lookup = String(next.categoryId || "").trim();
  const pathLookup = String(next.categoryPath || "").trim().toLowerCase();
  const shopifyCategory = (shopifyIndex.categories || []).find((row) => (
    (lookup && (row.id === lookup || row.handle === lookup || String(row.id || "").split("/").pop() === lookup)) ||
    (pathLookup && String(row.fullName || row.name || "").trim().toLowerCase() === pathLookup)
  ));
  if (!shopifyCategory) return next;
  const compact = compactShopifyCategory(shopifyCategory);
  return {
    ...next,
    categoryId: shopifyCategory.id,
    categoryPath: shopifyCategory.fullName,
    categoryHandle: shopifyCategory.handle,
    taxonomyVersion: shopifyIndex.version || "",
    googleCategory: compact.googleCategory,
    attributes: compact.attributes
  };
}

async function ebayDefaultCategoryTreeId(db, marketplaceId = "EBAY_US") {
  const data = await ebayRequest(db, `/commerce/taxonomy/v1/get_default_category_tree_id?marketplace_id=${encodeURIComponent(marketplaceId || "EBAY_US")}`, { tokenType: "app" });
  return String(data.categoryTreeId || "").trim();
}

function ebaySuggestionPath(suggestion = {}) {
  const ancestors = Array.isArray(suggestion.categoryTreeNodeAncestors) ? suggestion.categoryTreeNodeAncestors : [];
  const path = ancestors.slice().reverse().map((node) => node.categoryName).filter(Boolean);
  const leaf = suggestion.category?.categoryName;
  if (leaf) path.push(leaf);
  return path.filter((value, index, list) => list.indexOf(value) === index).join(" > ");
}

function compactEbayCategorySuggestion(suggestion = {}, treeId = "") {
  const category = suggestion.category || {};
  return {
    id: String(category.categoryId || "").trim(),
    categoryId: String(category.categoryId || "").trim(),
    name: category.categoryName || "",
    fullName: ebaySuggestionPath(suggestion),
    path: ebaySuggestionPath(suggestion).split(" > ").filter(Boolean),
    taxonomyVersion: treeId,
    source: "eBay"
  };
}

async function searchEbayTaxonomy(db, query = "", limit = 12, marketplaceId = "EBAY_US") {
  const q = String(query || "").trim();
  if (!q) return { channel: "ebay", marketplaceId, categoryTreeId: "", total: 0, categories: [] };
  const max = Math.max(1, Math.min(Number(limit || 12), 25));
  const categoryTreeId = await ebayDefaultCategoryTreeId(db, marketplaceId);
  if (!categoryTreeId) throw new Error("eBay category tree ID was not returned.");
  const data = await ebayRequest(db, `/commerce/taxonomy/v1/category_tree/${encodeURIComponent(categoryTreeId)}/get_category_suggestions?q=${encodeURIComponent(q)}`, { tokenType: "app" });
  const suggestions = Array.isArray(data.categorySuggestions) ? data.categorySuggestions : [];
  return {
    channel: "ebay",
    marketplaceId,
    categoryTreeId,
    total: suggestions.length,
    categories: suggestions.slice(0, max).map((suggestion) => compactEbayCategorySuggestion(suggestion, categoryTreeId)).filter((row) => row.categoryId)
  };
}

function compactEbayAspect(aspect = {}) {
  const constraint = aspect.aspectConstraint || {};
  const name = aspect.localizedAspectName || "";
  const usage = constraint.aspectUsage || "";
  return {
    id: name,
    name,
    handle: name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, ""),
    description: [
      constraint.aspectDataType,
      constraint.itemToAspectCardinality,
      constraint.aspectMode
    ].filter(Boolean).join(" / "),
    required: Boolean(constraint.aspectRequired),
    recommended: usage === "RECOMMENDED",
    usage,
    valueMode: constraint.aspectMode || "",
    values: Array.isArray(aspect.aspectValues) ? aspect.aspectValues.map((value) => value.localizedValue).filter(Boolean).slice(0, 20) : []
  };
}

async function ebayCategoryAspects(db, categoryId = "", options = {}) {
  const id = String(categoryId || "").trim();
  if (!id) return [];
  const marketplaceId = options.marketplaceId || ebayChannelSettings(db).ebayMarketplaceId || "EBAY_US";
  const categoryTreeId = options.categoryTreeId || await ebayDefaultCategoryTreeId(db, marketplaceId);
  if (!categoryTreeId) throw new Error("eBay category tree ID was not returned.");
  const data = await ebayRequest(db, `/commerce/taxonomy/v1/category_tree/${encodeURIComponent(categoryTreeId)}/get_item_aspects_for_category?category_id=${encodeURIComponent(id)}`, { tokenType: "app" });
  const aspects = Array.isArray(data.aspects) ? data.aspects : [];
  return aspects.map(compactEbayAspect).filter((aspect) => aspect.name);
}

async function enrichEbayCategoryMapping(db, mapping = {}) {
  const categoryId = String(mapping.categoryId || "").trim();
  if (!categoryId) return mapping;
  try {
    const attributes = await ebayCategoryAspects(db, categoryId, { categoryTreeId: mapping.taxonomyVersion || "" });
    return { ...mapping, attributes };
  } catch (error) {
    return {
      ...mapping,
      notes: [mapping.notes, `eBay aspects sync failed: ${error.message}`].filter(Boolean).join(" ")
    };
  }
}

function ebayCategorySearchQuery(categoryName = "") {
  const parts = String(categoryName || "").split(">").map((part) => part.trim()).filter(Boolean);
  return parts[parts.length - 1] || parts.join(" ") || String(categoryName || "").trim();
}

function ebayCategoryAutoSearchQuery(categoryName = "") {
  return String(categoryName || "")
    .replace(/[>&/]+/g, " ")
    .replace(/[,\-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function ebayCategoryTokens(value = "") {
  const stop = new Set(["and", "or", "the", "for", "with", "of", "to", "a", "an", "other", "accessories", "supplies"]);
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .split(/\s+/)
    .filter((token) => token.length > 2 && !stop.has(token));
}

function scoreEbayCategoryMatch(sourceCategory = "", suggestion = {}) {
  const sourceTokens = new Set(ebayCategoryTokens(sourceCategory));
  const targetTokens = ebayCategoryTokens(`${suggestion.name || ""} ${suggestion.fullName || ""}`);
  let score = 0;
  targetTokens.forEach((token) => {
    if (sourceTokens.has(token)) score += 3;
  });
  const source = String(sourceCategory || "").toLowerCase();
  const path = String(suggestion.fullName || suggestion.name || "").toLowerCase();
  if (/business|industrial|hardware|plumbing|metalworking|tools|food service|janitorial|maintenance/.test(source) && path.includes("business & industrial")) score += 4;
  if (/tools|hardware|fasteners|plumbing|metalworking/.test(source) && /tools|hardware|fasteners|plumbing|metalworking|building materials/.test(path)) score += 3;
  if (/food service|hospitality|restaurant/.test(source) && /restaurant|food service|commercial kitchen/.test(path)) score += 5;
  if (/janitorial|cleaning|maintenance/.test(source) && /cleaning|janitorial|maintenance/.test(path)) score += 5;
  if (/business|industrial|hardware|plumbing|metalworking|tools|food service|janitorial|maintenance/.test(source) && /art|crafts|collectibles|books|jewelry/.test(path)) score -= 6;
  return score;
}

function bestEbayCategoryMatch(sourceCategory = "", categories = []) {
  return categories
    .map((category, index) => ({ category, index, score: scoreEbayCategoryMatch(sourceCategory, category) }))
    .sort((a, b) => b.score - a.score || a.index - b.index)[0]?.category || categories[0] || null;
}

async function autoMapEbayCategories(db, options = {}) {
  const scope = options.scope === "source" ? "source" : "main";
  const overwrite = Boolean(options.overwrite);
  const limit = Math.max(1, Math.min(Number(options.limit || 50), 250));
  const marketplaceId = options.marketplaceId || ebayChannelSettings(db).ebayMarketplaceId || "EBAY_US";
  const rows = publicCategories(db, "", scope).categories
    .filter((category) => overwrite || !(category.mappings?.ebay?.categoryId))
    .sort((a, b) => Number(b.productCount || 0) - Number(a.productCount || 0))
    .slice(0, limit);
  const results = [];
  let mapped = 0;
  for (const row of rows) {
    const query = ebayCategoryAutoSearchQuery(row.name) || ebayCategorySearchQuery(row.name);
    try {
      const search = await searchEbayTaxonomy(db, query, 5, marketplaceId);
      const match = bestEbayCategoryMatch(row.name, search.categories);
      if (!match) {
        results.push({ category: row.name, query, status: "missing", message: "No eBay suggestion returned." });
        continue;
      }
      const setting = findOrCreateCategorySetting(db, row.name);
      const previousEbayMapping = setting.mappings?.ebay || {};
      setting.mappings.ebay = normalizeChannelCategoryMapping({
        ...setting.mappings.ebay,
        categoryId: match.categoryId,
        categoryPath: match.fullName || match.name,
        categoryHandle: match.name,
        taxonomyVersion: search.categoryTreeId,
        status: "needs_review",
        notes: `Auto-suggested from eBay taxonomy for "${query}". Review before publishing listings.`
      });
      if (setting.status !== "mapped" || /auto-mapped|auto-suggested/i.test(previousEbayMapping.notes || "")) setting.status = "needs_review";
      setting.updatedAt = new Date().toISOString();
      mapped += 1;
      results.push({ category: row.name, query, status: "needs_review", ebayCategoryId: match.categoryId, ebayCategoryPath: match.fullName || match.name });
    } catch (error) {
      results.push({ category: row.name, query, status: "error", message: error.message });
    }
  }
  return { requested: rows.length, mapped, results, scope, marketplaceId };
}

function findOrCreateCategorySetting(db, categoryName) {
  db.categorySettings = normalizeCategorySettings(db.categorySettings);
  const identity = categoryIdentity(categoryName, "main");
  let category = db.categorySettings.find((row) => (
    row.categoryId === identity.id ||
    row.id === identity.id ||
    formatCategoryName(row.name).toLowerCase() === identity.name.toLowerCase()
  ));
  if (!category) {
    category = normalizeCategorySettings([{ categoryId: identity.id, name: identity.name }])[0];
    db.categorySettings.push(category);
  }
  return category;
}

function categorySavedSettings(settings, category) {
  const saved = settings.get(category.id) || settings.get(category.categoryId) || settings.get(`name:${formatCategoryName(category.name || "").toLowerCase()}`) || {};
  return saved.name ? applyStoredAttributeMappingsToCategory(saved) : saved;
}

function categoryMappingSummary(category, saved) {
  const mappings = saved.mappings || {};
  const mappingCount = ["shopify", "temu", "tiktok", "ebay", "whatnot"].filter((key) => {
    const mapping = mappings[key] || {};
    return mapping.categoryId || mapping.categoryPath || mapping.collectionHandle;
  }).length;
  return {
    mappings,
    mappingCount,
    missingMappings: ["shopify", "temu", "tiktok", "ebay", "whatnot"].filter((key) => {
      const mapping = mappings[key] || {};
      return !(mapping.categoryId || mapping.categoryPath || mapping.collectionHandle);
    })
  };
}

function categorySourceMappingCount(vendorMappings = {}, categoryName = "") {
  const key = formatCategoryName(categoryName).toLowerCase();
  if (!key) return 0;
  return Object.values(normalizeVendorCategoryMappings(vendorMappings))
    .filter((mapping) => formatCategoryName(mapping.mainCategory).toLowerCase() === key)
    .length;
}

function categoryDeleteBlockers(category = {}) {
  const blockers = [];
  if (Number(category.productCount || 0) > 0) blockers.push(`${Number(category.productCount || 0).toLocaleString()} products use this category`);
  if (Number(category.sourceMappingCount || 0) > 0) blockers.push(`${Number(category.sourceMappingCount || 0).toLocaleString()} source categories map here`);
  return blockers;
}

function publicCategoryRow(category, settings, scope, context = {}) {
  const categoryName = formatCategoryName(category.name);
  const saved = categorySavedSettings(settings, { ...category, name: categoryName });
  const { mappings, mappingCount, missingMappings } = categoryMappingSummary(category, saved);
  const savedExists = Boolean(saved.name);
  const sourceMappingCount = Number(context.sourceMappingCounts?.get(categoryName.toLowerCase()) || category.sourceMappingCount || 0);
  const productCount = Number(category.productCount || 0);
  const lifecycle = !savedExists && productCount > 0 ? "new" : savedExists && productCount === 0 ? "outdated" : "current";
  const createdSource = saved.createdSource || category.createdSource || (scope === "main" && productCount > 0 ? "system:true-value" : "manual");
  const createdByLabel = createdSource === "system:true-value"
    ? "System - True Value"
    : (saved.createdBy || category.createdBy || "Manual");
  const blockers = categoryDeleteBlockers({ ...category, productCount, sourceMappingCount });
  return {
    ...category,
    scope,
    name: categoryName,
    topBrands: Array.isArray(category.topBrands) ? category.topBrands.map((brand) => ({ ...brand, name: formatBrandName(brand.name) })) : [],
    status: saved.status || (mappingCount ? "mapped" : "needs_review"),
    owner: saved.owner || "",
    notes: saved.notes || "",
    mappings: {
      shopify: normalizeChannelCategoryMapping(mappings.shopify),
      temu: normalizeChannelCategoryMapping(mappings.temu),
      tiktok: normalizeChannelCategoryMapping(mappings.tiktok),
      ebay: normalizeChannelCategoryMapping(mappings.ebay),
      whatnot: normalizeChannelCategoryMapping(mappings.whatnot)
    },
    smartCollection: normalizeSmartCollectionProfile(saved.smartCollection || saved.shopifyCollection || {}, categoryName),
    defaults: normalizeCategorySettings([{ ...saved, name: categoryName, categoryId: category.id }])[0].defaults,
    requiredAttributes: Array.isArray(saved.requiredAttributes) ? saved.requiredAttributes : [],
    savedExists,
    createdBy: saved.createdBy || category.createdBy || "",
    updatedBy: saved.updatedBy || category.updatedBy || "",
    createdSource,
    createdByLabel,
    createdAt: saved.createdAt || category.createdAt || "",
    updatedAt: saved.updatedAt || category.updatedAt || "",
    lifecycle,
    sourceMappingCount,
    canDelete: blockers.length === 0,
    deleteBlockers: blockers,
    mappingCount,
    missingMappings
  };
}

function aggregateMainCatalogCategories(db) {
  if (Array.isArray(db.__mainCategoryRows)) {
    const byCategory = new Map();
    for (const rawRow of db.__mainCategoryRows) {
      const name = formatCategoryName(rawRow.name || "Uncategorized") || "Uncategorized";
      const identity = categoryIdentity(name, "main");
      byCategory.set(name.toLowerCase(), {
        id: identity.id,
        categoryId: identity.id,
        name,
        productCount: Number(rawRow.productCount || 0),
        activeProductCount: Number(rawRow.activeProductCount || 0),
        stockProductCount: Number(rawRow.stockProductCount || 0),
        hazardousProductCount: Number(rawRow.hazardousProductCount || 0),
        topVendors: Array.isArray(rawRow.topVendors) ? rawRow.topVendors : [],
        topBrands: Array.isArray(rawRow.topBrands) ? rawRow.topBrands : []
      });
    }
    return [...byCategory.values()].sort((a, b) => b.productCount - a.productCount || a.name.localeCompare(b.name));
  }
  const byCategory = new Map();
  const systemSettings = readSystemSettingsStore(db.systemSettings || {});
  for (const item of db.inventory || []) {
    const promoted = applySourceCategoryMainPromotion(item, systemSettings);
    const name = promoted.categoryVerified ? (formatCategoryName(promoted.category || promoted.mainCategory || "Uncategorized") || "Uncategorized") : "Uncategorized";
    const key = name.toLowerCase();
    if (!byCategory.has(key)) {
      const identity = categoryIdentity(name, "main");
      byCategory.set(key, {
        id: identity.id,
        categoryId: identity.id,
        name,
        productCount: 0,
        activeProductCount: 0,
        stockProductCount: 0,
        hazardousProductCount: 0,
        _vendors: new Map(),
        _brands: new Map()
      });
    }
    const row = byCategory.get(key);
    row.productCount += 1;
    if (item.active !== false) row.activeProductCount += 1;
    if (Number(item.stockQty ?? item.qty ?? 0) > 0) row.stockProductCount += 1;
    if (item.hazardous) row.hazardousProductCount += 1;
    const vendor = sourceTextValue(item.supplier || item.vendor || "Unassigned");
    if (vendor) row._vendors.set(vendor, (row._vendors.get(vendor) || 0) + 1);
    const brand = formatBrandName(item.brand || "");
    if (brand) row._brands.set(brand, (row._brands.get(brand) || 0) + 1);
  }
  for (const setting of normalizeCategorySettings(db.categorySettings)) {
    const name = formatCategoryName(setting.name || "");
    if (!name) continue;
    const key = name.toLowerCase();
    if (!byCategory.has(key)) {
      const identity = categoryIdentity(name, "main");
      byCategory.set(key, {
        id: identity.id,
        categoryId: identity.id,
        name,
        productCount: 0,
        activeProductCount: 0,
        stockProductCount: 0,
        hazardousProductCount: 0,
        _vendors: new Map(),
        _brands: new Map()
      });
    }
  }
  return [...byCategory.values()].map((row) => {
    const topVendors = [...row._vendors.entries()].map(([name, count]) => ({ name, count })).sort((a, b) => b.count - a.count).slice(0, 12);
    const topBrands = [...row._brands.entries()].map(([name, count]) => ({ name, count })).sort((a, b) => b.count - a.count).slice(0, 12);
    delete row._vendors;
    delete row._brands;
    return { ...row, topVendors, topBrands };
  }).sort((a, b) => b.productCount - a.productCount || a.name.localeCompare(b.name));
}

function sourceCatalogCategoryRows() {
  const index = readCatalogCategoryIndex();
  return {
    rows: (index.categories || []).map((category) => {
      const name = formatCategoryName(category.name);
      return { ...category, id: category.id || categoryIdentity(name, "source").id, categoryId: category.id || categoryIdentity(name, "source").id, name };
    }),
    index
  };
}

function categoryCoverage(db) {
  if (db.__categoryCoverageOverride) return db.__categoryCoverageOverride;
  const settings = normalizeCategorySettings(db.categorySettings);
  const mainRows = aggregateMainCatalogCategories(db);
  const sourceRows = sourceCatalogCategoryRows().rows;
  const vendorMappings = normalizeVendorCategoryMappings(db.vendorCategoryMappings);
  const mainRowNames = new Set(mainRows.map((row) => formatCategoryName(row.name).toLowerCase()).filter(Boolean));
  const mappedMainNames = new Set(settings
    .map((row) => formatCategoryName(row.name).toLowerCase())
    .filter((name) => name && mainRowNames.has(name)));
  for (const row of mainRows) mappedMainNames.add(formatCategoryName(row.name).toLowerCase());
  const shopifyMapped = settings.filter((row) => row.mappings?.shopify?.categoryPath || row.mappings?.shopify?.categoryId);
  const shopifyWithTaxonomyId = shopifyMapped.filter((row) => row.mappings?.shopify?.categoryId);
  const products = Array.isArray(db.inventory) ? db.inventory : [];
  const verifiedProducts = products.filter((item) => item.categoryVerified && formatCategoryName(item.category || item.mainCategory));
  const uncategorizedProducts = products.filter((item) => !(item.categoryVerified && formatCategoryName(item.category || item.mainCategory)));
  const activeUncategorizedProducts = uncategorizedProducts.filter((item) => item.active !== false);
  const sourceCategoryNames = new Set(sourceRows.map((row) => formatCategoryName(row.name).toLowerCase()).filter(Boolean));
  const learnedVendorCategoryNames = new Set(Object.values(vendorMappings).map((row) => formatCategoryName(row.vendorCategory).toLowerCase()).filter(Boolean));
  const unmappedMainRows = mainRows.filter((row) => {
    const saved = settings.find((setting) => formatCategoryName(setting.name).toLowerCase() === formatCategoryName(row.name).toLowerCase());
    return !(saved?.mappings?.shopify?.categoryPath || saved?.mappings?.shopify?.categoryId);
  });
  const pathMissingTaxonomy = shopifyMapped.filter((row) => row.mappings?.shopify?.categoryPath && !row.mappings?.shopify?.categoryId);
  const matrixifyReadiness = matrixifySmartCollectionReadiness(mainRows, settings);
  const { rows: matrixifyRows, ...matrixify } = matrixifyReadiness;
  const menuIssues = matrixifyMenuReviewRows(readMatrixifyMenuImportTemplate());
  return {
    mainCategoryCount: mappedMainNames.size,
    sourceCategoryCount: sourceCategoryNames.size,
    shopifyMappedCount: shopifyMapped.length,
    shopifyTaxonomyIdCount: shopifyWithTaxonomyId.length,
    shopifyMissingCount: unmappedMainRows.length,
    shopifyPathMissingTaxonomyIdCount: pathMissingTaxonomy.length,
    productCount: products.length,
    verifiedProductCount: verifiedProducts.length,
    uncategorizedProductCount: uncategorizedProducts.length,
    activeUncategorizedProductCount: activeUncategorizedProducts.length,
    vendorCategoryMappingCount: Object.keys(vendorMappings).length,
    sourceVendorCategoryMappedCount: [...learnedVendorCategoryNames].filter((name) => sourceCategoryNames.has(name)).length,
    matrixify,
    attention: [
      { key: "missing-shopify", label: "Main categories missing Shopify mapping", count: unmappedMainRows.length, sample: unmappedMainRows.slice(0, 5).map((row) => row.name) },
      { key: "missing-taxonomy-id", label: "Shopify paths missing taxonomy ID", count: pathMissingTaxonomy.length, sample: pathMissingTaxonomy.slice(0, 5).map((row) => row.name) },
      { key: "uncategorized-products", label: "Products missing verified Main category", count: uncategorizedProducts.length, sample: uncategorizedProducts.slice(0, 5).map((item) => item.sku || item.title).filter(Boolean) },
      { key: "matrixify-duplicates", label: "Matrixify duplicate handles", count: matrixify.duplicateHandleCount, sample: matrixifyRows.filter((row) => row.duplicate_handle).slice(0, 5).map((row) => row.collection_handle) },
      { key: "matrixify-missing-images", label: "Matrixify rows missing images", count: matrixify.missingImageCount, sample: matrixifyRows.filter((row) => !row.missing_shopify && row.missing_image).slice(0, 5).map((row) => row.category) },
      { key: "matrixify-seo-review", label: "Matrixify SEO needs review", count: matrixify.weakSeoCount, sample: matrixifyRows.filter((row) => row.weak_title_tag || row.weak_description_tag || row.duplicate_title_tag || row.duplicate_description_tag).slice(0, 5).map((row) => row.collection_title) },
      { key: "matrixify-menu-review", label: "Matrixify menu needs review", count: menuIssues.length, sample: menuIssues.slice(0, 5).map((row) => row.title || row.menu_item_id) }
    ]
  };
}

function categoryCoverageRows(db, issue) {
  const settings = normalizeCategorySettings(db.categorySettings);
  const mainRows = aggregateMainCatalogCategories(db);
  const vendorMappings = normalizeVendorCategoryMappings(db.vendorCategoryMappings);
  const settingForName = (name) => settings.find((row) => formatCategoryName(row.name).toLowerCase() === formatCategoryName(name).toLowerCase());
  if (issue === "missing-shopify") {
    return mainRows
      .map((row) => ({ row, setting: settingForName(row.name) }))
      .filter(({ setting }) => !(setting?.mappings?.shopify?.categoryPath || setting?.mappings?.shopify?.categoryId))
      .map(({ row }) => ({
        category: row.name,
        products: row.productCount || 0,
        active_products: row.activeProductCount || 0,
        issue: "Missing Shopify category mapping",
        current_shopify_category: ""
      }));
  }
  if (issue === "missing-taxonomy-id") {
    return settings
      .filter((row) => row.mappings?.shopify?.categoryPath && !row.mappings?.shopify?.categoryId)
      .map((row) => ({
        category: row.name,
        shopify_category: row.mappings.shopify.categoryPath || "",
        shopify_category_id: "",
        issue: "Shopify category path did not match a taxonomy ID"
      }));
  }
  if (issue === "uncategorized-products") {
    return (db.inventory || [])
      .filter((item) => !(item.categoryVerified && formatCategoryName(item.category || item.mainCategory)))
      .map((item) => ({
        sku: item.sku || "",
        title: item.marketplaceTitle || item.title || "",
        supplier: item.supplier || item.vendor || "",
        vendor_category: item.sourceCategory || item.vendorCategory || "",
        current_main_category: item.category || item.mainCategory || "",
        active: item.active !== false ? "true" : "false"
      }));
  }
  if (issue === "vendor-category-mappings") {
    return Object.values(vendorMappings)
      .sort((a, b) => String(a.supplier).localeCompare(String(b.supplier)) || String(a.vendorCategory).localeCompare(String(b.vendorCategory)))
      .map((row) => ({
        supplier: row.supplier || "",
        vendor_category: row.vendorCategory || "",
        main_category: row.mainCategory || "",
        sample_sku: row.sampleSku || "",
        match_count: row.matchCount || 0,
        conflict_count: row.conflictCount || 0,
        updated_at: row.updatedAt || ""
      }));
  }
  if (issue === "matrixify-duplicates") {
    return matrixifySmartCollectionReadiness(mainRows, settings).rows
      .filter((row) => row.duplicate_handle)
      .map((row) => ({ ...row, issue: "Duplicate Matrixify collection handle" }));
  }
  if (issue === "matrixify-missing-images") {
    return matrixifySmartCollectionReadiness(mainRows, settings).rows
      .filter((row) => !row.missing_shopify && row.missing_image)
      .map((row) => ({ ...row, issue: "Matrixify collection image is missing" }));
  }
  if (issue === "matrixify-seo-review") {
    return matrixifySmartCollectionReadiness(mainRows, settings).rows
      .filter((row) => !row.missing_shopify)
      .filter((row) => row.weak_title_tag || row.weak_description_tag || row.duplicate_title_tag || row.duplicate_description_tag)
      .map((row) => ({
        category: row.category,
        collection_handle: row.collection_handle,
        collection_title: row.collection_title,
        product_type: row.product_type,
        title_tag: row.title_tag,
        title_length: String(row.title_tag || "").length,
        description_tag: row.description_tag,
        description_length: String(row.description_tag || "").length,
        duplicate_title_tag: row.duplicate_title_tag ? "true" : "false",
        duplicate_description_tag: row.duplicate_description_tag ? "true" : "false",
        issue: [
          row.weak_title_tag ? "Weak title tag" : "",
          row.weak_description_tag ? "Weak description tag" : "",
          row.duplicate_title_tag ? "Duplicate title tag" : "",
          row.duplicate_description_tag ? "Duplicate description tag" : ""
        ].filter(Boolean).join("; ")
      }));
  }
  if (issue === "matrixify-menu-review") {
    return matrixifyMenuReviewRows(readMatrixifyMenuImportTemplate());
  }
  return [];
}

function masterCategoryMappingRows(db = {}) {
  const settings = normalizeCategorySettings(db.categorySettings);
  const vendorMappings = normalizeVendorCategoryMappings(db.vendorCategoryMappings);
  const mainRows = aggregateMainCatalogCategories(db);
  const mainByName = new Map(mainRows.map((row) => [formatCategoryName(row.name).toLowerCase(), row]));
  for (const rawSetting of settings) {
    const setting = applyStoredAttributeMappingsToCategory(rawSetting);
    const name = formatCategoryName(setting.name);
    if (name && !mainByName.has(name.toLowerCase())) {
      mainByName.set(name.toLowerCase(), {
        name,
        productCount: 0,
        activeProductCount: 0,
        stockProductCount: 0
      });
    }
  }
  const rows = [];
  const mappingsByMain = new Map();
  for (const mapping of Object.values(vendorMappings)) {
    const mainCategory = formatCategoryName(mapping.mainCategory);
    if (!mainCategory) continue;
    const key = mainCategory.toLowerCase();
    if (!mappingsByMain.has(key)) mappingsByMain.set(key, []);
    mappingsByMain.get(key).push(mapping);
  }
  for (const [key, main] of mainByName.entries()) {
    const setting = settings.find((row) => formatCategoryName(row.name).toLowerCase() === key) || {};
    const shopify = normalizeChannelCategoryMapping(setting.mappings?.shopify || {});
    const smartCollection = normalizeSmartCollectionProfile(setting.smartCollection || setting.shopifyCollection || {}, main.name);
    const ebay = normalizeChannelCategoryMapping(setting.mappings?.ebay || {});
    const learnedMappings = (mappingsByMain.get(key) || []).sort((a, b) => String(a.supplier).localeCompare(String(b.supplier)) || String(a.vendorCategory).localeCompare(String(b.vendorCategory)));
    const base = {
      "Main Category": main.name,
      "Source Supplier": "",
      "Source Category": "",
      "Shopify": shopify.categoryPath || shopify.categoryId || "",
      "Shopify Category ID": shopify.categoryId || "",
      "Shopify Product Type": smartCollection.productType || "",
      "Shopify Collection": smartCollection.title || "",
      "Shopify Collection Handle": smartCollection.handle || shopify.collectionHandle || "",
      "eBay": ebay.categoryPath || ebay.categoryId || "",
      "eBay Category ID": ebay.categoryId || "",
      "Product Count": main.productCount || 0,
      "Active Products": main.activeProductCount || 0,
      "Stock Products": main.stockProductCount || 0,
      "Mapping Status": setting.status || "",
      "Source Match Count": "",
      "Source Conflict Count": "",
      "Sample SKU": "",
      "Updated At": setting.updatedAt || ""
    };
    if (!learnedMappings.length) {
      rows.push(base);
      continue;
    }
    for (const mapping of learnedMappings) {
      rows.push({
        ...base,
        "Source Supplier": mapping.supplier || "",
        "Source Category": mapping.vendorCategory || "",
        "Source Match Count": mapping.matchCount || 0,
        "Source Conflict Count": mapping.conflictCount || 0,
        "Sample SKU": mapping.sampleSku || "",
        "Updated At": mapping.updatedAt || base["Updated At"]
      });
    }
  }
  return rows.sort((a, b) => String(a["Main Category"]).localeCompare(String(b["Main Category"])) || String(a["Source Supplier"]).localeCompare(String(b["Source Supplier"])) || String(a["Source Category"]).localeCompare(String(b["Source Category"])));
}

function marketplaceCategoryAttributeRows(db = {}, options = {}) {
  const categoryIdFilter = String(options.categoryId || "").trim();
  const settings = normalizeCategorySettings(db.categorySettings).filter((setting) => {
    if (!categoryIdFilter) return true;
    const settingId = String(setting.categoryId || setting.id || categoryIdentity(formatCategoryName(setting.name || ""), "main").id);
    return settingId === categoryIdFilter;
  });
  const mainRows = categoryIdFilter ? [] : aggregateMainCatalogCategories(db);
  const mainByName = new Map(mainRows.map((row) => [formatCategoryName(row.name).toLowerCase(), row]));
  const channels = ["shopify", "ebay", "temu", "tiktok", "whatnot"];
  const channelFilter = String(options.channel || "").trim().toLowerCase();
  const allowedChannels = channelFilter && channels.includes(channelFilter) ? [channelFilter] : channels;
  const rows = [];
  for (const rawSetting of settings) {
    const setting = applyStoredAttributeMappingsToCategory(rawSetting);
    const mainCategory = formatCategoryName(setting.name);
    if (!mainCategory) continue;
    const main = mainByName.get(mainCategory.toLowerCase()) || {};
    for (const channel of allowedChannels) {
      const mapping = normalizeChannelCategoryMapping(setting.mappings?.[channel] || {});
      const attributes = Array.isArray(mapping.attributes) ? mapping.attributes : [];
      const attributeMappings = Array.isArray(mapping.attributeMappings) ? mapping.attributeMappings : [];
      const addRow = (attribute = {}, mapped = {}) => {
        rows.push({
          "Main Category": mainCategory,
          "Category ID": categoryIdentity(mainCategory, "main").id,
          "Marketplace": channel,
          "Marketplace Category": mapping.categoryPath || mapping.categoryId || "",
          "Marketplace Category ID": mapping.categoryId || "",
          "Attribute": attribute.name || mapped.attributeName || mapped.attributeHandle || mapped.attributeId || "",
          "Attribute ID": attribute.id || mapped.attributeId || "",
          "Attribute Handle": attribute.handle || mapped.attributeHandle || "",
          "Required": attribute.required || mapped.required ? "true" : "false",
          "Recommended": attribute.recommended || mapped.recommended ? "true" : "false",
          "Value Mode": attribute.valueMode || attribute.usage || "",
          "Allowed Values": Array.isArray(attribute.values) ? attribute.values.join(" | ") : "",
          "Mapped Source Field": mapped.sourceField || "",
          "Fallback Value": mapped.fallbackValue || "",
          "Mapping Enabled": mapped.enabled === false ? "false" : mapped.sourceField || mapped.fallbackValue ? "true" : "",
          "Product Count": main.productCount || 0,
          "Updated At": setting.updatedAt || ""
        });
      };
      if (!attributes.length && mapping.categoryId) {
        addRow({}, {});
        continue;
      }
      const usedMappingKeys = new Set();
      for (const attribute of attributes) {
        const keys = [attribute.id, attribute.name, attribute.handle].map((value) => String(value || "").trim().toLowerCase()).filter(Boolean);
        const mapped = attributeMappings.find((row) => [row.attributeId, row.attributeName, row.attributeHandle].map((value) => String(value || "").trim().toLowerCase()).some((key) => keys.includes(key))) || {};
        if (mapped.id) usedMappingKeys.add(mapped.id);
        addRow(attribute, mapped);
      }
      for (const mapped of attributeMappings) {
        if (mapped.id && usedMappingKeys.has(mapped.id)) continue;
        addRow({}, mapped);
      }
    }
  }
  return rows.sort((a, b) => String(a["Main Category"]).localeCompare(String(b["Main Category"])) || String(a.Marketplace).localeCompare(String(b.Marketplace)) || String(a.Attribute).localeCompare(String(b.Attribute)));
}

function coverageIssueLabel(issue) {
  return {
    "missing-shopify": "missing-shopify-mappings",
    "missing-taxonomy-id": "shopify-paths-missing-taxonomy-id",
    "uncategorized-products": "uncategorized-products",
    "vendor-category-mappings": "vendor-category-mappings",
    "matrixify-duplicates": "matrixify-duplicate-handles",
    "matrixify-missing-images": "matrixify-missing-images",
    "matrixify-seo-review": "matrixify-seo-review",
    "matrixify-menu-review": "matrixify-menu-review"
  }[issue] || "category-coverage";
}

function rowsToCsv(rows = []) {
  const headers = [...new Set(rows.flatMap((row) => Object.keys(row)))];
  return [headers, ...rows.map((row) => headers.map((header) => row[header] ?? ""))]
    .map((row) => row.map(escapeCsv).join(","))
    .join("\n");
}

const DATA_QUALITY_EXPORT_COLUMNS = [
  "SKU",
  "Title",
  "Product score",
  "Shopify score",
  "eBay score",
  "Missing fields",
  "Issue types",
  "Shopify status",
  "Sync source",
  "Stale days",
  "Closeout",
  "Suggested fix"
];

function dataQualityExportRow(row = {}) {
  return {
    SKU: row.sku,
    Title: row.title,
    "Product score": row.productScore,
    "Shopify score": row.shopifyScore,
    "eBay score": row.ebayScore,
    "Missing fields": (row.issues || []).join("; "),
    "Issue types": (row.issueTypes || []).join("; "),
    "Shopify status": row.shopifyLive ? "Live" : row.shopifyReady ? "Ready" : "Needs work",
    "Sync source": row.syncSource,
    "Stale days": row.staleDays ?? "",
    Closeout: row.toBeDiscontinued ? "TRUE" : "FALSE",
    "Suggested fix": (row.issues || []).slice(0, 3).map((issue) => `Add ${issue}`).join("; ")
  };
}

async function streamDataQualityCsvFromPostgres(res, query = {}) {
  res.writeHead(200, {
    "Content-Type": "text/csv; charset=utf-8",
    "Content-Disposition": "attachment; filename=dataplus-data-quality.csv"
  });
  await writeStreamText(res, `${DATA_QUALITY_EXPORT_COLUMNS.map(escapeCsv).join(",")}\n`);
  const pageSize = 1000;
  let offset = 0;
  while (true) {
    const page = await postgres.readProductQualityRows({ ...query, limit: pageSize, offset, skipCount: true });
    const rows = page?.rows || [];
    if (!rows.length) break;
    const chunk = rows.map((row) => {
      const exportRow = dataQualityExportRow(row);
      return DATA_QUALITY_EXPORT_COLUMNS.map((column) => escapeCsv(exportRow[column] ?? "")).join(",");
    }).join("\n");
    await writeStreamText(res, `${chunk}\n`);
    offset += rows.length;
    if (rows.length < pageSize) break;
  }
  res.end();
}

const PRODUCT_CHANGE_EXPORT_COLUMNS = [
  "sku",
  "supplier",
  "vendorSku",
  "title",
  "field",
  "before",
  "after",
  "delta",
  "deltaPercent",
  "direction",
  "source",
  "jobId",
  "importedAt"
];

function productChangeExportRow(row = {}) {
  return {
    sku: row.sku,
    supplier: row.supplier,
    vendorSku: row.vendorSku,
    title: row.title,
    field: row.field,
    before: row.before,
    after: row.after,
    delta: row.delta,
    deltaPercent: row.deltaPercent,
    direction: row.direction,
    source: row.source,
    jobId: row.jobId,
    importedAt: row.importedAt
  };
}

async function streamProductChangesCsvFromPostgres(res, query = {}) {
  res.writeHead(200, {
    "Content-Type": "text/csv; charset=utf-8",
    "Content-Disposition": "attachment; filename=source-catalog-sku-changes.csv"
  });
  await writeStreamText(res, `${PRODUCT_CHANGE_EXPORT_COLUMNS.map(escapeCsv).join(",")}\n`);
  const pageSize = 1000;
  const maxRows = Math.max(1, Math.min(250000, Number(query.limit || 25000)));
  let written = 0;
  for (let page = 1; written < maxRows; page += 1) {
    const result = await postgres.listProductChangeEvents({ ...query, page, limit: Math.min(pageSize, maxRows - written), skipMeta: true });
    const rows = result?.rows || [];
    if (!rows.length) break;
    const chunk = rows.map((row) => {
      const exportRow = productChangeExportRow(row);
      return PRODUCT_CHANGE_EXPORT_COLUMNS.map((column) => escapeCsv(exportRow[column] ?? "")).join(",");
    }).join("\n");
    await writeStreamText(res, `${chunk}\n`);
    written += rows.length;
    if (rows.length < pageSize) break;
  }
  res.end();
}

async function streamCloseoutSkusCsv(res) {
  if (fs.existsSync(CATALOG_CLOSEOUT_FILE)) {
    res.writeHead(200, {
      "Content-Type": "text/csv; charset=utf-8",
      "Content-Disposition": "attachment; filename=source-catalog-closeouts.csv"
    });
    return fs.createReadStream(CATALOG_CLOSEOUT_FILE).pipe(res);
  }
  if (!postgres.isPostgresEnabled()) return sendJson(res, 404, { error: "Closeout export is not ready yet." });
  res.writeHead(200, {
    "Content-Type": "text/csv; charset=utf-8",
    "Content-Disposition": "attachment; filename=source-catalog-closeouts.csv"
  });
  await writeStreamText(res, "sku\n");
  const pageSize = 1000;
  for (let page = 1; ; page += 1) {
    const result = await postgres.listProducts({ page, limit: pageSize, filters: { toBeDiscontinued: "true" } });
    const rows = result?.inventory || [];
    if (!rows.length) break;
    await writeStreamText(res, rows.map((item) => escapeCsv(item.sku || "")).join("\n") + "\n");
    if (rows.length < pageSize) break;
  }
  res.end();
}

const IMPORT_ERROR_COLUMNS = ["row", "record_key", "field", "issue", "raw_value", "sku", "category", "supplier", "details"];

function csvRecordRow(record, fallback = "") {
  return record?.__rowNumber || fallback || "";
}

function standardImportError(attrs = {}) {
  const row = {
    row: attrs.row ?? csvRecordRow(attrs.record),
    record_key: attrs.recordKey ?? attrs.key ?? attrs.sku ?? attrs.category ?? "",
    field: attrs.field || "",
    issue: attrs.issue || attrs.error || "Import issue",
    raw_value: attrs.rawValue ?? attrs.raw_value ?? "",
    sku: attrs.sku || "",
    category: attrs.category || "",
    supplier: attrs.supplier || "",
    details: attrs.details || ""
  };
  for (const [key, value] of Object.entries(attrs)) {
    if (row[key] === undefined && !["record", "key", "error", "rawValue", "raw_value"].includes(key)) row[key] = value ?? "";
  }
  return row;
}

function importErrorMessages(rows = []) {
  return rows.map((row) => {
    const normalized = standardImportError(row);
    const target = normalized.record_key || normalized.sku || normalized.category || normalized.field;
    return `${normalized.issue}${target ? `: ${target}` : ""}${normalized.row ? ` (row ${normalized.row})` : ""}`;
  }).slice(0, 50);
}

function publicCategories(db, query = "", scope = "source") {
  const settings = categorySettingsMap(db);
  const vendorMappings = normalizeVendorCategoryMappings(db.vendorCategoryMappings);
  const sourceMappingCounts = new Map();
  for (const mapping of Object.values(vendorMappings)) {
    const key = formatCategoryName(mapping.mainCategory).toLowerCase();
    if (key) sourceMappingCounts.set(key, (sourceMappingCounts.get(key) || 0) + 1);
  }
  const q = String(query || "").trim().toLowerCase();
  const normalizedScope = scope === "main" ? "main" : "source";
  const source = normalizedScope === "main"
    ? { rows: aggregateMainCatalogCategories(db), index: { generatedAt: "", catalogImportedAt: "" } }
    : sourceCatalogCategoryRows();
  const matchingRows = q
    ? source.rows.filter((category) => `${category.name || ""} ${category.status || ""} ${category.notes || ""} ${(category.topVendors || []).map((v) => v.name).join(" ")}`.toLowerCase().includes(q))
    : source.rows;
  const rows = matchingRows.map((category) => publicCategoryRow(category, settings, normalizedScope, { sourceMappingCounts }));
  return {
    categories: rows,
    total: rows.length,
    scope: normalizedScope,
    coverage: categoryCoverage(db),
    indexGeneratedAt: source.index.generatedAt || "",
    catalogImportedAt: source.index.catalogImportedAt || ""
  };
}

function compactPublicCategoryMapping(mapping = {}) {
  const normalized = normalizeChannelCategoryMapping(mapping || {});
  const hasMapping = Boolean(normalized.categoryId || normalized.categoryPath || normalized.collectionHandle || normalized.categoryHandle);
  const hasReview = /review/i.test(`${normalized.status || ""} ${normalized.notes || ""}`);
  if (!hasMapping && !hasReview) return null;
  return {
    categoryId: normalized.categoryId || "",
    categoryPath: normalized.categoryPath || "",
    categoryHandle: normalized.categoryHandle || "",
    collectionHandle: normalized.collectionHandle || "",
    attributeCount: Array.isArray(normalized.attributes) ? normalized.attributes.length : 0,
    status: normalized.status || (hasMapping ? "mapped" : "missing"),
    review: hasReview
  };
}

function compactPublicSmartCollection(profile = {}) {
  const normalized = normalizeSmartCollectionProfile(profile || {});
  const result = {};
  if (normalized.enabled === false) result.enabled = false;
  if (normalized.productType) result.productType = normalized.productType;
  if (normalized.handle) result.handle = normalized.handle;
  if (normalized.title) result.title = normalized.title;
  return result;
}

function compactPublicCategoryRow(row = {}) {
  return {
    ...row,
    notes: row.notes || "",
    topVendors: Array.isArray(row.topVendors) ? row.topVendors.slice(0, 6) : [],
    topBrands: Array.isArray(row.topBrands) ? row.topBrands.slice(0, 6) : [],
    mappings: Object.fromEntries([
      ["shopify", compactPublicCategoryMapping(row.mappings?.shopify)],
      ["temu", compactPublicCategoryMapping(row.mappings?.temu)],
      ["tiktok", compactPublicCategoryMapping(row.mappings?.tiktok)],
      ["ebay", compactPublicCategoryMapping(row.mappings?.ebay)],
      ["whatnot", compactPublicCategoryMapping(row.mappings?.whatnot)]
    ].filter(([, mapping]) => mapping)),
    smartCollection: compactPublicSmartCollection(row.smartCollection || {}),
    defaults: undefined,
    requiredAttributes: Array.isArray(row.requiredAttributes) && row.requiredAttributes.length ? row.requiredAttributes.slice(0, 20) : []
  };
}

function compactCategoryResponse(data = {}) {
  return {
    ...data,
    categories: (Array.isArray(data.categories) ? data.categories : []).map(compactPublicCategoryRow)
  };
}

function rawChannelMappingForList(mapping = {}) {
  const hasMapping = Boolean(mapping?.categoryId || mapping?.categoryPath || mapping?.collectionHandle || mapping?.categoryHandle);
  const hasReview = /review/i.test(`${mapping?.status || ""} ${mapping?.notes || ""}`);
  if (!hasMapping && !hasReview) return null;
  return {
    categoryId: mapping.categoryId || "",
    categoryPath: mapping.categoryPath || "",
    categoryHandle: mapping.categoryHandle || "",
    collectionHandle: mapping.collectionHandle || "",
    attributeCount: Array.isArray(mapping.attributes) ? mapping.attributes.length : 0,
    status: mapping.status || (hasMapping ? "mapped" : "missing"),
    review: hasReview
  };
}

function rawCategoryMappingsForList(saved = {}) {
  const mappings = saved.mappings || {};
  const result = {};
  for (const channel of ["shopify", "temu", "tiktok", "ebay", "whatnot"]) {
    const compact = rawChannelMappingForList(mappings[channel] || {});
    if (compact) result[channel] = compact;
  }
  return result;
}

function categoryMappingCountForList(mappings = {}) {
  return ["shopify", "temu", "tiktok", "ebay", "whatnot"].filter((key) => {
    const mapping = mappings[key] || {};
    return mapping.categoryId || mapping.categoryPath || mapping.collectionHandle;
  }).length;
}

function categoryMissingMappingsForList(mappings = {}) {
  return ["shopify", "temu", "tiktok", "ebay", "whatnot"].filter((key) => {
    const mapping = mappings[key] || {};
    return !(mapping.categoryId || mapping.categoryPath || mapping.collectionHandle);
  });
}

function compactCoverageForList(categories = []) {
  const shopifyMapped = categories.filter((row) => row.mappings?.shopify?.categoryId || row.mappings?.shopify?.categoryPath);
  const shopifyWithTaxonomyId = shopifyMapped.filter((row) => row.mappings?.shopify?.categoryId);
  const missingShopify = categories.filter((row) => !(row.mappings?.shopify?.categoryId || row.mappings?.shopify?.categoryPath));
  const pathMissingTaxonomy = shopifyMapped.filter((row) => row.mappings?.shopify?.categoryPath && !row.mappings?.shopify?.categoryId);
  return {
    mainCategoryCount: categories.length,
    sourceCategoryCount: 0,
    shopifyMappedCount: shopifyMapped.length,
    shopifyTaxonomyIdCount: shopifyWithTaxonomyId.length,
    shopifyMissingCount: missingShopify.length,
    shopifyPathMissingTaxonomyIdCount: pathMissingTaxonomy.length,
    productCount: categories.reduce((sum, row) => sum + Number(row.productCount || 0), 0),
    verifiedProductCount: categories.reduce((sum, row) => sum + Number(row.productCount || 0), 0),
    uncategorizedProductCount: 0,
    activeUncategorizedProductCount: 0,
    vendorCategoryMappingCount: 0,
    sourceVendorCategoryMappedCount: 0,
    matrixify: {},
    attention: [
      { key: "missing-shopify", label: "Main categories missing Shopify mapping", count: missingShopify.length, sample: missingShopify.slice(0, 5).map((row) => row.name) },
      { key: "missing-taxonomy-id", label: "Shopify paths missing taxonomy ID", count: pathMissingTaxonomy.length, sample: pathMissingTaxonomy.slice(0, 5).map((row) => row.name) }
    ]
  };
}

function publicCategoriesLiteFromPostgresState(db = {}, query = "", scope = "main", options = {}) {
  const normalizedScope = scope === "main" ? "main" : "source";
  const settings = Array.isArray(db.categorySettings) ? db.categorySettings : [];
  const settingsByName = new Map();
  for (const saved of settings) {
    const name = formatCategoryName(saved.name || saved.category || "");
    if (name) settingsByName.set(name.toLowerCase(), saved);
  }
  const byName = new Map();
  const sourceRows = normalizedScope === "main"
    ? (Array.isArray(db.__mainCategoryRows) ? db.__mainCategoryRows : [])
    : sourceCatalogCategoryRows().rows;
  for (const rawRow of sourceRows) {
    const name = formatCategoryName(rawRow.name || "Uncategorized") || "Uncategorized";
    byName.set(name.toLowerCase(), {
      id: rawRow.id || categoryIdentity(name, normalizedScope).id,
      categoryId: rawRow.categoryId || rawRow.id || categoryIdentity(name, normalizedScope).id,
      name,
      productCount: Number(rawRow.productCount || 0),
      activeProductCount: Number(rawRow.activeProductCount || 0),
      stockProductCount: Number(rawRow.stockProductCount || 0),
      hazardousProductCount: Number(rawRow.hazardousProductCount || 0),
      sourceCatalogProductCount: Number(rawRow.sourceCatalogProductCount || 0),
      createdSource: rawRow.createdSource || "",
      topVendors: Array.isArray(rawRow.topVendors) ? rawRow.topVendors.slice(0, 6) : [],
      topBrands: Array.isArray(rawRow.topBrands) ? rawRow.topBrands.slice(0, 6) : []
    });
  }
  if (normalizedScope !== "main") {
    for (const saved of settings) {
      const name = formatCategoryName(saved.name || saved.category || "");
      if (!name || byName.has(name.toLowerCase())) continue;
      const identity = categoryIdentity(name, normalizedScope);
      byName.set(name.toLowerCase(), {
        id: saved.id || saved.categoryId || identity.id,
        categoryId: saved.categoryId || saved.id || identity.id,
        name,
        productCount: 0,
        activeProductCount: 0,
        stockProductCount: 0,
        hazardousProductCount: 0,
        topVendors: [],
        topBrands: []
      });
    }
  }
  const categories = [...byName.values()].map((row) => {
    const saved = settingsByName.get(row.name.toLowerCase()) || {};
    const mappings = rawCategoryMappingsForList(saved);
    const mappingCount = categoryMappingCountForList(mappings);
    const missingMappings = categoryMissingMappingsForList(mappings);
    const savedExists = Boolean(saved.name || saved.categoryId || saved.id);
    const lifecycle = !savedExists && row.productCount > 0 ? "new" : savedExists && row.productCount === 0 ? "outdated" : "current";
    const sourceMappingCount = Number(row.sourceMappingCount || 0);
    const createdSource = saved.createdSource || row.createdSource || (normalizedScope === "main" && row.productCount > 0 ? "system:true-value" : "manual");
    const createdByLabel = ["system:true-value", "system:true-value-source"].includes(createdSource)
      ? "System - True Value"
      : (saved.createdBy || row.createdBy || "Manual");
    const blockers = categoryDeleteBlockers({ ...row, sourceMappingCount });
    return {
      ...row,
      scope: normalizedScope,
      status: saved.status || (mappingCount ? "mapped" : "needs_review"),
      owner: saved.owner || "",
      notes: saved.notes || "",
      mappings,
      smartCollection: compactPublicSmartCollection(saved.smartCollection || saved.shopifyCollection || {}),
      requiredAttributes: Array.isArray(saved.requiredAttributes) && saved.requiredAttributes.length ? saved.requiredAttributes.slice(0, 20) : [],
      savedExists,
      createdBy: saved.createdBy || row.createdBy || "",
      updatedBy: saved.updatedBy || row.updatedBy || "",
      createdSource,
      createdByLabel,
      createdAt: saved.createdAt || row.createdAt || "",
      updatedAt: saved.updatedAt || row.updatedAt || "",
      lifecycle,
      sourceMappingCount,
      canDelete: blockers.length === 0,
      deleteBlockers: blockers,
      mappingCount,
      missingMappings
    };
  }).sort((a, b) => Number(b.productCount || 0) - Number(a.productCount || 0) || a.name.localeCompare(b.name));
  const q = String(query || "").trim().toLowerCase();
  const filtered = q
    ? categories.filter((category) => `${category.name} ${category.status} ${category.notes} ${(category.topVendors || []).map((v) => v.name).join(" ")}`.toLowerCase().includes(q))
    : categories;
  const responseCategories = normalizedScope === "source" && !q && !options.full ? filtered.slice(0, 3000) : filtered;
  return {
    categories: responseCategories,
    total: filtered.length,
    scope: normalizedScope,
    coverage: db.__categoryCoverageOverride || compactCoverageForList(categories),
    indexGeneratedAt: "",
    catalogImportedAt: ""
  };
}

async function rebuildStoredCategorySummaryIndex(scope = "main") {
  if (!postgres.isPostgresEnabled()) return null;
  const normalizedScope = scope === "source" ? "source" : "main";
  let db;
  if (normalizedScope === "main") {
    const [categorySettings, vendorCategoryMappings, mainRows] = await Promise.all([
      postgres.readStateField("categorySettings").catch(() => []),
      postgres.readStateField("vendorCategoryMappings").catch(() => ({})),
      postgres.listCategoryProductStats()
    ]);
    db = {
      inventory: [],
      categorySettings: categorySettings || [],
      vendorCategoryMappings: vendorCategoryMappings || {},
      __mainCategoryRows: mainRows || []
    };
  } else {
    const [categorySettings, vendorCategoryMappings] = await Promise.all([
      postgres.readStateField("categorySettings").catch(() => []),
      postgres.readStateField("vendorCategoryMappings").catch(() => ({}))
    ]);
    db = {
      inventory: [],
      categorySettings: categorySettings || [],
      vendorCategoryMappings: vendorCategoryMappings || {}
    };
  }
  const data = publicCategoriesLiteFromPostgresState(db, "", normalizedScope, { full: true });
  await postgres.replaceCategorySummaryIndex(normalizedScope, data.categories || [], {
    generatedAt: new Date().toISOString(),
    source: "server-rebuild"
  });
  return data;
}

function categoryResponseFromStoredIndex(index = {}, query = "", scope = "main", coverageOverride = null) {
  const normalizedScope = scope === "source" ? "source" : "main";
  const categories = Array.isArray(index.rows) ? index.rows : [];
  const q = String(query || "").trim();
  return {
    categories,
    total: Number(index.total || categories.length || 0),
    scope: normalizedScope,
    coverage: coverageOverride || compactCoverageForList(categories),
    indexGeneratedAt: index.generatedAt || categories[0]?.__indexMeta?.generatedAt || "",
    catalogImportedAt: "",
    storedIndex: true,
    query: q
  };
}

async function publicCategoriesFast(query = "", scope = "source") {
  const normalizedScope = scope === "main" ? "main" : "source";
  const normalizedQuery = String(query || "").trim().toLowerCase();
  const key = `${normalizedScope}|${normalizedQuery}`;
  const now = Date.now();
  const cached = categoryResponseCache.get(key);
  if (cached && now - cached.createdAt < 10 * 60_000) return cached.data;
  const stored = readCategoryResponseCacheFile();
  const staleStored = stored || readCategoryResponseCacheFile({ allowStale: true });
  if (postgres.isPostgresEnabled()) {
    const limit = normalizedScope === "source" && !normalizedQuery ? 3000 : 100000;
    let index = await postgres.readCategorySummaryIndex(normalizedScope, { q: normalizedQuery, limit }).catch(() => null);
    if (!index?.rows?.length && !normalizedQuery) {
      const rebuilt = await rebuildStoredCategorySummaryIndex(normalizedScope);
      index = rebuilt ? {
        rows: normalizedScope === "source" ? (rebuilt.categories || []).slice(0, limit) : (rebuilt.categories || []),
        total: rebuilt.total || rebuilt.categories?.length || 0,
        generatedAt: new Date().toISOString()
      } : index;
    }
    if (index?.rows?.length || normalizedQuery) {
      const data = categoryResponseFromStoredIndex(index || { rows: [], total: 0 }, query, normalizedScope, normalizedScope === "source" ? staleStored?.main?.coverage : null);
      categoryResponseCache.set(key, { createdAt: Date.now(), data });
      return data;
    }
  }
  if (stored?.[normalizedScope]) {
    const data = filterCategoryResponse(stored[normalizedScope], query, normalizedScope);
    categoryResponseCache.set(key, { createdAt: Date.now(), data });
    return data;
  }
  let db;
  if (postgres.isPostgresEnabled() && normalizedScope === "source") {
    const [categorySettings, vendorCategoryMappings] = await Promise.all([
      postgres.readStateField("categorySettings"),
      postgres.readStateField("vendorCategoryMappings")
    ]);
    db = { inventory: [], categorySettings, vendorCategoryMappings };
    const data = publicCategoriesLiteFromPostgresState(db, query, normalizedScope);
    if (staleStored?.main?.coverage) data.coverage = staleStored.main.coverage;
    writeCategoryResponseCacheFile(normalizedScope, data);
    categoryResponseCache.set(key, { createdAt: Date.now(), data });
    return data;
  } else if (postgres.isPostgresEnabled() && normalizedScope === "main") {
    const [categorySettings, vendorCategoryMappings, mainRows] = await Promise.all([
      postgres.readStateField("categorySettings"),
      postgres.readStateField("vendorCategoryMappings"),
      postgres.listCategoryProductStats()
    ]);
    db = { inventory: [], categorySettings, vendorCategoryMappings, __mainCategoryRows: mainRows || [], __categoryCoverageOverride: staleStored?.main?.coverage || staleStored?.source?.coverage || null };
    const data = publicCategoriesLiteFromPostgresState(db, query, normalizedScope);
    writeCategoryResponseCacheFile(normalizedScope, data);
    categoryResponseCache.set(key, { createdAt: Date.now(), data });
    return data;
  } else {
    db = await readDbFast();
  }
  const fullData = compactCategoryResponse(publicCategories(db, "", normalizedScope));
  if (normalizedScope === "source" && staleStored?.main?.coverage) fullData.coverage = staleStored.main.coverage;
  const data = normalizedQuery ? filterCategoryResponse(fullData, query, normalizedScope) : fullData;
  writeCategoryResponseCacheFile(normalizedScope, fullData);
  categoryResponseCache.set(key, { createdAt: Date.now(), data });
  if (categoryResponseCache.size > 50) {
    const oldest = [...categoryResponseCache.entries()].sort((a, b) => a[1].createdAt - b[1].createdAt).slice(0, 10);
    for (const [oldKey] of oldest) categoryResponseCache.delete(oldKey);
  }
  return data;
}

function readCategoryResponseCacheFile(options = {}) {
  if (!fs.existsSync(CATEGORY_CACHE_FILE)) return null;
  try {
    const data = JSON.parse(fs.readFileSync(CATEGORY_CACHE_FILE, "utf8"));
    return data.cacheVersion === CATEGORY_CACHE_VERSION || options.allowStale ? data : null;
  } catch {
    return null;
  }
}

function writeCategoryResponseCacheFile(scope, data) {
  try {
    const current = readCategoryResponseCacheFile() || {};
    current.cacheVersion = CATEGORY_CACHE_VERSION;
    current[scope] = { ...data, cachedAt: new Date().toISOString() };
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    fs.writeFileSync(CATEGORY_CACHE_FILE, JSON.stringify(current));
  } catch {
    // Category reads can still use the in-memory cache if the sidecar write fails.
  }
}

function filterCategoryResponse(data = {}, query = "", scope = "source") {
  const q = String(query || "").trim().toLowerCase();
  const categories = Array.isArray(data.categories) ? data.categories : [];
  const filtered = q
    ? categories.filter((category) => `${category.name} ${category.status} ${category.notes} ${(category.topVendors || []).map((v) => v.name).join(" ")}`.toLowerCase().includes(q))
    : categories;
  return {
    ...data,
    categories: filtered,
    total: filtered.length,
    scope
  };
}

function clearCategoryResponseCache() {
  categoryResponseCache = new Map();
  redisCache.deleteByPrefix("dataplus:category-requirements:").catch(() => {});
  try {
    if (fs.existsSync(CATEGORY_CACHE_FILE)) fs.unlinkSync(CATEGORY_CACHE_FILE);
  } catch {
    // Cache invalidation is best-effort; the in-memory cache is cleared above.
  }
  scheduleStoredCategorySummaryRebuild("both");
}

function categoryRequirementsCacheKey(categoryId = "", channel = "") {
  const category = String(categoryId || "").trim().toLowerCase();
  const marketplace = String(channel || "").trim().toLowerCase();
  if (!category || !marketplace) return "";
  const identity = crypto.createHash("sha1").update(`${category}|${marketplace}`).digest("hex");
  return `dataplus:category-requirements:v1:${identity}`;
}

const categorySummaryRebuildTimers = new Map();

function scheduleStoredCategorySummaryRebuild(scope = "both") {
  if (!postgres.isPostgresEnabled()) return;
  const scopes = scope === "both" ? ["main", "source"] : [scope === "source" ? "source" : "main"];
  for (const targetScope of scopes) {
    if (categorySummaryRebuildTimers.has(targetScope)) clearTimeout(categorySummaryRebuildTimers.get(targetScope));
    categorySummaryRebuildTimers.set(targetScope, setTimeout(async () => {
      categorySummaryRebuildTimers.delete(targetScope);
      try {
        await rebuildStoredCategorySummaryIndex(targetScope);
        categoryResponseCache = new Map();
      } catch (error) {
        console.error(`Unable to rebuild ${targetScope} category summary index`, error);
      }
    }, 500));
  }
}

function findPublicCategory(db, categoryId, scope = "source") {
  const categories = publicCategories(db, "", scope).categories;
  return categories.find((category) => category.id === categoryId || category.categoryId === categoryId);
}

function normalizeOrderTimeline(order) {
  const events = Array.isArray(order.timeline) ? order.timeline : [];
  if (!events.some((event) => event.type === "created")) {
    events.unshift({
      id: crypto.randomUUID(),
      type: "created",
      title: "Order created",
      message: `${order.source} order imported into DataPlus.`,
      user: "System",
      createdAt: order.createdAt || new Date().toISOString()
    });
  }
  if (order.notes && !events.some((event) => event.type === "note" && event.message === order.notes)) {
    events.push({
      id: crypto.randomUUID(),
      type: "note",
      title: "Initial note",
      message: order.notes,
      user: "System",
      createdAt: order.updatedAt || order.createdAt || new Date().toISOString()
    });
  }
  return events.sort((a, b) => new Date(a.createdAt || 0) - new Date(b.createdAt || 0));
}

function addOrderTimeline(order, event) {
  order.timeline = normalizeOrderTimeline(order);
  order.timeline.push({
    id: crypto.randomUUID(),
    user: "Luis",
    createdAt: new Date().toISOString(),
    ...event
  });
  order.timeline.sort((a, b) => new Date(a.createdAt || 0) - new Date(b.createdAt || 0));
}

function addInventoryLedger(db, item, event = {}) {
  db.inventoryLedger = Array.isArray(db.inventoryLedger) ? db.inventoryLedger : [];
  const qtyBefore = Number(event.qtyBefore ?? item.qty ?? 0);
  const qtyAfter = Number(event.qtyAfter ?? item.qty ?? 0);
  const reservedBefore = Number(event.reservedBefore ?? item.reserved ?? 0);
  const reservedAfter = Number(event.reservedAfter ?? item.reserved ?? 0);
  const quantityChange = Number(event.quantityChange ?? (qtyAfter - qtyBefore));
  const reservedChange = Number(event.reservedChange ?? (reservedAfter - reservedBefore));
  db.inventoryLedger.unshift({
    id: crypto.randomUUID(),
    productId: item.id,
    sku: item.sku,
    title: item.title || item.marketplaceTitle || "",
    type: event.type || "adjustment",
    source: event.source || "manual",
    referenceId: event.referenceId || "",
    referenceNumber: event.referenceNumber || "",
    warehouseId: event.warehouseId || "",
    warehouseName: event.warehouseName || "",
    locationBin: event.locationBin || "",
    quantityChange,
    reservedChange,
    qtyBefore,
    qtyAfter,
    reservedBefore,
    reservedAfter,
    reason: event.reason || "",
    serials: Array.isArray(event.serials) ? event.serials : [],
    user: event.user || "Luis",
    createdAt: new Date().toISOString()
  });
}

function skuMatchesInventoryItem(value, item = {}) {
  const key = String(value || "").trim().toLowerCase();
  if (!key) return false;
  return [item.sku, item.id, ...(item.aliases || []).map((row) => row.aliasSku)]
    .filter(Boolean)
    .some((candidate) => String(candidate).toLowerCase() === key);
}

function inventoryOrderLines(order = {}, item = {}) {
  return orderLineItems(order).filter((line) => skuMatchesInventoryItem(line.sku || line.mappedSku || line.originalSku, item));
}

function inventorySkuOperations(item = {}, orders = [], ledger = []) {
  const now = Date.now();
  const day = 24 * 60 * 60 * 1000;
  const terminal = new Set(["fulfilled", "shipped", "canceled", "cancelled", "void", "deleted", "refunded"]);
  const rows = orders.map((order) => {
    const lines = inventoryOrderLines(order, item);
    const quantity = lines.reduce((sum, line) => sum + Number(line.qty || 0), 0);
    const allocations = (Array.isArray(order.inventoryAllocations) ? order.inventoryAllocations : [])
      .filter((allocation) => skuMatchesInventoryItem(allocation.sku || allocation.productId, item) && allocation.status !== "released")
      .map((allocation) => ({ ...allocation, orderId: order.id, orderNumber: order.orderNumber, buyer: order.buyer, status: order.status }));
    const fulfilled = (Array.isArray(order.fulfillmentLines) ? order.fulfillmentLines : [])
      .filter((line) => skuMatchesInventoryItem(line.sku, item))
      .reduce((sum, line) => sum + Number(line.qtyFulfilled || 0), 0);
    return { ...order, inventoryQuantity: quantity, inventoryFulfilledQty: fulfilled, inventoryAllocations: allocations };
  }).filter((order) => order.inventoryQuantity > 0 || order.inventoryAllocations.length > 0);
  const openOrders = rows.filter((order) => !terminal.has(String(order.status || "").toLowerCase()));
  const shippedRows = rows.filter((order) => order.inventoryFulfilledQty > 0 || terminal.has(String(order.status || "").toLowerCase()));
  const soldWithin = (days) => shippedRows.reduce((sum, order) => {
    const timestamp = new Date(order.shippedAt || order.fulfilledAt || order.updatedAt || order.createdAt || 0).getTime();
    return timestamp && now - timestamp <= days * day ? sum + Number(order.inventoryFulfilledQty || order.inventoryQuantity || 0) : sum;
  }, 0);
  const shipped30 = soldWithin(30);
  const shipped90 = soldWithin(90);
  const available = Number(item.qty || 0) - Number(item.reserved || 0);
  const activeAllocations = rows.flatMap((order) => order.inventoryAllocations);
  return {
    orders: rows,
    allocations: activeAllocations,
    ledger: ledger.filter((row) => skuMatchesInventoryItem(row.sku || row.productId, item)).slice(0, 100),
    metrics: {
      openOrderCount: openOrders.length,
      openOrderUnits: openOrders.reduce((sum, order) => sum + Number(order.inventoryQuantity || 0), 0),
      allocatedUnits: activeAllocations.reduce((sum, allocation) => sum + Number(allocation.qty || 0), 0),
      shippedOrderCount: shippedRows.length,
      shipped30,
      shipped90,
      averageDaily30: shipped30 / 30,
      averageDaily90: shipped90 / 90,
      daysOfCover: shipped30 > 0 ? Math.max(0, available) / (shipped30 / 30) : null,
      available
    }
  };
}

function cleanSerialPart(value) {
  return String(value || "")
    .trim()
    .replace(/[^A-Za-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .toUpperCase() || "NA";
}

function generatedSerial(po, vendor, receivedAt, unitIndex = 1) {
  const base = `${cleanSerialPart(po.poNumber)}-${cleanSerialPart(vendor?.vendorNumber || po.supplier)}-${cleanSerialPart(receivedAt)}`;
  return unitIndex > 1 ? `${base}-${String(unitIndex).padStart(3, "0")}` : base;
}

function generatedReceiptSerial(po, vendor, receivedAt, sku, unitIndex = 1) {
  const base = `${cleanSerialPart(po.poNumber)}-${cleanSerialPart(vendor?.vendorNumber || po.supplier)}-${cleanSerialPart(sku)}-${cleanSerialPart(receivedAt)}`;
  return `${base}-${String(unitIndex).padStart(3, "0")}`;
}

function findOpenPurchaseOrderLinks(db, orderIds = []) {
  const ids = new Set(orderIds.filter(Boolean));
  const duplicates = [];
  for (const order of (db.orders || []).filter((row) => ids.has(row.id))) {
    const poIds = Array.isArray(order.purchaseOrderIds) ? order.purchaseOrderIds : [];
    for (const poId of poIds) {
      const po = (db.purchaseOrders || []).find((row) => row.id === poId);
      if (po && !["closed", "canceled"].includes(String(po.status || "").toLowerCase())) {
        duplicates.push({
          orderId: order.id,
          orderNumber: order.orderNumber,
          poId: po.id,
          poNumber: po.poNumber,
          status: po.status
        });
      }
    }
  }
  return duplicates;
}

function createPurchaseOrderFromOrders(db, orderIds, options = {}) {
  const ids = [...new Set((orderIds || []).filter(Boolean))];
  if (!ids.length) throw new Error("At least one order is required to create a purchase order.");
  const duplicates = options.forceDuplicate ? [] : findOpenPurchaseOrderLinks(db, ids);
  if (duplicates.length) {
    const error = new Error("One or more selected orders already has an open purchase order.");
    error.code = "DUPLICATE_OPEN_PO";
    error.duplicates = duplicates;
    throw error;
  }
  const orders = ids.map((id) => db.orders.find((order) => order.id === id)).filter(Boolean);
  if (!orders.length) throw new Error("No matching orders found for purchase order.");

  const itemMap = new Map();
  for (const order of orders) {
    const items = order.items?.length ? order.items : [{ sku: order.sku, title: order.title, qty: order.qty, price: order.productCost || 0 }];
    for (const item of items) {
      const sku = item.sku || "UNKNOWN";
      const existing = itemMap.get(sku) || {
        sku,
        title: item.title || order.title || sku,
        qty: 0,
        estimatedUnitCost: Number(order.productCost || 0) / Math.max(1, Number(order.qty || 1)),
        orderNumbers: []
      };
      existing.qty += Number(item.qty || 0);
      if (!existing.orderNumbers.includes(order.orderNumber)) existing.orderNumbers.push(order.orderNumber);
      itemMap.set(sku, existing);
    }
  }

  const vendor = options.vendorId ? findVendorById(db, options.vendorId) : findVendorByName(db, options.supplier) || preferredVendorForOrders(db, orders) || findVendorByName(db, "Local Wholesale");
  const warehouse = (db.warehouses || []).find((item) => item.id === options.warehouseId) || (db.warehouses || [])[0] || null;
  const po = {
    id: crypto.randomUUID(),
    poNumber: nextPoNumber(db),
    status: "draft",
    vendorId: vendor?.id || "",
    supplier: vendor?.name || options.supplier || "Unassigned supplier",
    warehouseId: warehouse?.id || "",
    warehouseName: warehouse?.name || "",
    source: orders.length > 1 ? "master-order-selection" : "order",
    orderIds: orders.map((order) => order.id),
    orderNumbers: orders.map((order) => order.orderNumber),
    items: Array.from(itemMap.values()),
    totalUnits: Array.from(itemMap.values()).reduce((sum, item) => sum + Number(item.qty || 0), 0),
    estimatedCost: orders.reduce((sum, order) => sum + Number(order.productCost || 0), 0),
    notes: options.notes || "",
    createdBy: options.user || "Luis",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    timeline: [
      {
        id: crypto.randomUUID(),
        type: "created",
        title: "PO created",
        message: `Created from ${orders.length} order${orders.length === 1 ? "" : "s"}.`,
        user: options.user || "Luis",
        createdAt: new Date().toISOString()
      }
    ],
    returns: []
  };

  db.purchaseOrders = db.purchaseOrders || [];
  db.purchaseOrders.unshift(po);

  for (const order of orders) {
    order.purchaseOrderIds = Array.isArray(order.purchaseOrderIds) ? order.purchaseOrderIds : [];
    order.purchaseOrderNumbers = Array.isArray(order.purchaseOrderNumbers) ? order.purchaseOrderNumbers : [];
    if (!order.purchaseOrderIds.includes(po.id)) order.purchaseOrderIds.push(po.id);
    if (!order.purchaseOrderNumbers.includes(po.poNumber)) order.purchaseOrderNumbers.push(po.poNumber);
    addOrderTimeline(order, {
      type: "po",
      title: "Purchase order created",
      message: `${po.poNumber} created for ${orders.length > 1 ? "selected orders" : "this order"}.`,
      user: po.createdBy
    });
  }

  return po;
}

function nextDraftNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.draft = Number(db.sequence.draft || 0) + 1;
  return `DRF-${String(db.sequence.draft).padStart(5, "0")}`;
}

function nextDraftRevisionNumber(db, quoteGroupId) {
  const group = String(quoteGroupId || "").trim();
  if (!group) return 1;
  return ((db.orderDrafts || [])
    .filter((row) => String(row.quoteGroupId || "").trim() === group)
    .reduce((max, row) => Math.max(max, Number(row.revisionNumber || 1)), 0)) + 1;
}

function nextReturnNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.return = Number(db.sequence.return || 0) + 1;
  return `RET-${String(db.sequence.return).padStart(5, "0")}`;
}

function nextOrderNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.order = Number(db.sequence.order || 1000) + 1;
  return `${ORDER_PREFIX}-${String(db.sequence.order).padStart(6, "0")}`;
}

function nextPoNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.po = Number(db.sequence.po || 2000) + 1;
  return `PO-${String(db.sequence.po).padStart(6, "0")}`;
}

function nextVendorNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.vendor = Number(db.sequence.vendor || 3000) + 1;
  return `VEN-${String(db.sequence.vendor).padStart(5, "0")}`;
}

function nextWarehouseCode(db) {
  db.sequence = db.sequence || {};
  db.sequence.warehouse = Number(db.sequence.warehouse || 0) + 1;
  return `WH-${String(db.sequence.warehouse).padStart(3, "0")}`;
}

function nextCustomerNumber(db) {
  db.sequence = db.sequence || {};
  db.sequence.customer = Number(db.sequence.customer || (db.customers || []).length) + 1;
  return `CUS-${String(db.sequence.customer).padStart(5, "0")}`;
}

