function publicState(db, options = {}) {
  const connectorState = mergedConnectorState(db);
  const ebaySettings = ebayChannelSettings(db);
  const lite = Boolean(options.lite);
  const shopifyStatusMap = lite ? {} : readShopifyStatusMapSync();
  const sourceEnrichmentMap = lite ? {} : readProductSourceEnrichmentSync();
  const systemSettings = normalizeSystemSettings(db.systemSettings || {});
  const safeDb = {
    ...db,
    systemSettings,
    tablePreferences: normalizeUserTablePreferences(db.tablePreferences || {}),
    connections: (db.connections || []).map(publicConnection),
    inventory: lite ? [] : (db.inventory || []).map((item) => publicInventoryListItem(item, { shopifyStatusMap, sourceEnrichmentMap, systemSettings })),
    orders: lite ? (db.orders || []).slice(0, 25) : (db.orders || []),
    importJobs: clientImportJobs(Array.isArray(db.importJobs) ? db.importJobs.slice(0, IMPORT_JOB_HISTORY_LIMIT) : []),
    categorySettings: lite ? [] : (db.categorySettings || []),
    vendorCategoryMappings: lite ? {} : (db.vendorCategoryMappings || {}),
    sourceCatalogOverrides: {},
    connectorState: {
      temuAuthorized: Boolean(connectorState.temuAccessToken),
      temuMallId: connectorState.temuMallId || "",
      temuLastOrderSync: connectorState.temuLastOrderSync || null,
      ebayAuthorized: Boolean(connectorState.ebayAccessToken || connectorState.ebayRefreshToken),
      ebayEnvironment: process.env.EBAY_ENVIRONMENT || "production",
      ebayLastOrderSync: connectorState.ebayLastOrderSync || null,
      ebayListingDefaults: {
        marketplaceId: ebaySettings.ebayMarketplaceId || process.env.EBAY_MARKETPLACE_ID || "EBAY_US",
        merchantLocationKey: ebaySettings.ebayMerchantLocationKey || process.env.EBAY_MERCHANT_LOCATION_KEY || "",
        paymentPolicyId: ebaySettings.ebayPaymentPolicyId || process.env.EBAY_PAYMENT_POLICY_ID || "",
        returnPolicyId: ebaySettings.ebayReturnPolicyId || process.env.EBAY_RETURN_POLICY_ID || "",
        fulfillmentPolicyId: ebaySettings.ebayFulfillmentPolicyId || process.env.EBAY_FULFILLMENT_POLICY_ID || "",
        currency: ebaySettings.ebayCurrency || process.env.EBAY_CURRENCY || "USD"
      }
    }
  };
  return { ...safeDb, summary: db.__summaryOverride || summarize({ ...safeDb, inventory: db.inventory || [], orders: db.orders || [] }), inventoryLoaded: !lite, categorySettingsLoaded: !lite, ordersLoaded: !lite };
}

async function withOperationalSummary(db) {
  if (!postgres.isPostgresEnabled()) return db;
  const now = Date.now();
  if (!operationalSummaryCache.pending && now - operationalSummaryCache.refreshedAt > 60_000) {
    operationalSummaryCache.pending = postgres.readOperationalSummary()
      .then((summary) => {
        if (summary) {
          operationalSummaryCache.value = summary;
          operationalSummaryCache.refreshedAt = Date.now();
        }
      })
      .catch((error) => console.warn("Unable to refresh Postgres operational summary:", error.message || error))
      .finally(() => { operationalSummaryCache.pending = null; });
  }
  if (!operationalSummaryCache.value) return db;
  return {
    ...db,
    __summaryOverride: {
      ...operationalSummaryCache.value,
      sources: (db.connections || []).map((connection) => ({
        id: connection.id,
        name: connection.name,
        connected: Boolean(connection.connected),
        status: connection.status || "",
        lastSync: connection.lastSync || null
      }))
    }
  };
}

function publicStateJson(db, options = {}) {
  const lite = Boolean(options.lite);
  const dbMtime = postgres.isPostgresEnabled() ? 0 : (fs.existsSync(DB_FILE) ? fs.statSync(DB_FILE).mtimeMs : 0);
  const settingsMtime = fs.existsSync(SYSTEM_SETTINGS_FILE) ? fs.statSync(SYSTEM_SETTINGS_FILE).mtimeMs : 0;
  const preferencesMtime = fs.existsSync(USER_TABLE_PREFERENCES_FILE) ? fs.statSync(USER_TABLE_PREFERENCES_FILE).mtimeMs : 0;
  const enrichmentMtime = fs.existsSync(PRODUCT_SOURCE_ENRICHMENT_FILE) ? fs.statSync(PRODUCT_SOURCE_ENRICHMENT_FILE).mtimeMs : 0;
  if (
    publicStateJsonCache &&
    publicStateJsonCache.dbMtime === dbMtime &&
    publicStateJsonCache.settingsMtime === settingsMtime &&
    publicStateJsonCache.preferencesMtime === preferencesMtime &&
    publicStateJsonCache.enrichmentMtime === enrichmentMtime &&
    publicStateJsonCache.lite === lite
  ) {
    return publicStateJsonCache.text;
  }
  const text = JSON.stringify(publicState(db, { lite }));
  publicStateJsonCache = { dbMtime, settingsMtime, preferencesMtime, enrichmentMtime, lite, text };
  return text;
}

function publicStateGzip(db, options = {}) {
  const text = publicStateJson(db, options);
  const lite = Boolean(options.lite);
  if (!publicStateJsonCache.gzip || publicStateJsonCache.gzipLite !== lite) {
    publicStateJsonCache.gzip = zlib.gzipSync(text);
    publicStateJsonCache.gzipLite = lite;
  }
  return publicStateJsonCache.gzip;
}

function summarize(db) {
  const activeOrders = db.orders.filter(isReportableOrder);
  const openOrders = activeOrders.filter((order) => order.status !== "confirmed").length;
  const lowStock = db.inventory.filter((item) => item.qty - item.reserved <= item.reorderPoint).length;
  const reserved = db.inventory.reduce((sum, item) => sum + Number(item.reserved || 0), 0);
  const sales = activeOrders.reduce((sum, order) => sum + Number(order.total || 0), 0);
  const profit = activeOrders.reduce((sum, order) => {
    return sum + Number(order.total || 0) - Number(order.productCost || 0) - Number(order.marketplaceFees || 0) - Number(order.shippingCost || 0) - Number(order.refundAmount || 0);
  }, 0);
  const customers = db.customers || [];
  const purchaseOrders = db.purchaseOrders || [];
  return {
    inventoryCount: db.inventory.length,
    openOrders,
    lowStock,
    reserved,
    sales,
    profit,
    customerCount: customers.length,
    repeatCustomers: customers.filter((customer) => customer.repeatCustomer).length,
    purchaseOrderCount: purchaseOrders.length,
    openPurchaseOrders: purchaseOrders.filter(isOpenPurchaseOrder).length,
    sources: (db.connections || []).map((connection) => ({
      id: connection.id,
      name: connection.name,
      connected: Boolean(connection.connected),
      status: connection.status || "",
      lastSync: connection.lastSync || null
    }))
  };
}

